-- Poems batch 16
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0c0b401a-6771-4507-9487-bbcf9c938473','往河陽宿峽陵寄李侍御','孟郊','唐','唐诗','tang','','[]','莫天寒風悲屑屑，啼鳥遶樹泉水噎。',64,'全唐诗/poet.tang.19000.json','["莫天寒風悲屑屑，啼鳥遶樹泉水噎。", "行路解鞍投古陵，蒼蒼隔山見微月。", "鴞鳴犬吠霜煙昏，開囊拂巾對盤飧。", "人生窮達感知己，明日投君申片言。"]'),
('198e0d6d-50d7-4893-8299-6565d82ba247','鵶路溪行呈陸中丞','孟郊','唐','唐诗','tang','','[]','鵶路不可越，三十六渡溪。',108,'全唐诗/poet.tang.19000.json','["鵶路不可越，三十六渡溪。", "有物飲碧水，高林挂青蜺。", "歷覽道更險，驅使跡頻暌。", "視聽易常主，心魂互相迷。", "浪石忽搖動，沙堤信難躋。", "危峰紫霄外，古木浮雲齊。", "出阻望汝郡，大賢多招攜。", "疲馬戀舊秣，羈禽思故棲。", "應憐泣楚玉，棄置如塵泥。"]'),
('b1d9067e-1f3e-4789-81cb-4d11507c9601','獨宿峴首憶長安故人','孟郊','唐','唐诗','tang','','[]','月迥無隱物，況復大江秋。',48,'全唐诗/poet.tang.19000.json','["月迥無隱物，況復大江秋。", "江城與沙村，人語風颼飀。", "峴亭當此時，故人不同遊。", "故人在長安，亦可將夢求。"]'),
('71700e1e-f443-4d15-8ad9-0b7d116afde5','雜曲歌辭 伊州 歌第三','蓋嘉運','唐','唐诗','tang','','[]','聞道黃花戍，頻年不解兵。',24,'全唐诗/poet.tang.2000.json','["聞道黃花戍，頻年不解兵。", "可憐閨裏月，偏照漢家營。"]'),
('3e9f7376-b439-4ae5-a7cc-c7b987b19317','雜曲歌辭 伊州 歌第四','蓋嘉運','唐','唐诗','tang','','[]','千里東歸客，無心憶舊遊。',24,'全唐诗/poet.tang.2000.json','["千里東歸客，無心憶舊遊。", "挂帆游白水，高枕到青州。"]'),
('39b8e8f4-e55f-44cc-9054-637f6babcce1','雜曲歌辭 伊州 歌第五','蓋嘉運','唐','唐诗','tang','','[]','桂殿江烏對，彫屏海燕重。',24,'全唐诗/poet.tang.2000.json','["桂殿江烏對，彫屏海燕重。", "秖應多釀酒，醉罷樂高鐘。"]'),
('623257f6-e8db-4c0a-9f5b-dfd49f8ff92a','雜曲歌辭 伊州 入破第一','蓋嘉運','唐','唐诗','tang','','[]','千門今夜曉初晴，萬里天河徹帝京。',32,'全唐诗/poet.tang.2000.json','["千門今夜曉初晴，萬里天河徹帝京。", "璨璨繁星駕秋色，稜稜霜氣韻鐘聲。"]'),
('d02e9b44-7604-4af9-b174-162d059c4d6c','雜曲歌辭 伊州 入破第二','蓋嘉運','唐','唐诗','tang','','[]','長安二月柳依依，西出流沙路漸微。',32,'全唐诗/poet.tang.2000.json','["長安二月柳依依，西出流沙路漸微。", "閼氏山上春光少，相府庭邊驛使稀。"]'),
('3cc39afc-6e45-4b7e-a104-ab1d718aaf46','雜曲歌辭 伊州 入破第三','蓋嘉運','唐','唐诗','tang','','[]','三秋大漠冷溪山，八月嚴霜變草顏。',32,'全唐诗/poet.tang.2000.json','["三秋大漠冷溪山，八月嚴霜變草顏。", "卷斾風行宵渡磧，銜枚電掃曉應還。"]'),
('badca271-bf99-42c4-829c-2fcf20f16950','雜曲歌辭 伊州 入破第四','蓋嘉運','唐','唐诗','tang','','[]','行樂三陽早，芳菲二月春。',24,'全唐诗/poet.tang.2000.json','["行樂三陽早，芳菲二月春。", "閨中紅粉態，陌上看花人。"]'),
('3f0c3044-abde-40f5-bd9f-ac83fdbe8319','雜曲歌辭 伊州 入破第五','蓋嘉運','唐','唐诗','tang','','[]','君住孤山下，煙深夜徑長。',24,'全唐诗/poet.tang.2000.json','["君住孤山下，煙深夜徑長。", "轅門渡綠水，遊苑遶垂楊。"]'),
('94292002-770c-46a9-8403-d5b4db792fbf','雜曲歌辭 陸州 歌第一','不詳','唐','唐诗','tang','','[]','分野中峰變，陰晴衆壑殊。',24,'全唐诗/poet.tang.2000.json','["分野中峰變，陰晴衆壑殊。", "欲投人處宿，隔浦問樵夫。"]'),
('7df9a231-79b5-4ae0-8350-5e2ca6f08da7','雜曲歌辭 陸州 歌第二','不詳','唐','唐诗','tang','','[]','共得煙霞徑，東歸山水遊。',24,'全唐诗/poet.tang.2000.json','["共得煙霞徑，東歸山水遊。", "蕭蕭望林夜，寂寂坐中秋。"]'),
('c2d0eb43-3cb8-42b2-9ea0-c5614cadb1eb','雜曲歌辭 陸州 歌第三','不詳','唐','唐诗','tang','','[]','香氣傳空滿，妝花映薄紅。',24,'全唐诗/poet.tang.2000.json','["香氣傳空滿，妝花映薄紅。", "歌聲天仗外，舞態御樓中。"]'),
('0a022fd2-30af-4cec-81fd-e5b991ecbfd5','雜曲歌辭 陸州 排遍第一','不詳','唐','唐诗','tang','','[]','樹發花如錦，鶯嗁柳若絲。',24,'全唐诗/poet.tang.2000.json','["樹發花如錦，鶯嗁柳若絲。", "更逢歡宴地，愁見別離時。"]'),
('4cc2e497-c243-49fc-a919-6e50b73ec5cf','雜曲歌辭 陸州 排遍第二','不詳','唐','唐诗','tang','','[]','明月照秋葉，西風響夜砧。',24,'全唐诗/poet.tang.2000.json','["明月照秋葉，西風響夜砧。", "彊言徒自亂，往事不堪尋。"]'),
('599966fc-6eb9-4c49-97e8-89ca38dfbb78','雜曲歌辭 陸州 排遍第三','不詳','唐','唐诗','tang','','[]','坐對銀釭曉，停留玉筯痕。',24,'全唐诗/poet.tang.2000.json','["坐對銀釭曉，停留玉筯痕。", "君門常不見，無處謝前恩。"]'),
('0b08a6a1-5fbc-4148-9992-fb1469abe45a','雜曲歌辭 陸州 排遍第四','不詳','唐','唐诗','tang','','[]','曙月當窗滿，征人出塞遙。',24,'全唐诗/poet.tang.2000.json','["曙月當窗滿，征人出塞遙。", "畫樓終日閉，清管爲誰調。"]'),
('adfb0df6-df08-488c-a287-37a643ffa171','雜曲歌辭 簇拍陸州','不詳','唐','唐诗','tang','','[]','西去輪臺萬里餘，故鄉音耗日應疎。',32,'全唐诗/poet.tang.2000.json','["西去輪臺萬里餘，故鄉音耗日應疎。", "隴山鸚鵡能言語，爲報閨人數寄書。"]'),
('867793fe-5429-4df3-b46a-8dd6e75220d2','雜曲歌辭 石州','不詳','唐','唐诗','tang','','[]','自從君去遠巡邊，終日羅幃獨自眠。',52,'全唐诗/poet.tang.2000.json','["自從君去遠巡邊，終日羅幃獨自眠。", "看花情轉切，攬鏡淚如泉。", "一自離君後，嗁多雙臉穿。", "何時狂虜滅，免得更留連。"]'),
('7066e611-faa5-427c-8fce-e0bf10c55416','雜曲歌辭 蓋羅縫 一','不詳','唐','唐诗','tang','','["\u6218\u4e89", "\u5199\u666f", "\u5fe7\u56fd\u5fe7\u6c11", "\u7231\u56fd", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','秦時明月漢時關，萬里征人尚未還。',32,'全唐诗/poet.tang.2000.json','["秦時明月漢時關，萬里征人尚未還。", "但願龍庭神將在，不教胡馬渡陰山。"]'),
('dbc7ee41-850f-4bb2-999c-49c8bfa948c0','雜曲歌辭 蓋羅縫 二','不詳','唐','唐诗','tang','','[]','音書杜絕白狼西，桃李無顏黃鳥嗁。',32,'全唐诗/poet.tang.2000.json','["音書杜絕白狼西，桃李無顏黃鳥嗁。", "寒鳥春深歸去盡，出門腸斷草萋萋。"]'),
('2ab191eb-2b10-434e-ba32-cb1f8b0a2d93','雜曲歌辭 雙帶子','不詳','唐','唐诗','tang','','[]','私言切語誰人會，海燕雙飛繞畫梁。',32,'全唐诗/poet.tang.2000.json','["私言切語誰人會，海燕雙飛繞畫梁。", "君學秋胡不相識，妾亦無心去采桑。"]'),
('0376fc59-bd2b-4b6a-9105-50bf77dc6999','雜曲歌辭 崑崙子','不詳','唐','唐诗','tang','','[]','[揚]子譚經去，淮王載酒過。',26,'全唐诗/poet.tang.2000.json','["[揚]子譚經去，淮王載酒過。", "醉來嗁鳥喚，坐久落花多。"]'),
('f1991aab-5e58-411b-81ec-9a6c85e4601f','雜曲歌辭 祓禊曲 一','不詳','唐','唐诗','tang','','[]','昨見春條綠，那知秋葉黃。',24,'全唐诗/poet.tang.2000.json','["昨見春條綠，那知秋葉黃。", "蟬聲猶未斷，寒鴈已成行。"]'),
('4f33dbfd-6e6d-4ec9-97fd-aa549782ca2f','雜曲歌辭 祓禊曲 二','不詳','唐','唐诗','tang','','[]','金谷園中柳，春來已舞腰。',24,'全唐诗/poet.tang.2000.json','["金谷園中柳，春來已舞腰。", "那堪好風景，獨上洛陽橋。"]'),
('926a2036-d651-4bda-a7ef-55dd30aeecf3','雜曲歌辭 祓禊曲 三','不詳','唐','唐诗','tang','','[]','何處堪愁思，花間長樂宮。',24,'全唐诗/poet.tang.2000.json','["何處堪愁思，花間長樂宮。", "君王不重客，泣淚向春風。"]'),
('697019d0-83f3-4cd1-ba6f-7738d9c31ce0','雜曲歌辭 上巳樂','張祜','唐','唐诗','tang','','[]','猩猩血綵繫頭標，天上齊聲舉畫橈。',32,'全唐诗/poet.tang.2000.json','["猩猩血綵繫頭標，天上齊聲舉畫橈。", "卻是內人爭意切，六宮羅袖一時招。"]'),
('68c8add6-7843-4c4f-b6c1-e18bb7e071bb','雜曲歌辭 穆護砂','不詳','唐','唐诗','tang','','[]','玉管朝朝弄，清歌日日新。',24,'全唐诗/poet.tang.2000.json','["玉管朝朝弄，清歌日日新。", "折花當驛路，寄與隴頭人。"]'),
('1cb1b2d2-0d2c-43ab-945c-b037aecbc027','雜曲歌辭 思歸樂 一','不詳','唐','唐诗','tang','','[]','晚日催弦管，春風入綺羅。',24,'全唐诗/poet.tang.2000.json','["晚日催弦管，春風入綺羅。", "杏花如有意，偏落舞衫多。"]'),
('e5ada04a-9a0c-4d4e-9fc1-223b9a670f76','雜曲歌辭 思歸樂 二','不詳','唐','唐诗','tang','','[]','萬里春應盡，三江鴈亦稀。',24,'全唐诗/poet.tang.2000.json','["萬里春應盡，三江鴈亦稀。", "連天漢水廣，孤客未言歸。"]'),
('144cfce8-087e-423d-be53-e93551cdeb48','雜曲歌辭 金殿樂','不詳','唐','唐诗','tang','','[]','入夜秋砧動，千門起四鄰。',24,'全唐诗/poet.tang.2000.json','["入夜秋砧動，千門起四鄰。", "不緣樓上月，應爲隴頭人。"]'),
('2c455d41-a372-4356-a9ed-975ddd89ff9c','雜曲歌辭 胡渭州 一','不詳','唐','唐诗','tang','','["\u957f\u6c5f"]','亭亭孤月照行舟，寂寂長江萬里流。',32,'全唐诗/poet.tang.2000.json','["亭亭孤月照行舟，寂寂長江萬里流。", "鄉國不知何處是？雲山漫漫使人愁。"]'),
('c1594acd-0832-44f9-a254-6abff067a1a4','雜曲歌辭 胡渭州 二','不詳','唐','唐诗','tang','','[]','楊柳千尋色，桃花一苑芳。',24,'全唐诗/poet.tang.2000.json','["楊柳千尋色，桃花一苑芳。", "風吹入簾裏，惟有惹衣香。"]'),
('90e06f7f-0e09-4944-b773-b1583e0d29bd','雜曲歌辭 戎渾','不詳','唐','唐诗','tang','','[]','風勁角弓鳴，將軍獵渭城。',24,'全唐诗/poet.tang.2000.json','["風勁角弓鳴，將軍獵渭城。", "草枯鷹眼疾，雪盡馬蹏輕。"]'),
('e3ad53a0-5a07-4866-aa4a-e782065bf905','雜曲歌辭 牆頭花 一','不詳','唐','唐诗','tang','','[]','蟋蟀鳴洞房，梧桐落金井。',24,'全唐诗/poet.tang.2000.json','["蟋蟀鳴洞房，梧桐落金井。", "爲君裁舞衣，天寒翦刀冷。"]'),
('f7864efd-7500-46b6-82b7-fbf9be8267b0','雜曲歌辭 牆頭花 二','不詳','唐','唐诗','tang','','[]','妾有羅衣裳，秦王在時作。',24,'全唐诗/poet.tang.2000.json','["妾有羅衣裳，秦王在時作。", "爲舞春風多，秋來不堪著。"]'),
('f9b86487-a06d-4efb-9858-cf3d9065aba0','雜曲歌辭 采桑','不詳','唐','唐诗','tang','','[]','自古多征戰，由來尚甲兵。',45,'全唐诗/poet.tang.2000.json','["自古多征戰，由來尚甲兵。", "長驅千里去，一舉兩蕃平。", "按劒從沙漠歌謠滿帝京寄言天下將須立武功名。"]'),
('ca9c4f70-c296-4005-b36c-20c4de16d530','雜曲歌辭 [楊]下採桑','不詳','唐','唐诗','tang','','[]','飛絲惹綠塵，軟葉對孤輪。',24,'全唐诗/poet.tang.2000.json','["飛絲惹綠塵，軟葉對孤輪。", "今朝入園去，物色彊看人。"]'),
('7c8d82d0-2f42-4b39-a90d-0ee7e8e4bc4d','雜曲歌辭 破陣樂 一','不詳','唐','唐诗','tang','','[]','秋來四面足風沙，塞外征人暫別家。',32,'全唐诗/poet.tang.2000.json','["秋來四面足風沙，塞外征人暫別家。", "千里不辭行路遠，時光早晚到天涯。"]'),
('07d180a6-24fb-43f7-b04c-298962aa03b5','雜曲歌辭 破陣樂 二','不詳','唐','唐诗','tang','','[]','漢兵出頓金微，照日明光鐵衣。',56,'全唐诗/poet.tang.2000.json','["漢兵出頓金微，照日明光鐵衣。", "百里火幡熖熖，千行雲騎騑騑。", "蹙踏遼河自竭，鼓噪燕山可飛。", "正屬四方朝賀，端知萬舞皇威。"]'),
('cbceb077-c964-4d19-8fa4-3b2c6613c08c','雜曲歌辭 破陣樂 三','不詳','唐','唐诗','tang','','[]','少年膽氣凌雲，共許驍雄出羣。',56,'全唐诗/poet.tang.2000.json','["少年膽氣凌雲，共許驍雄出羣。", "匹馬城南挑戰，單刀薊北從軍。", "一鼓鮮卑送欵，五餌單于解紛。", "誓欲成名報國，羞將開口論勳。"]'),
('02baf687-c1d8-49bb-9847-688b4b0db9c4','雜曲歌辭 戰勝樂','不詳','唐','唐诗','tang','','[]','百戰得功名，天兵意氣生。',24,'全唐诗/poet.tang.2000.json','["百戰得功名，天兵意氣生。", "三邊永不戰，此是我皇英。"]'),
('a1dde17d-5fd4-496f-a262-b24ac571e95a','雜曲歌辭 劒南臣','不詳','唐','唐诗','tang','','[]','不分君恩斷，觀妝視鏡中。',48,'全唐诗/poet.tang.2000.json','["不分君恩斷，觀妝視鏡中。", "容華尚春日，嬌愛已秋風。", "枕席臨窗曉，屏帷對月空。", "年年後庭樹，芳悴在深宮。"]'),
('c24d198e-752f-482c-aa79-d48fed994530','雜曲歌辭 征步郎','不詳','唐','唐诗','tang','','[]','塞外虜塵飛，頻年度磧西。',24,'全唐诗/poet.tang.2000.json','["塞外虜塵飛，頻年度磧西。", "死生隨玉劒，辛苦向金微。"]'),
('f42e692d-0221-4d2a-afbb-c99700a0fe7f','雜曲歌辭 [歎]疆場','不詳','唐','唐诗','tang','','[]','聞道行人至，妝梳對鏡臺。',24,'全唐诗/poet.tang.2000.json','["聞道行人至，妝梳對鏡臺。", "淚痕猶尚在，笑靨自然開。"]'),
('d9ae5a2a-e1ad-41a8-997d-5944e0fc9aab','雜曲歌辭 塞姑','不詳','唐','唐诗','tang','','[]','昨日盧梅塞口，整見諸人鎮守。',28,'全唐诗/poet.tang.2000.json','["昨日盧梅塞口，整見諸人鎮守。", "都護三年不歸，折盡江邊楊柳。"]'),
('1cfb73a2-ed75-48f1-afb8-eda13036d320','雜曲歌辭 水鼓子','不詳','唐','唐诗','tang','','[]','雕弓白羽獵初回，薄夜牛羊復下來。',32,'全唐诗/poet.tang.2000.json','["雕弓白羽獵初回，薄夜牛羊復下來。", "夢水河邊秋草合，黑山峰外陣雲開。"]'),
('f1320c1f-949a-4cbe-ad23-4806878632c5','雜曲歌辭 婆羅門','楊敬述進','唐','唐诗','tang','','["\u601d\u5ff5", "\u6218\u4e89", "\u51ac\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u8fb9\u585e", "\u4e03\u8a00\u7edd\u53e5"]','迴樂峰前沙似雪，受降城外月如霜。',32,'全唐诗/poet.tang.2000.json','["迴樂峰前沙似雪，受降城外月如霜。", "不知何處吹蘆管？一夜征人盡望鄉。"]'),
('102d5f4d-6b07-4d8a-9d98-52af69d55cbf','雜曲歌辭 浣沙女 一','不詳','唐','唐诗','tang','','[]','南陌春風早，東鄰去日斜。',24,'全唐诗/poet.tang.2000.json','["南陌春風早，東鄰去日斜。", "千花開瑞錦，香撲美人車。"]'),
('0a3e9a54-f14b-4e37-9d2c-6c9b231df309','雜曲歌辭 浣沙女 二','不詳','唐','唐诗','tang','','[]','長樂青門外，宜春小苑東。',24,'全唐诗/poet.tang.2000.json','["長樂青門外，宜春小苑東。", "樓開萬戶上，人向百花中。"]'),
('a423eb43-701c-4dd0-b979-52027c8bb410','雜曲歌辭 鎮西','不詳','唐','唐诗','tang','','[]','天邊物色更無春，祗有羊羣與馬羣。',32,'全唐诗/poet.tang.2000.json','["天邊物色更無春，祗有羊羣與馬羣。", "誰家營裏吹羌笛，哀怨教人不忍聞。"]'),
('2f4af038-8199-49be-a010-aa7ac9a67f9b','雜曲歌辭 鎮西 二','不詳','唐','唐诗','tang','','[]','歲去年來拜聖朝，更無山闕對溪橋。',32,'全唐诗/poet.tang.2000.json','["歲去年來拜聖朝，更無山闕對溪橋。", "九門楊柳渾無半，猶自千條與萬條。"]'),
('6c4216a7-1983-433b-bfd6-54ae9855d629','雜曲歌辭 回紇','不詳','唐','唐诗','tang','','[]','曾聞瀚海使難通，幽閨少婦罷裁縫。',46,'全唐诗/poet.tang.2000.json','["曾聞瀚海使難通，幽閨少婦罷裁縫。", "緬想邊庭征戰苦，誰能對鏡治愁容。", "久戍人將老，須臾變作白頭翁。"]'),
('7fba1e28-e436-49dd-bb7c-ea006ec5eb51','雜曲歌辭 長命女','不詳','唐','唐诗','tang','','[]','雲送關西雨，風傳渭北秋。',24,'全唐诗/poet.tang.2000.json','["雲送關西雨，風傳渭北秋。", "孤燈然客夢，寒杵擣鄉愁。"]'),
('d1ff695a-6eff-4704-b986-d5e5f34360c5','雜曲歌辭 醉公子','不詳','唐','唐诗','tang','','[]','昨日春園飲，今朝倒接䍦。',24,'全唐诗/poet.tang.2000.json','["昨日春園飲，今朝倒接䍦。", "誰人扶上馬，不省下樓時。"]'),
('dba6002d-e6fe-4774-b34d-6d0e1399dc39','雜曲歌辭 一片子','不詳','唐','唐诗','tang','','[]','柳色青山映，梨花雪鳥藏。',24,'全唐诗/poet.tang.2000.json','["柳色青山映，梨花雪鳥藏。", "綠窗桃李下，閑坐歎春芳。"]'),
('61295446-6023-4dfe-9135-ae8c2c2acb72','雜曲歌辭 甘州','不詳','唐','唐诗','tang','','[]','欲使傳消息，空書意不任。',24,'全唐诗/poet.tang.2000.json','["欲使傳消息，空書意不任。", "寄君明月鏡，偏照故人心。"]'),
('e25a9ff8-af98-482b-8a10-ac04bad9eb57','雜曲歌辭 濮陽女','不詳','唐','唐诗','tang','','[]','鴈來書不至，月照獨眠房。',24,'全唐诗/poet.tang.2000.json','["鴈來書不至，月照獨眠房。", "賤妾多愁思，不堪秋夜長。"]'),
('ad596df7-559f-4f97-81d3-7cba94b371c5','雜曲歌辭 相府蓮','不詳','唐','唐诗','tang','','[]','夜聞鄰婦泣，切切有餘哀。',24,'全唐诗/poet.tang.2000.json','["夜聞鄰婦泣，切切有餘哀。", "即問緣何事，征人戰未迴。"]'),
('c5b54cf0-094f-4f32-ae1b-d12cb826cead','雜曲歌辭 蔟拍相府蓮','不詳','唐','唐诗','tang','','[]','莫以今時寵，寧無舊日恩。',48,'全唐诗/poet.tang.2000.json','["莫以今時寵，寧無舊日恩。", "看花滿眼淚，不共楚王言。", "閨燭無人影，羅屏有夢魂。", "近來音耗絕，終日望應門。"]'),
('1e48a64e-3132-42f5-8903-cd1d7c497709','雜曲歌辭 離別難','不詳','唐','唐诗','tang','','[]','此別難重陳，花深復變人。',48,'全唐诗/poet.tang.2000.json','["此別難重陳，花深復變人。", "來時梅覆雪，去日柳含春。", "物候催行客，歸途淑氣新。", "剡川今已遠，魂夢暗相親。"]'),
('04cc4964-a77d-491f-ad66-b7d704843efa','雜曲歌辭 離別難','白居易','唐','唐诗','tang','','[]','綠楊陌上送行人，馬去車回一望塵。',32,'全唐诗/poet.tang.2000.json','["綠楊陌上送行人，馬去車回一望塵。", "不覺別時紅淚盡，歸來無淚可霑巾。"]'),
('fc0f941e-daa1-4ec4-ace0-205c08f267b5','雜曲歌辭 山鷓鴣 一','不詳','唐','唐诗','tang','','[]','玉關征戍久，空閨人獨愁。',24,'全唐诗/poet.tang.2000.json','["玉關征戍久，空閨人獨愁。", "寒露溼青苔，別來蓬鬢秋。"]'),
('22aa7825-50bb-4538-8c64-07e9be2e0d20','雜曲歌辭 山鷓鴣 二','不詳','唐','唐诗','tang','','[]','人坐青樓晚，鶯語百花時。',24,'全唐诗/poet.tang.2000.json','["人坐青樓晚，鶯語百花時。", "愁人多自老，腸斷君不知。"]'),
('20ee2b22-3a2e-484b-a3be-ed05d933fdf6','雜曲歌辭 鷓鴣詞','李益','唐','唐诗','tang','','[]','湘江斑竹枝，錦翼鷓鴣飛。',24,'全唐诗/poet.tang.2000.json','["湘江斑竹枝，錦翼鷓鴣飛。", "處處湘雲合，郎從何處歸。"]'),
('1a4b1e08-0a98-4cfc-bf09-df2d48032a83','雜曲歌辭 鷓鴣詞 一','李涉','唐','唐诗','tang','','[]','湘江煙水深，沙岸隔楓林。',48,'全唐诗/poet.tang.2000.json','["湘江煙水深，沙岸隔楓林。", "何處鷓鴣飛？日斜斑竹陰。", "二女虛垂淚，三閭枉自沈。", "惟有鷓鴣鳥，獨傷行客心。"]'),
('7df84efd-f604-4f15-bb4b-02a967dc849f','雜曲歌辭 鷓鴣詞 二','李涉','唐','唐诗','tang','','[]','越岡連越井，越鳥更南飛。',48,'全唐诗/poet.tang.2000.json','["越岡連越井，越鳥更南飛。", "何處鷓鴣嗁，夕煙東嶺歸。", "嶺頭行人少，天涯北客稀。", "鷓鴣嗁別處，相對淚霑衣。"]'),
('7f26ad4f-5b4e-4d68-a5de-9b8c6a9658c1','雜曲歌辭 樂世','白居易','唐','唐诗','tang','','[]','管急絲繁拍漸稠，綠腰宛轉曲終頭。',32,'全唐诗/poet.tang.2000.json','["管急絲繁拍漸稠，綠腰宛轉曲終頭。", "誠知樂世聲聲樂，老病人聽未免愁。"]'),
('fc51fef4-8791-4d57-8148-088441d6a3ab','雜曲歌辭 急[樂世]','白居易','唐','唐诗','tang','','[]','正抽碧線繡紅羅，忽聽黃鶯斂翠蛾。',32,'全唐诗/poet.tang.2000.json','["正抽碧線繡紅羅，忽聽黃鶯斂翠蛾。", "秋思冬愁春恨望，大都不得意時多。"]'),
('5e5dc90f-39b3-40a2-8b94-5c4848fd301f','雜曲歌辭 何滿子','白居易','唐','唐诗','tang','','[]','世傳滿子是人名，臨就刑時曲始成。',32,'全唐诗/poet.tang.2000.json','["世傳滿子是人名，臨就刑時曲始成。", "一曲四詞歌八疊，從頭便是斷腸聲。"]'),
('40b21364-d2c7-4aef-95ec-106c41bd77ed','雜曲歌辭 何滿子','薛逢','唐','唐诗','tang','','[]','繫馬宮槐老，持杯店菊黃。',24,'全唐诗/poet.tang.2000.json','["繫馬宮槐老，持杯店菊黃。", "故交今不見，流恨滿川光。"]'),
('b5f1094b-b9be-43cf-8e04-9b984642a630','雜曲歌辭 清平調 一','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5973\u5b50", "\u4e50\u5e9c", "\u8d5e\u7f8e", "\u8fd1\u4ee3\u66f2\u8f9e"]','雲想衣裳花想容，春風拂檻露華濃。',32,'全唐诗/poet.tang.2000.json','["雲想衣裳花想容，春風拂檻露華濃。", "若非羣玉山頭見，會向瑤臺月下逢。"]'),
('73dadc56-88ff-4f11-9ff5-da0e0adf533c','雜曲歌辭 清平調 二','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5973\u5b50", "\u8fd1\u4ee3\u66f2\u8f9e", "\u4e50\u5e9c"]','一枝紅豔露凝香，雲雨巫山枉斷腸。',32,'全唐诗/poet.tang.2000.json','["一枝紅豔露凝香，雲雨巫山枉斷腸。", "借問漢宮誰得似，可憐飛燕倚新妝。"]'),
('0db5450e-f1e0-4d53-8106-529def535537','雜曲歌辭 清平調 三','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u5199\u4eba", "\u82b1", "\u5199\u82b1", "\u8fd1\u4ee3\u66f2\u8f9e"]','名花傾國兩相歡，長得君王帶笑看。',32,'全唐诗/poet.tang.2000.json','["名花傾國兩相歡，長得君王帶笑看。", "解釋春風無限恨，沈香亭北倚闌干。"]'),
('f4361ba5-68fa-40ca-8795-6dddc27ad023','雜曲歌辭 回波樂','李景伯','唐','唐诗','tang','','[]','回波爾時酒巵，微臣職在箴規。',28,'全唐诗/poet.tang.2000.json','["回波爾時酒巵，微臣職在箴規。", "侍宴既過三爵，諠譁竊恐非儀。"]'),
('c243b415-6685-4c96-9952-fd82f813199d','雜曲歌辭 聖明樂 一','張仲素','唐','唐诗','tang','','[]','玉帛殊方至，歌鍾比屋聞。',24,'全唐诗/poet.tang.2000.json','["玉帛殊方至，歌鍾比屋聞。", "華夷今一貫，同賀聖明君。"]'),
('826f0eb7-19d7-4a47-b186-26cc447991cc','雜曲歌辭 聖明樂 二','張仲素','唐','唐诗','tang','','[]','九陌祥煙合，千春瑞月明。',24,'全唐诗/poet.tang.2000.json','["九陌祥煙合，千春瑞月明。", "宮花將苑柳，先發鳳皇城。"]'),
('a53d63f2-c22e-41d7-81dd-f4529d2978a1','雜曲歌辭 聖明樂','令狐楚','唐','唐诗','tang','','[]','海浪恬丹徼，邊塵靜異山。',24,'全唐诗/poet.tang.2000.json','["海浪恬丹徼，邊塵靜異山。", "從今萬里外，不復鎖蕭關。"]'),
('76ea242b-dea0-40d6-8e0c-84be8761df5a','雜曲歌辭 大酺樂','不詳','唐','唐诗','tang','','[]','淚滴珠難盡，容殘玉易銷。',24,'全唐诗/poet.tang.2000.json','["淚滴珠難盡，容殘玉易銷。", "儻隨明月去，莫道夢魂遙。"]'),
('d3fc929a-d769-4b7f-86af-f2534b9a26e1','雜曲歌辭 大酺樂 一','杜審言','唐','唐诗','tang','','[]','聖后乘乾日，皇明御曆辰。',48,'全唐诗/poet.tang.2000.json','["聖后乘乾日，皇明御曆辰。", "紫宮初啓坐，蒼璧正臨春。", "雷雨垂膏澤，金錢賜下人。", "詔酺歡賞徧，交泰覩惟新。"]'),
('ff257f62-6a13-4be9-b536-bfe07af7807e','雜曲歌辭 大酺樂 二','杜審言','唐','唐诗','tang','','[]','毘陵震澤九州通，士女歡娛萬國同。',64,'全唐诗/poet.tang.2000.json','["毘陵震澤九州通，士女歡娛萬國同。", "伐鼓撞鐘驚海上，新妝袨服照江東。", "梅花落處疑殘雪，柳葉開時任好風。", "大德不官逢道泰，天長地久屬年豐。"]'),
('a94934c3-03e9-4030-9668-8dee295256a8','雜曲歌辭 大酺樂 一','張祜','唐','唐诗','tang','','[]','車駕東來值太平，大酺三日洛陽城。',32,'全唐诗/poet.tang.2000.json','["車駕東來值太平，大酺三日洛陽城。", "小兒一伎竿頭絕，天下傳呼萬歲聲。"]'),
('8b55e01e-a88a-4058-a516-243c818c9043','雜曲歌辭 大酺樂 二','張祜','唐','唐诗','tang','','[]','紫陌酺歸日欲斜，紅塵開路薛王家。',32,'全唐诗/poet.tang.2000.json','["紫陌酺歸日欲斜，紅塵開路薛王家。", "雙鬟前說樓前鼓，兩伎爭輪好結花。"]'),
('b28a5507-0edb-48cc-b0c6-a61347d772de','雜曲歌辭 千秋樂','張祜','唐','唐诗','tang','','[]','八月平時花萼樓，萬方同樂奏千秋。',32,'全唐诗/poet.tang.2000.json','["八月平時花萼樓，萬方同樂奏千秋。", "傾城人看長竿出，一伎初成趙解愁。"]'),
('0fb36238-1a2b-41a3-9a5f-a7e910d7c16b','雜曲歌辭 火鳳辭 一','李百藥','唐','唐诗','tang','','[]','歌聲扇裏出，妝影扇中輕。',48,'全唐诗/poet.tang.2000.json','["歌聲扇裏出，妝影扇中輕。", "未能令掩笑，何處欲鄣聲。", "知音自不惑，得念是分明。", "莫見雙嚬斂，疑人含笑情。"]'),
('8ce536af-9b75-421f-aca0-b5ec399dcfb4','雜曲歌辭 火鳳辭 二','李百藥','唐','唐诗','tang','','[]','佳人靚晚妝，清唱動蘭房。',48,'全唐诗/poet.tang.2000.json','["佳人靚晚妝，清唱動蘭房。", "影入含風扇，聲飛照日梁。", "嬌嚬眉際斂，逸韻口中香。", "自有橫陳分，應憐秋夜長。"]'),
('53faf355-3055-4ddb-8285-6b42a984dbbf','雜曲歌辭 熱戲樂','張祜','唐','唐诗','tang','','[]','熱戲爭心劇火燒，銅槌暗執不相饒。',32,'全唐诗/poet.tang.2000.json','["熱戲爭心劇火燒，銅槌暗執不相饒。", "上皇失喜寧王笑，百尺幢竿果動搖。"]'),
('ffefb2df-5b94-4f50-9907-4be92746cc4a','雜曲歌辭 春鶯囀','張祜','唐','唐诗','tang','','[]','興慶池南柳未開，太真先把一枝梅。',32,'全唐诗/poet.tang.2000.json','["興慶池南柳未開，太真先把一枝梅。", "內人已唱春鶯囀，花下傞傞軟舞來。"]'),
('f182179e-9140-43eb-97bb-78db53c97055','雜曲歌辭 達摩支','溫庭筠','唐','唐诗','tang','','[]','擣麝成塵香不滅，拗蓮作寸絲難絕。',99,'全唐诗/poet.tang.2000.json','["擣麝成塵香不滅，拗蓮作寸絲難絕。", "紅淚文姬洛水春，白頭蘇武天山雪。", "君不見無愁高緯花漫漫，漳浦宴餘清露寒。", "一旦臣僚共囚虜，欲吹羌管先汍瀾。", "舊臣頭鬢霜華早，可惜雄心醉中老。", "萬古春歸夢不歸，鄴城風雨連天草。"]'),
('516379b7-d6f7-4fd9-b5f5-d6dcd7dc92ee','雜曲歌辭 如意娘','則天皇后','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u76f8\u601d", "\u5a49\u7ea6"]','看朱成碧思紛紛，憔悴支離爲憶君。',32,'全唐诗/poet.tang.2000.json','["看朱成碧思紛紛，憔悴支離爲憶君。", "不信比來長下淚，開箱驗取石榴裙。"]'),
('4ba8b942-3ced-425b-a5d4-8a890208df29','雜曲歌辭 雨霖鈴','張祜','唐','唐诗','tang','','[]','雨霖鈴夜卻歸秦，猶是張徽一曲新。',32,'全唐诗/poet.tang.2000.json','["雨霖鈴夜卻歸秦，猶是張徽一曲新。", "長說上皇垂淚教，月明南內更無人。"]'),
('3f36a88f-5b5d-4f50-87fa-ef10188af102','雜曲歌辭 桂花曲','不詳','唐','唐诗','tang','','[]','可憐天上桂花孤，試問姮娥更要無。',32,'全唐诗/poet.tang.2000.json','["可憐天上桂花孤，試問姮娥更要無。", "月宮幸有閒田地，何不中央種兩株。"]'),
('e4a87504-f9a3-4599-b770-aba4afd3cb04','雜曲歌辭 渭城曲','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u53cb\u60c5", "\u5c0f\u5b66\u53e4\u8bd7", "\u9001\u522b", "\u521d\u4e2d\u53e4\u8bd7"]','謂城朝雨浥輕塵，客舍青青柳色春。',32,'全唐诗/poet.tang.2000.json','["謂城朝雨浥輕塵，客舍青青柳色春。", "勸君更盡一杯酒，西出陽關無故人。"]'),
('ca5f0ec8-8c80-4fd6-aca5-1f283d430ad4','雜曲歌辭 竹枝','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','帝子蒼梧不復歸，洞庭葉下荆雲飛。',32,'全唐诗/poet.tang.2000.json','["帝子蒼梧不復歸，洞庭葉下荆雲飛。", "巴人夜唱竹枝後，腸斷曉猨聲漸稀。"]'),
('5640c81c-c876-463a-8e7a-1c64020e12b3','雜曲歌辭 竹枝 一','劉禹錫','唐','唐诗','tang','','[]','白帝城頭春草生，白鹽山下蜀江清。',32,'全唐诗/poet.tang.2000.json','["白帝城頭春草生，白鹽山下蜀江清。", "南人上來歌一曲，北人莫上動鄉情。"]'),
('6164ec67-303e-46b4-bbb8-193b64d9e23b','雜曲歌辭 竹枝 二','劉禹錫','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u6843\u82b1", "\u7231\u60c5", "\u5199\u666f", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','山桃紅花滿上頭，蜀江春水拍江流。',32,'全唐诗/poet.tang.2000.json','["山桃紅花滿上頭，蜀江春水拍江流。", "花紅易衰似郎意，水流無限似儂愁。"]'),
('597c32ad-6e79-437e-8725-63efff85d83a','雜曲歌辭 竹枝 三','劉禹錫','唐','唐诗','tang','','[]','江上朱樓新雨晴，瀼西春水縠文生。',32,'全唐诗/poet.tang.2000.json','["江上朱樓新雨晴，瀼西春水縠文生。", "橋東橋西好楊柳，人來人去唱歌行。"]'),
('77121ae7-3102-441e-bb70-1a232193c92e','雜曲歌辭 竹枝 四','劉禹錫','唐','唐诗','tang','','[]','日出三竿春霧消，江頭蜀客駐蘭橈。',32,'全唐诗/poet.tang.2000.json','["日出三竿春霧消，江頭蜀客駐蘭橈。", "憑寄狂夫書一紙，住在成都萬里橋。"]'),
('c1d87228-104c-4e95-96d3-4f17ecf86238','雜曲歌辭 竹枝 五','劉禹錫','唐','唐诗','tang','','[]','兩岸山花似雪開，家家春酒滿銀杯。',32,'全唐诗/poet.tang.2000.json','["兩岸山花似雪開，家家春酒滿銀杯。", "昭君坊中多女伴，永安宮外踏青來。"]'),
('130faeb2-00ea-4744-b85b-62baadfe8d82','雜曲歌辭 竹枝 六','劉禹錫','唐','唐诗','tang','','[]','瞿塘嘈嘈十二灘，此中道路古來難。',32,'全唐诗/poet.tang.2000.json','["瞿塘嘈嘈十二灘，此中道路古來難。", "長恨人心不如水，等閑平地起波瀾。"]'),
('08630597-508f-4bdd-b9b1-2d531a175574','雜曲歌辭 竹枝 七','劉禹錫','唐','唐诗','tang','','[]','巫峽蒼蒼煙雨時，清猨啼在最高枝。',32,'全唐诗/poet.tang.2000.json','["巫峽蒼蒼煙雨時，清猨啼在最高枝。", "箇裏愁人腸自斷，由來不是此聲悲。"]'),
('0fa962c2-c63a-47bb-842e-2125894fbaea','雜曲歌辭 竹枝 八','劉禹錫','唐','唐诗','tang','','[]','城西門前灩澦堆，年年波浪不能摧。',32,'全唐诗/poet.tang.2000.json','["城西門前灩澦堆，年年波浪不能摧。", "懊惱人心不如石，少時東去復西來。"]'),
('e139708b-9909-4489-acfd-9458dac6e8e4','雜曲歌辭 竹枝 九','劉禹錫','唐','唐诗','tang','','["\u5c71", "\u751f\u6d3b", "\u98ce\u4fd7"]','山上層層桃李花，雲間煙火是人家。',32,'全唐诗/poet.tang.2000.json','["山上層層桃李花，雲間煙火是人家。", "銀釧金釵來負水，長刀短笠去燒畬。"]'),
('7b000fd9-b9ce-4215-8777-32267dcc5456','雜曲歌辭 竹枝 一','劉禹錫','唐','唐诗','tang','','[]','楊柳青青江水平，聞郎江上唱歌聲。',32,'全唐诗/poet.tang.2000.json','["楊柳青青江水平，聞郎江上唱歌聲。", "東邊日出西邊雨，道是無情還有情。"]'),
('c12c30c3-e7da-4123-994c-c007a05c13e0','雜曲歌辭 竹枝 二','劉禹錫','唐','唐诗','tang','','["\u601d\u4e61", "\u5c71\u6c34"]','楚水巴山江雨多，巴人能唱本鄉歌。',32,'全唐诗/poet.tang.2000.json','["楚水巴山江雨多，巴人能唱本鄉歌。", "今朝北客思歸去，迴入紇那披綠羅。"]'),
('d4172a5d-55d3-42da-9db7-6dfda5034a88','雜曲歌辭 竹枝 一','白居易','唐','唐诗','tang','','[]','瞿塘峽口冷煙低，白帝城頭月向西。',32,'全唐诗/poet.tang.2000.json','["瞿塘峽口冷煙低，白帝城頭月向西。", "唱到竹枝聲咽處，寒猨晴鳥一時啼。"]'),
('55ca2017-0c5a-47a0-b04f-83282daa65b5','雜曲歌辭 竹枝 二','白居易','唐','唐诗','tang','','[]','竹枝苦怨怨何人，夜靜山空歇又聞。',32,'全唐诗/poet.tang.2000.json','["竹枝苦怨怨何人，夜靜山空歇又聞。", "蠻兒巴女齊聲唱，愁殺江樓病使君。"]'),
('41998801-e03b-44b6-ae52-d8703c1a7b17','雜曲歌辭 竹枝 三','白居易','唐','唐诗','tang','','[]','巴東船舫上巴西，波面風生雨脚齊。',32,'全唐诗/poet.tang.2000.json','["巴東船舫上巴西，波面風生雨脚齊。", "水蓼冷花紅蔟蔟，江蘺溼葉碧萋萋。"]'),
('8e192c25-d4a1-4a6c-aadc-a780ab6dfd34','雜曲歌辭 竹枝 四','白居易','唐','唐诗','tang','','[]','江畔誰人唱竹枝，前聲斷咽後聲遲。',32,'全唐诗/poet.tang.2000.json','["江畔誰人唱竹枝，前聲斷咽後聲遲。", "怪來調苦緣詞苦，多是通州司馬詩。"]'),
('a7d7a94e-be74-4b86-8512-35700e9dad55','雜曲歌辭 竹枝 一','李涉','唐','唐诗','tang','','[]','荆門灘急水潺潺，兩岸猨啼煙滿山。',32,'全唐诗/poet.tang.2000.json','["荆門灘急水潺潺，兩岸猨啼煙滿山。", "渡頭年少應官去，月落西陵望不還。"]'),
('d4e17c65-86f6-4948-9eec-b4e12c1c927a','雜曲歌辭 竹枝 二','李涉','唐','唐诗','tang','','[]','巫峽雲開神女祠，綠潭紅樹影參差。',32,'全唐诗/poet.tang.2000.json','["巫峽雲開神女祠，綠潭紅樹影參差。", "下牢戍口初相問，無義灘頭剩別離。"]'),
('97c18fe0-deb7-4493-85d8-f3c602b3fd6c','雜曲歌辭 竹枝 三','李涉','唐','唐诗','tang','','[]','石壁千重樹萬重，白雲斜掩碧芙蓉。',32,'全唐诗/poet.tang.2000.json','["石壁千重樹萬重，白雲斜掩碧芙蓉。", "昭君溪上年年月，獨自嬋娟色最濃。"]'),
('a11a6b16-e984-4fd0-9978-4b97082f6a2b','雜曲歌辭 竹枝 四','李涉','唐','唐诗','tang','','[]','十二峰頭月欲低，空濛江上子規啼。',32,'全唐诗/poet.tang.2000.json','["十二峰頭月欲低，空濛江上子規啼。", "孤舟一夜東歸客，泣向春風憶建溪。"]'),
('20f46758-bdec-41a6-b5bf-b329495828ba','雜曲歌辭 竹枝 一','孫光憲','唐','唐诗','tang','','[]','門前春水白蘋花，岸上無人小艇斜。',32,'全唐诗/poet.tang.2000.json','["門前春水白蘋花，岸上無人小艇斜。", "商女經過江欲暮，散拋殘食飼神雅。"]'),
('bee3aac5-6076-488a-887f-40d547139cb9','雜曲歌辭 竹枝 二','孫光憲','唐','唐诗','tang','','[]','亂繩千結絆人深，越羅萬丈表長尋。',32,'全唐诗/poet.tang.2000.json','["亂繩千結絆人深，越羅萬丈表長尋。", "楊柳在身垂意緒，藕花落盡見蓮心。"]'),
('c798ff8d-5eb4-4926-82b2-bc7f6bbbdeb3','雜曲歌辭 楊柳枝 一','白居易','唐','唐诗','tang','','["\u548f\u7269", "\u67f3\u6811", "\u4e50\u5e9c", "\u548f\u7269\u8bd7", "\u8fd1\u4ee3\u66f2\u8f9e"]','一樹春風萬萬枝，嫩於金色軟於絲。',32,'全唐诗/poet.tang.2000.json','["一樹春風萬萬枝，嫩於金色軟於絲。", "永豐西角荒園裏，盡日無人屬阿誰。"]'),
('c279c714-6ac2-4c87-af9c-dc80e3c20ba7','雜曲歌辭 楊柳枝 二','白居易','唐','唐诗','tang','','["\u67f3\u6811", "\u8fd1\u4ee3\u66f2\u8f9e", "\u4e50\u5e9c"]','一樹衰殘委泥土，雙枝榮耀植天庭。',32,'全唐诗/poet.tang.2000.json','["一樹衰殘委泥土，雙枝榮耀植天庭。", "定知玄象今春後，柳宿光中添兩星。"]'),
('bee3cd27-8bb4-49b5-9e23-7d054908e6e7','雜曲歌辭 楊柳枝 一','白居易','唐','唐诗','tang','','[]','六么水調家家唱，白雪梅花處處吹。',32,'全唐诗/poet.tang.2000.json','["六么水調家家唱，白雪梅花處處吹。", "古歌舊曲君休聽，聽取新翻楊柳枝。"]'),
('0affef8d-094a-4955-9ab1-04fb2a16966b','雜曲歌辭 楊柳枝 二','白居易','唐','唐诗','tang','','[]','陶令門前四五樹，亞夫營裏百千條。',32,'全唐诗/poet.tang.2000.json','["陶令門前四五樹，亞夫營裏百千條。", "何似東都正二月，黃金枝映洛陽橋。"]'),
('dea9313c-3f8b-47be-bf52-0ba0c7b879b8','雜曲歌辭 楊柳枝 三','白居易','唐','唐诗','tang','','[]','依依嫋嫋復青青，句引清風無限情。',32,'全唐诗/poet.tang.2000.json','["依依嫋嫋復青青，句引清風無限情。", "白雪花繁空撲地，綠絲條弱不勝鶯。"]'),
('217cd97f-80d4-4b42-ade3-87e558da16a8','雜曲歌辭 楊柳枝 四','白居易','唐','唐诗','tang','','[]','紅板江橋青酒旗，館娃宮暖日斜時。',32,'全唐诗/poet.tang.2000.json','["紅板江橋青酒旗，館娃宮暖日斜時。", "可憐雨歇東風定，萬樹千條各自垂。"]'),
('3560c3d4-ef9f-4a41-b5eb-3c0a751df7f9','雜曲歌辭 楊柳枝 五','白居易','唐','唐诗','tang','','[]','蘇州楊柳任君誇，更有錢塘勝館娃。',32,'全唐诗/poet.tang.2000.json','["蘇州楊柳任君誇，更有錢塘勝館娃。", "若解多情尋小小，綠楊深處是蘇家。"]'),
('0724d85f-da02-4fda-8ea4-23490ffec36c','雜曲歌辭 楊柳枝 六','白居易','唐','唐诗','tang','','[]','蘇家小女舊知名，楊柳風前別有情。',32,'全唐诗/poet.tang.2000.json','["蘇家小女舊知名，楊柳風前別有情。", "剝條盤作銀環樣，卷葉吹爲玉笛聲。"]'),
('7838c975-46db-4207-95ff-79cd5aa726eb','雜曲歌辭 楊柳枝 七','白居易','唐','唐诗','tang','','[]','葉含濃露如啼眼，枝嫋輕風似舞腰。',32,'全唐诗/poet.tang.2000.json','["葉含濃露如啼眼，枝嫋輕風似舞腰。", "小樹不禁攀折苦，乞君留取兩三條。"]'),
('0485d5de-635b-4d89-8633-7c9bbf8cd319','雜曲歌辭 楊柳枝 八','白居易','唐','唐诗','tang','','[]','人言柳葉似愁眉，更有愁腸似柳絲。',32,'全唐诗/poet.tang.2000.json','["人言柳葉似愁眉，更有愁腸似柳絲。", "柳絲挽斷腸牽斷，彼此應無續得期。"]'),
('7919cf3e-24f0-494b-b1d7-cf441b743eb6','雜曲歌辭 楊柳枝','盧貞','唐','唐诗','tang','','[]','一樹依依在永豐，兩枝飛去杳無蹤。',32,'全唐诗/poet.tang.2000.json','["一樹依依在永豐，兩枝飛去杳無蹤。", "玉皇曾采人間曲，應逐歌聲入九重。"]'),
('187596fc-5d5c-482c-9d7d-2c6b8bab093c','雜曲歌辭 楊柳枝 一','劉禹錫','唐','唐诗','tang','','[]','塞北梅花羌笛吹，淮南桂樹小山詞。',32,'全唐诗/poet.tang.2000.json','["塞北梅花羌笛吹，淮南桂樹小山詞。", "請君莫奏前朝曲，聽唱新翻楊柳枝。"]'),
('29482a7d-b353-48eb-8094-f08b572739b7','雜曲歌辭 楊柳枝 二','劉禹錫','唐','唐诗','tang','','[]','南陌東城春早時，相逢何處不依依。',32,'全唐诗/poet.tang.2000.json','["南陌東城春早時，相逢何處不依依。", "桃紅李白皆誇好，須得垂楊相發輝。"]'),
('7010856b-a328-4e29-b395-65b77f8f0f50','雜曲歌辭 楊柳枝 三','劉禹錫','唐','唐诗','tang','','[]','鳳闕輕遮翡翠帷，龍墀遙望麴塵絲。',32,'全唐诗/poet.tang.2000.json','["鳳闕輕遮翡翠帷，龍墀遙望麴塵絲。", "御溝春水柳暉映，狂殺長安年少兒。"]'),
('a1218522-a4b2-4bcb-b402-c44c032eed42','雜曲歌辭 楊柳枝 四','劉禹錫','唐','唐诗','tang','','[]','金谷園中鶯亂飛，銅駝陌上好風吹。',32,'全唐诗/poet.tang.2000.json','["金谷園中鶯亂飛，銅駝陌上好風吹。", "城東桃李須臾盡，爭似垂楊無限時。"]'),
('507c64d7-be4c-4c96-9297-7de37d506e3c','雜曲歌辭 楊柳枝 五','劉禹錫','唐','唐诗','tang','','[]','花萼樓前初種時，美人樓上鬬腰支。',32,'全唐诗/poet.tang.2000.json','["花萼樓前初種時，美人樓上鬬腰支。", "如今拋擲上街裏，露葉如啼欲恨誰。"]'),
('9eabde8a-de35-452e-abe5-c85d34bac1a7','雜曲歌辭 楊柳枝 六','劉禹錫','唐','唐诗','tang','','[]','煬帝行宮汴水濱，數株殘柳不勝春。',32,'全唐诗/poet.tang.2000.json','["煬帝行宮汴水濱，數株殘柳不勝春。", "昨來風起花如雪，飛入宮牆不見人。"]'),
('55560145-871c-4ff9-96d7-d30c1a7ddf6d','雜曲歌辭 楊柳枝 七','劉禹錫','唐','唐诗','tang','','[]','御陌青門拂地垂，千條金縷萬條絲。',32,'全唐诗/poet.tang.2000.json','["御陌青門拂地垂，千條金縷萬條絲。", "如今綰作同心結，將贈行人知不知。"]'),
('5f5cbeee-3fc0-4e83-a702-1797d0a7d98d','雜曲歌辭 楊柳枝 八','劉禹錫','唐','唐诗','tang','','[]','城外春風滿酒旗，行人揮袂日西時。',32,'全唐诗/poet.tang.2000.json','["城外春風滿酒旗，行人揮袂日西時。", "長安陌上無窮樹，唯有垂楊管別離。"]'),
('5618d671-daf5-475c-9334-15c8bbc8e0b8','雜曲歌辭 楊柳枝 九','劉禹錫','唐','唐诗','tang','','[]','輕盈嫋娜占春華，舞榭妝樓處處遮。',32,'全唐诗/poet.tang.2000.json','["輕盈嫋娜占春華，舞榭妝樓處處遮。", "春盡絮飛留不得，隨風好去落誰家。"]'),
('f7e5a3c9-7114-4dc8-8eb2-c8f7efdd8f40','雜曲歌辭 楊柳枝 一','劉禹錫','唐','唐诗','tang','','[]','[揚]子江頭煙景迷，隋家宮樹拂金堤。',34,'全唐诗/poet.tang.2000.json','["[揚]子江頭煙景迷，隋家宮樹拂金堤。", "嵯峨猶有當時色，半蘸波中水鳥棲。"]'),
('894c1eec-7e59-40ab-b7d1-0b6e47d96b2b','雜曲歌辭 楊柳枝 二','劉禹錫','唐','唐诗','tang','','[]','迎得春光先到來，淺黃輕綠映樓臺。',32,'全唐诗/poet.tang.2000.json','["迎得春光先到來，淺黃輕綠映樓臺。", "只緣嫋娜多情思，便被春風長請挼。"]'),
('90663246-61d0-478b-932f-e57ba872f6d0','雜曲歌辭 楊柳枝 三','劉禹錫','唐','唐诗','tang','','[]','巫峽巫山楊柳多，朝雲暮雨遠相和。',32,'全唐诗/poet.tang.2000.json','["巫峽巫山楊柳多，朝雲暮雨遠相和。", "因想陽臺無限事，爲君迴唱竹枝歌。"]'),
('ec8d88be-15d5-4eab-9fb3-f7736e9a8e1e','雜曲歌辭 楊柳枝 一','李商隱','唐','唐诗','tang','','[]','暫憑樽酒送無憀，莫損愁眉與細腰。',32,'全唐诗/poet.tang.2000.json','["暫憑樽酒送無憀，莫損愁眉與細腰。", "人世死前唯有別，春風爭擬惜長條。"]'),
('55526114-de81-4cdc-94de-d691476415fb','雜曲歌辭 楊柳枝 二','李商隱','唐','唐诗','tang','','[]','含煙惹霧每依依，萬緒千條拂落暉。',32,'全唐诗/poet.tang.2000.json','["含煙惹霧每依依，萬緒千條拂落暉。", "爲報行人休盡折，半留相送半迎歸。"]'),
('4199debb-ddf2-4883-b2ec-ab23bec67736','雜曲歌辭 楊柳枝','韓琮','唐','唐诗','tang','','[]','梁苑隋堤事已空，萬條猶舞舊春風。',32,'全唐诗/poet.tang.2000.json','["梁苑隋堤事已空，萬條猶舞舊春風。", "那堪更想千年後，誰見楊花入漢宮。"]'),
('0d53be0f-c369-4ae8-967b-29735494f879','雜曲歌辭 楊柳枝','施肩吾','唐','唐诗','tang','','[]','傷見路傍楊柳春，一枝折盡一重新。',32,'全唐诗/poet.tang.2000.json','["傷見路傍楊柳春，一枝折盡一重新。", "今年還折去年處，不送去年離別人。"]'),
('e8c91841-9fd9-4772-b208-7ae09ecd7c52','雜曲歌辭 楊柳枝 一','溫庭筠','唐','唐诗','tang','','[]','宜春苑外最長條，閑嫋春風伴舞腰。',32,'全唐诗/poet.tang.2000.json','["宜春苑外最長條，閑嫋春風伴舞腰。", "正是玉人腸斷處，一渠春水赤欄橋。"]'),
('cfcba2d3-56c8-4921-bbdb-fb446bc99993','雜曲歌辭 楊柳枝 二','溫庭筠','唐','唐诗','tang','','[]','南內牆東御路傍，預知春色柳絲黃。',32,'全唐诗/poet.tang.2000.json','["南內牆東御路傍，預知春色柳絲黃。", "杏花未肯無情思，何事情人最斷腸。"]'),
('7d4b8467-fff8-4589-a1b1-6541fa01d8be','雜曲歌辭 楊柳枝 三','溫庭筠','唐','唐诗','tang','','["\u548f\u7269", "\u67f3\u6811", "\u5199\u4eba", "\u548f\u7269\u8bd7"]','蘇小門前柳萬條，毿毿金線拂平橋。',32,'全唐诗/poet.tang.2000.json','["蘇小門前柳萬條，毿毿金線拂平橋。", "黃鶯不語東風起，深閉朱門伴細腰。"]'),
('c3c0dd44-612a-452e-9e21-ea93dca451ae','雜曲歌辭 楊柳枝 四','溫庭筠','唐','唐诗','tang','','[]','金縷毿毿碧瓦溝，六宮眉黛惹春愁。',32,'全唐诗/poet.tang.2000.json','["金縷毿毿碧瓦溝，六宮眉黛惹春愁。", "晚來更帶龍池雨，半拂欄干半入樓。"]'),
('835a0bce-abb5-4d6e-9daa-76dafcb7cde4','雜曲歌辭 楊柳枝 五','溫庭筠','唐','唐诗','tang','','[]','館娃宮外鄴城西，遠映征帆近拂堤。',32,'全唐诗/poet.tang.2000.json','["館娃宮外鄴城西，遠映征帆近拂堤。", "繫得王孫歸意切，不關春草綠萋萋。"]'),
('4a8de963-4820-4dbf-9dbb-152cbfb3770b','雜曲歌辭 楊柳枝 六','溫庭筠','唐','唐诗','tang','','[]','兩兩黃鸝色似金，嫋枝啼露動芳音。',32,'全唐诗/poet.tang.2000.json','["兩兩黃鸝色似金，嫋枝啼露動芳音。", "春來幸自長如線，可惜牽纏蕩子心。"]'),
('2baec0cf-057f-451f-a85b-e68498daa912','雜曲歌辭 楊柳枝 七','溫庭筠','唐','唐诗','tang','','["\u67f3\u6811", "\u5bab\u5ef7", "\u5199\u666f"]','御柳如絲映九重，鳳凰窗柱繡芙蓉。',32,'全唐诗/poet.tang.2000.json','["御柳如絲映九重，鳳凰窗柱繡芙蓉。", "景陽樓伴千條露，一面新妝待曉鍾。"]'),
('133b4d40-ef24-4056-b825-9084969e7d0f','雜曲歌辭 楊柳枝 八','溫庭筠','唐','唐诗','tang','','[]','織錦機邊鶯語頻，停梭垂淚憶征人。',32,'全唐诗/poet.tang.2000.json','["織錦機邊鶯語頻，停梭垂淚憶征人。", "塞門三月猶蕭索，縱有垂楊未覺春。"]'),
('2cfbda92-0eca-4326-84ff-29d47fbf85fd','雜曲歌辭 楊柳枝 一','皇甫松','唐','唐诗','tang','','[]','春入行宮映翠微，玄宗侍女舞烟絲。',32,'全唐诗/poet.tang.2000.json','["春入行宮映翠微，玄宗侍女舞烟絲。", "如今柳向空城綠，玉笛何人更把吹。"]'),
('5f578ab9-742f-4b95-b53e-984209c4bbb2','雜曲歌辭 楊柳枝 二','皇甫松','唐','唐诗','tang','','[]','爛熳春歸水國時，吳王宮殿柳垂絲。',32,'全唐诗/poet.tang.2000.json','["爛熳春歸水國時，吳王宮殿柳垂絲。", "黃鶯長呌空閨畔，西子無因更得知。"]'),
('3298dac3-8bd3-440e-b4c2-463633a3373d','雜曲歌辭 楊柳枝 一','僧齊己','唐','唐诗','tang','','[]','鳳樓高映綠陰陰，凝碧多含雨露深。',32,'全唐诗/poet.tang.2000.json','["鳳樓高映綠陰陰，凝碧多含雨露深。", "莫謂一枝柔軟力，幾曾牽破別離心。"]'),
('37592b5c-0fd6-4d9a-828e-e7c6f7adccff','雜曲歌辭 楊柳枝 二','僧齊己','唐','唐诗','tang','','[]','館娃宮畔響廊前，依託吳王養翠煙。',32,'全唐诗/poet.tang.2000.json','["館娃宮畔響廊前，依託吳王養翠煙。", "劒去國亡臺榭毀，却隨紅樹噪秋蟬。"]'),
('d4ddbbfb-d0c7-4800-972c-0c6e9f708f0c','雜曲歌辭 楊柳枝 三','僧齊己','唐','唐诗','tang','','[]','穠低似中陶潛酒，軟極如傷宋玉風。',32,'全唐诗/poet.tang.2000.json','["穠低似中陶潛酒，軟極如傷宋玉風。", "多謝將軍遶營種，翠中閑卓戰旗紅。"]'),
('e68d7789-eef5-4c31-859a-74c28a8f4237','雜曲歌辭 楊柳枝 四','僧齊己','唐','唐诗','tang','','[]','高僧愛惜遮江寺，遊子傷殘露野橋。',32,'全唐诗/poet.tang.2000.json','["高僧愛惜遮江寺，遊子傷殘露野橋。", "爭似著行垂上苑，碧桃紅杏對搖搖。"]'),
('353f48c1-b347-499a-a0c0-ed3f08740f1a','雜曲歌辭 楊柳枝 一','張祜','唐','唐诗','tang','','[]','莫折宮前楊柳枝，玄宗曾向笛中吹。',32,'全唐诗/poet.tang.2000.json','["莫折宮前楊柳枝，玄宗曾向笛中吹。", "傷心日暮煙霞起，無限春愁生翠眉。"]'),
('2c0a7d66-b63c-447b-ad4f-243373f868f2','雜曲歌辭 楊柳枝 二','張祜','唐','唐诗','tang','','[]','凝碧池邊斂翠眉，景陽臺下綰青絲。',32,'全唐诗/poet.tang.2000.json','["凝碧池邊斂翠眉，景陽臺下綰青絲。", "那勝妃子朝元閣，玉手和煙弄一枝。"]'),
('975a3b4e-ac73-41a7-bdff-616462179a5f','雜曲歌辭 楊柳枝 一','孫魴','唐','唐诗','tang','','[]','靈和風暖太昌春，舞線搖絲向昔人。',32,'全唐诗/poet.tang.2000.json','["靈和風暖太昌春，舞線搖絲向昔人。", "何似曉來江雨後，一行如畫隔遙津。"]'),
('d37c0944-3e2e-4119-9cb0-1c538421dc88','雜曲歌辭 楊柳枝 二','孫魴','唐','唐诗','tang','','[]','彭澤初栽五樹時，只應閑看一枝枝。',32,'全唐诗/poet.tang.2000.json','["彭澤初栽五樹時，只應閑看一枝枝。", "不知天意風流處，要與佳人學畫眉。"]'),
('b49c6ed5-cfe9-4e7f-887b-09c32f5ea770','雜曲歌辭 楊柳枝 三','孫魴','唐','唐诗','tang','','[]','暖傍離亭靜拂橋，入流穿檻綠搖搖。',32,'全唐诗/poet.tang.2000.json','["暖傍離亭靜拂橋，入流穿檻綠搖搖。", "不知落日誰相送，魂斷千條與萬條。"]'),
('29d1ec36-3569-4bd3-9f05-b4f067dcf9c6','雜曲歌辭 楊柳枝 四','孫魴','唐','唐诗','tang','','[]','春來綠樹遍天涯，未見垂楊未可誇。',32,'全唐诗/poet.tang.2000.json','["春來綠樹遍天涯，未見垂楊未可誇。", "晴日萬株烟一陣，閑坊兼是莫愁家。"]'),
('449f2973-8648-4608-b5fa-ef40cc98ce69','雜曲歌辭 楊柳枝 五','孫魴','唐','唐诗','tang','','[]','十首當年有舊詞，唱青歌翠幾無遺。',32,'全唐诗/poet.tang.2000.json','["十首當年有舊詞，唱青歌翠幾無遺。", "未曾得向行人道，不爲離情莫折伊。"]'),
('15fdfac2-e4e5-4b8a-b766-47eb1c570459','雜曲歌辭 楊柳枝 一','薛能','唐','唐诗','tang','','[]','華清高樹出離宮，南陌柔條帶暖風。',32,'全唐诗/poet.tang.2000.json','["華清高樹出離宮，南陌柔條帶暖風。", "誰見輕陰是良夜，瀑泉聲畔月明中。"]'),
('f1d44017-5866-4cfb-86c1-7b7230ed9794','雜曲歌辭 楊柳枝 二','薛能','唐','唐诗','tang','','[]','洛橋晴影覆江船，羌笛秋聲濕塞烟。',32,'全唐诗/poet.tang.2000.json','["洛橋晴影覆江船，羌笛秋聲濕塞烟。", "閑想習池公宴罷，水蒲風絮夕陽天。"]'),
('28fa9828-5ffe-4e34-a086-1906dcfa0edd','雜曲歌辭 楊柳枝 三','薛能','唐','唐诗','tang','','[]','嫩綠輕懸似綴旒，路人遙見隔宮樓。',32,'全唐诗/poet.tang.2000.json','["嫩綠輕懸似綴旒，路人遙見隔宮樓。", "誰能更近丹墀種，解播皇風入九州。"]'),
('f91f24a2-63c5-4a21-b733-94c8e94e3079','雜曲歌辭 楊柳枝 四','薛能','唐','唐诗','tang','','[]','暖風晴日斷浮埃，廢路新條發釣臺。',32,'全唐诗/poet.tang.2000.json','["暖風晴日斷浮埃，廢路新條發釣臺。", "處處輕輕可惆悵，後人攀處古人栽。"]'),
('8072e986-45ef-45ed-beb8-040dbc6faeb9','雜曲歌辭 楊柳枝 五','薛能','唐','唐诗','tang','','[]','潭上江邊嫋嫋垂，日高風靜絮相隨。',32,'全唐诗/poet.tang.2000.json','["潭上江邊嫋嫋垂，日高風靜絮相隨。", "青樓一樹無人見，正是女郎眠覺時。"]'),
('a5e5a4d7-0cbe-4661-af19-f8a890c39258','雜曲歌辭 楊柳枝 六','薛能','唐','唐诗','tang','','[]','汴水高懸百萬條，風清兩岸一時搖。',32,'全唐诗/poet.tang.2000.json','["汴水高懸百萬條，風清兩岸一時搖。", "隋家力盡虛栽得，無限春風屬聖朝。"]'),
('68465420-aa16-40f1-9135-c98161bc0b2d','雜曲歌辭 楊柳枝 七','薛能','唐','唐诗','tang','','[]','和花烟樹九重城，夾路春陰十萬營。',32,'全唐诗/poet.tang.2000.json','["和花烟樹九重城，夾路春陰十萬營。", "唯向邊頭不堪望，一株顦顇少人行。"]'),
('f350f56a-236f-47b2-b5c3-88af4f812bc2','雜曲歌辭 楊柳枝 八','薛能','唐','唐诗','tang','','[]','窗外齊垂旭日初，樓邊輕好暖風徐。',32,'全唐诗/poet.tang.2000.json','["窗外齊垂旭日初，樓邊輕好暖風徐。", "遊人莫道栽無益，桃李清陰却不如。"]'),
('ce40b604-9dbf-4a8b-be5f-1087991411d2','雜曲歌辭 楊柳枝 九','薛能','唐','唐诗','tang','','[]','衆木猶寒獨早青，御溝橋畔曲江亭。',32,'全唐诗/poet.tang.2000.json','["衆木猶寒獨早青，御溝橋畔曲江亭。", "陶家舊日應如此，一院春條綠遶廳。"]'),
('7368668e-9eaa-47fc-a801-a4405e2d9b1c','雜曲歌辭 楊柳枝 十','薛能','唐','唐诗','tang','','[]','帳偃纓垂細復繁，令人心想石家園。',32,'全唐诗/poet.tang.2000.json','["帳偃纓垂細復繁，令人心想石家園。", "風條月影皆堪重，何事侯門愛樹萱。"]'),
('4568b1d2-ed9f-4bbd-9947-064410a234a1','雜曲歌辭 楊柳枝 一','薛能','唐','唐诗','tang','','[]','數首新詞帶恨成，柳絲牽我我傷情。',32,'全唐诗/poet.tang.2000.json','["數首新詞帶恨成，柳絲牽我我傷情。", "柔娥幸有腰支穩，試踏吹聲作唱聲。"]'),
('1e26ce07-d2d2-43d0-a4cc-7d9a429e6b9f','雜曲歌辭 楊柳枝 二','薛能','唐','唐诗','tang','','[]','高出軍營遠映橋，賊兵曾斫火曾燒。',32,'全唐诗/poet.tang.2000.json','["高出軍營遠映橋，賊兵曾斫火曾燒。", "風流性在終難改，依舊春來萬萬條。"]'),
('4f316508-f241-44b3-82c1-7c186ac94926','雜曲歌辭 楊柳枝 三','薛能','唐','唐诗','tang','','[]','縣依陶令想嫌迂，營伴將軍即大麤。',32,'全唐诗/poet.tang.2000.json','["縣依陶令想嫌迂，營伴將軍即大麤。", "此日與君除萬恨，數篇風調更應無。"]'),
('f355cdf3-b0a6-464b-861a-470d7e0f6679','雜曲歌辭 楊柳枝 四','薛能','唐','唐诗','tang','','[]','狂似纖腰軟勝綿，自多情態更誰憐。',32,'全唐诗/poet.tang.2000.json','["狂似纖腰軟勝綿，自多情態更誰憐。", "遊人不折還堪恨，拋向橋邊與路邊。"]'),
('1cf97cf0-3351-4ed8-b21f-5f5e4055194c','雜曲歌辭 楊柳枝 五','薛能','唐','唐诗','tang','','[]','朝陽晴照綠楊烟，一別通波十七年。',32,'全唐诗/poet.tang.2000.json','["朝陽晴照綠楊烟，一別通波十七年。", "應有舊枝無處覓，萬株風裏卓旌旃。"]'),
('b39efc34-25d1-4773-9972-a9c79611eaaf','雜曲歌辭 楊柳枝 六','薛能','唐','唐诗','tang','','[]','晴垂芳態吐牙新，雨擺輕條濕面春。',16,'全唐诗/poet.tang.2000.json','["晴垂芳態吐牙新，雨擺輕條濕面春。"]'),
('7f92b6d4-b559-4e84-85e7-a8e7232502e2','雜曲歌辭 楊柳枝 七','薛能','唐','唐诗','tang','','[]','暖梳簪朵事登樓，因挂垂楊立地愁。',32,'全唐诗/poet.tang.2000.json','["暖梳簪朵事登樓，因挂垂楊立地愁。", "牽斷綠絲攀不得，半空懸著玉搔頭。"]'),
('64583f72-708b-4491-9062-569139e487e0','雜曲歌辭 楊柳枝 八','薛能','唐','唐诗','tang','','[]','西園高樹後庭根，處處尋芳有折痕。',32,'全唐诗/poet.tang.2000.json','["西園高樹後庭根，處處尋芳有折痕。", "終憶舊遊桃葉舍，一株斜映竹籬門。"]'),
('995df10a-d084-450a-8a24-be1df69c6b6d','雜曲歌辭 楊柳枝 九','薛能','唐','唐诗','tang','','[]','劉白蘇臺總近時，當初章句是誰推。',32,'全唐诗/poet.tang.2000.json','["劉白蘇臺總近時，當初章句是誰推。", "纖腰舞盡春楊柳，未有儂家一首詩。"]'),
('77530e99-324a-4ce4-aeeb-986eea8c56c5','雜曲歌辭 楊柳枝 一','牛嶠','唐','唐诗','tang','','["\u5bd3\u4eba", "\u540c\u60c5", "\u548f\u7269", "\u67f3\u6811", "\u548f\u7269\u8bd7"]','解凍風來末上青，解垂羅袖拜卿卿。',32,'全唐诗/poet.tang.2000.json','["解凍風來末上青，解垂羅袖拜卿卿。", "無端嫋娜臨官路，舞送行人過一生。"]'),
('418f0aad-1246-43c7-a2c1-923a7e133506','雜曲歌辭 楊柳枝 二','牛嶠','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u67f3\u6811", "\u548f\u7269\u8bd7"]','吳王宮裏色偏深，一簇纖條萬縷金。',32,'全唐诗/poet.tang.2000.json','["吳王宮裏色偏深，一簇纖條萬縷金。", "不憤錢塘蘇小小，引郎枝下結同心。"]'),
('3537415c-e55b-452e-a231-35ceb376ee56','雜曲歌辭 楊柳枝 三','牛嶠','唐','唐诗','tang','','[]','橋北橋南千萬條，恨伊張緒不相饒。',32,'全唐诗/poet.tang.2000.json','["橋北橋南千萬條，恨伊張緒不相饒。", "金羈白馬臨風望，認得羊家靜婉腰。"]'),
('8419d199-45c2-4b1c-bf48-822198b24712','雜曲歌辭 楊柳枝 四','牛嶠','唐','唐诗','tang','','[]','狂雪隨風撲馬飛，惹烟無力被風欹。',32,'全唐诗/poet.tang.2000.json','["狂雪隨風撲馬飛，惹烟無力被風欹。", "莫交移入靈和殿，宮女三千又妒伊。"]'),
('30d40e41-070f-4314-b279-17123fa9fc5a','雜曲歌辭 楊柳枝 五','牛嶠','唐','唐诗','tang','','[]','裊翠籠煙拂暖波，舞裙新染麴塵羅。',32,'全唐诗/poet.tang.2000.json','["裊翠籠煙拂暖波，舞裙新染麴塵羅。", "章華臺畔隋堤上，倚得春風爾許多。"]'),
('07f5b1c7-ca64-4ad1-8d52-158de29be63d','雜曲歌辭 楊柳枝 一','和凝','唐','唐诗','tang','','[]','軟碧搖煙似送人，映花時把翠眉嚬。',32,'全唐诗/poet.tang.2000.json','["軟碧搖煙似送人，映花時把翠眉嚬。", "青青自是風流主，漫颭金絲待洛神。"]'),
('12d9f990-20ad-456b-827d-dacd6ea09a70','雜曲歌辭 楊柳枝 二','和凝','唐','唐诗','tang','','[]','瑟瑟羅裙金縷腰，黛眉偎破未重描。',32,'全唐诗/poet.tang.2000.json','["瑟瑟羅裙金縷腰，黛眉偎破未重描。", "醉來咬損新花子，拽住仙郎儘放嬌。"]'),
('d21445d0-930f-43ac-b31b-de28e5ec6e6b','雜曲歌辭 楊柳枝 三','和凝','唐','唐诗','tang','','[]','鵲橋初就咽銀河，今夜仙郎自性和。',32,'全唐诗/poet.tang.2000.json','["鵲橋初就咽銀河，今夜仙郎自性和。", "不是昔年攀桂樹，豈能月裏索姮娥。"]'),
('a9d921b6-4f1c-4c4e-8947-febee301c85c','雜曲歌辭 楊柳枝 一','孫光憲','唐','唐诗','tang','','[]','閭門風暖落花乾，飛遍江南雪不寒。',32,'全唐诗/poet.tang.2000.json','["閭門風暖落花乾，飛遍江南雪不寒。", "獨有晚來臨水驛，閑人多凭赤闌干。"]'),
('e6aba936-75bb-4b3b-a888-8444a74d0f93','雜曲歌辭 楊柳枝 二','孫光憲','唐','唐诗','tang','','[]','有池有榭即濛濛，浸潤翻成長養功。',32,'全唐诗/poet.tang.2000.json','["有池有榭即濛濛，浸潤翻成長養功。", "恰似有人長點檢，著行排立向春風。"]'),
('e88d5283-8031-4ecf-b613-826783d40296','雜曲歌辭 楊柳枝 三','孫光憲','唐','唐诗','tang','','[]','根柢雖然傍濁河，無妨終日近笙歌。',32,'全唐诗/poet.tang.2000.json','["根柢雖然傍濁河，無妨終日近笙歌。", "驂驂金帶誰堪比，還笑黃鶯不較多。"]'),
('b2e8d143-9385-411c-93ff-57b99918841a','雜曲歌辭 楊柳枝 四','孫光憲','唐','唐诗','tang','','[]','萬株枯槁怨亡隋，似弔吳臺各自垂。',32,'全唐诗/poet.tang.2000.json','["萬株枯槁怨亡隋，似弔吳臺各自垂。", "好是淮陰明月裏，酒樓橫笛不勝吹。"]'),
('52598ca7-8d4b-40c4-9814-e82a51ec379d','雜曲歌辭 浪淘沙 一','劉禹錫','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u751f\u6d3b", "\u7530\u56ed", "\u4e94\u5e74\u7ea7\u4e0b\u518c", "\u5411\u5f80"]','九曲黃河萬里沙，浪淘風簸自天涯。',32,'全唐诗/poet.tang.2000.json','["九曲黃河萬里沙，浪淘風簸自天涯。", "如今直上銀河去，同到牽牛織女家。"]'),
('fc30758f-4193-49ff-af8d-dbc8695f082b','雜曲歌辭 浪淘沙 二','劉禹錫','唐','唐诗','tang','','[]','洛水橋邊春日斜，碧流輕淺見瓊沙。',32,'全唐诗/poet.tang.2000.json','["洛水橋邊春日斜，碧流輕淺見瓊沙。", "無端陌上狂風急，驚起鴛鴦出浪花。"]'),
('0e0c0380-f696-4e39-ab6b-116e307d07cd','雜曲歌辭 浪淘沙 三','劉禹錫','唐','唐诗','tang','','[]','汴水東流虎眼文，清淮曉色鴨頭春。',32,'全唐诗/poet.tang.2000.json','["汴水東流虎眼文，清淮曉色鴨頭春。", "君看渡口淘沙處，渡却人間多少人。"]'),
('529c0d3e-48e1-4c90-b552-53472032523c','雜曲歌辭 浪淘沙 四','劉禹錫','唐','唐诗','tang','','[]','鸚鵡洲頭浪颭沙，青樓春望日將斜。',32,'全唐诗/poet.tang.2000.json','["鸚鵡洲頭浪颭沙，青樓春望日將斜。", "銜泥燕子爭歸舍，獨自狂夫不憶家。"]'),
('0980785c-7c0b-4dad-8ce9-7412dab56f0e','雜曲歌辭 浪淘沙 五','劉禹錫','唐','唐诗','tang','','[]','濯錦江邊兩岸花，春風吹浪正淘沙。',32,'全唐诗/poet.tang.2000.json','["濯錦江邊兩岸花，春風吹浪正淘沙。", "女郎剪下鴛鴦錦，將向中流疋晚霞。"]'),
('b29b3e4b-125f-4b2f-a0fb-44e5d40694f5','雜曲歌辭 浪淘沙 六','劉禹錫','唐','唐诗','tang','','[]','日照澄洲江霧開，淘金女伴滿江隈。',32,'全唐诗/poet.tang.2000.json','["日照澄洲江霧開，淘金女伴滿江隈。", "美人首飾侯王印，盡是沙中浪底來。"]'),
('ff1a5ac4-3d25-4735-a33a-175b394c5d88','雜曲歌辭 浪淘沙 七','劉禹錫','唐','唐诗','tang','','[]','八月濤聲吼地來，頭高數丈觸山迴。',32,'全唐诗/poet.tang.2000.json','["八月濤聲吼地來，頭高數丈觸山迴。", "須臾却入海門去，卷起沙堆似雪堆。"]'),
('1f4d7c75-238b-4f92-917c-bcdf16e8c7a4','雜曲歌辭 浪淘沙 八','劉禹錫','唐','唐诗','tang','','[]','莫道讒言如浪深，莫言遷客似沙沈。',32,'全唐诗/poet.tang.2000.json','["莫道讒言如浪深，莫言遷客似沙沈。", "千淘萬漉雖辛苦，吹盡狂沙始到金。"]'),
('fe65ba74-a10a-460f-b406-7ede22d6b4db','雜曲歌辭 浪淘沙 九','劉禹錫','唐','唐诗','tang','','[]','流水淘沙不暫停，前波未滅後波生。',32,'全唐诗/poet.tang.2000.json','["流水淘沙不暫停，前波未滅後波生。", "令人忽憶瀟湘渚，迴唱迎神三兩聲。"]'),
('c3c752d8-19ad-4fb6-997c-372f0feb2ddc','雜曲歌辭 浪淘沙 一','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','一泊沙來一泊去，一重浪滅一重生。',32,'全唐诗/poet.tang.2000.json','["一泊沙來一泊去，一重浪滅一重生。", "相攪相淘無歇日，會交山海一時平。"]'),
('a0f2e998-354c-4294-a226-f1e86fb44df0','雜曲歌辭 浪淘沙 二','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','白浪茫茫與海連，平沙浩浩四無邊。',32,'全唐诗/poet.tang.2000.json','["白浪茫茫與海連，平沙浩浩四無邊。", "暮去朝來淘不住，遂令東海變桑田。"]'),
('7efea582-e182-40d2-bdc6-e8f3ca1aa341','雜曲歌辭 浪淘沙 三','白居易','唐','唐诗','tang','','[]','青草湖中萬里程，黃梅雨裏一人行。',32,'全唐诗/poet.tang.2000.json','["青草湖中萬里程，黃梅雨裏一人行。", "愁見灘頭夜泊處，風翻暗浪打船聲。"]'),
('c84b9b43-e843-4bdd-b17d-1b08a0b2739b','雜曲歌辭 浪淘沙 四','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u5987\u5973", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u7231\u60c5", "\u5fe0\u8d1e", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','借問江湖與海水，何似君情與妾心。',32,'全唐诗/poet.tang.2000.json','["借問江湖與海水，何似君情與妾心。", "相恨不如潮有信，相思始覺海非深。"]'),
('d413cfff-0a86-4664-9cba-b6f83972c332','雜曲歌辭 浪淘沙 五','白居易','唐','唐诗','tang','','["\u79bb\u522b", "\u4f24\u611f", "\u7231\u60c5"]','海底飛塵終有日，山頭化石豈無時。',32,'全唐诗/poet.tang.2000.json','["海底飛塵終有日，山頭化石豈無時。", "誰道小郎拋小婦，船頭一去沒迴期。"]'),
('42435311-9d8b-476d-96b3-20f36c22325b','雜曲歌辭 浪淘沙 六','白居易','唐','唐诗','tang','','[]','隨波逐浪到天涯，遷客生還有幾家。',32,'全唐诗/poet.tang.2000.json','["隨波逐浪到天涯，遷客生還有幾家。", "却到帝鄉重富貴，請君莫忘浪淘沙。"]'),
('b96ade28-3647-489f-b892-e404be2b6c26','雜曲歌辭 浪淘沙 一','皇甫松','唐','唐诗','tang','','[]','灘頭細草接疎林，浪惡罾船半欲沈。',32,'全唐诗/poet.tang.2000.json','["灘頭細草接疎林，浪惡罾船半欲沈。", "宿鷺眠洲非舊浦，去年沙觜是江心。"]'),
('259186b3-61f5-4a2f-9e97-9af5e32a4fdd','雜曲歌辭 浪淘沙 二','皇甫松','唐','唐诗','tang','','[]','蠻歌豆蔻北人愁，松雨蒲風夜艇秋。',32,'全唐诗/poet.tang.2000.json','["蠻歌豆蔻北人愁，松雨蒲風夜艇秋。", "浪起鵁鶄眠不得，寒沙細細入江流。"]'),
('180ab533-0c67-4513-b77d-268b0bfbac0e','雜曲歌辭 紇那曲 一','劉禹錫','唐','唐诗','tang','','[]','楊柳鬱青青，竹枝無限情。',24,'全唐诗/poet.tang.2000.json','["楊柳鬱青青，竹枝無限情。", "同郎一回顧，聽唱紇那聲。"]'),
('103d5c6f-d81f-4350-9208-82a04347c662','雜曲歌辭 紇那曲 二','劉禹錫','唐','唐诗','tang','','[]','踏曲興無窮，調同詞不同。',24,'全唐诗/poet.tang.2000.json','["踏曲興無窮，調同詞不同。", "願郎千萬壽，長作主人翁。"]'),
('6a0ec327-a23d-4dec-aa45-2ff058ef8579','雜曲歌辭 瀟湘神二曲 一','劉禹錫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u548f\u7269", "\u5a49\u7ea6"]','湘水流，湘水流，九疑雲物至今愁。',32,'全唐诗/poet.tang.2000.json','["湘水流，湘水流，九疑雲物至今愁。", "君問二妃何處所？零陵香草露中秋。"]'),
('4c3c5caf-0800-47ea-99b6-05dc96cd6cbd','雜曲歌辭 瀟湘神二曲 二','劉禹錫','唐','唐诗','tang','','["\u6000\u53e4", "\u548f\u7269", "\u54c0\u6028", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u548f\u7269\u8bd7", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','斑竹枝，斑竹枝，淚痕點點寄相思。',32,'全唐诗/poet.tang.2000.json','["斑竹枝，斑竹枝，淚痕點點寄相思。", "楚客欲聽瑤瑟怨，瀟湘深夜月明時。"]'),
('e9901206-250a-4157-863a-fb6a2f4113af','雜曲歌辭 拋毬樂 一','劉禹錫','唐','唐诗','tang','','[]','五綵繡團團，登君玳瑁筵。',36,'全唐诗/poet.tang.2000.json','["五綵繡團團，登君玳瑁筵。", "最宜紅燭下，偏稱落花前。", "上客如先起，應須贈一船。"]'),
('69232a1f-6d59-4055-b3fc-d235ce463406','雜曲歌辭 拋毬樂 二','劉禹錫','唐','唐诗','tang','','[]','春早見花枝，朝朝恨發遲。',36,'全唐诗/poet.tang.2000.json','["春早見花枝，朝朝恨發遲。", "及看花落後，却憶未開時。", "幸有拋毬樂，一杯君莫辭。"]'),
('acdced11-4d57-4972-86ca-857760554500','雜曲歌辭 太平樂 一','白居易','唐','唐诗','tang','','[]','歲豐仍節儉，時泰更銷兵。',24,'全唐诗/poet.tang.2000.json','["歲豐仍節儉，時泰更銷兵。", "聖念長如此，何憂不太平。"]'),
('1b6120ba-8af3-4172-9efe-a90d38f4d10f','雜曲歌辭 太平樂 二','白居易','唐','唐诗','tang','','[]','湛露浮堯酒，薰風起舜歌。',24,'全唐诗/poet.tang.2000.json','["湛露浮堯酒，薰風起舜歌。", "願同堯舜意，所樂在人和。"]'),
('41291a11-919c-4007-af8a-8fc503de866a','雜曲歌辭 太平樂','王涯','唐','唐诗','tang','','[]','風俗今和厚，君王在穆清。',24,'全唐诗/poet.tang.2000.json','["風俗今和厚，君王在穆清。", "行看采花曲，盡是太階平。"]'),
('cfd7f91f-9022-4396-b34e-390a0746680a','雜曲歌辭 太平樂','張仲素','唐','唐诗','tang','','[]','聖德超千古，皇威靜四方。',24,'全唐诗/poet.tang.2000.json','["聖德超千古，皇威靜四方。", "蒼生今息戰，無事覺時長。"]'),
('e837b2b0-b44b-4d86-b9b1-043ab9774cd5','雜曲歌辭 昇平樂 一','薛能','唐','唐诗','tang','','[]','正氣遶宮樓，皇居信上遊。',48,'全唐诗/poet.tang.2000.json','["正氣遶宮樓，皇居信上遊。", "遠岡延聖祚，平地載神州。", "會合皆重譯，潺湲近八流。", "中興豈假問，據此自千秋。"]'),
('00addf50-d832-47a4-85a1-ff8796bd5edb','雜曲歌辭 昇平樂 二','薛能','唐','唐诗','tang','','[]','寥泬敞延英，朝班立位橫。',48,'全唐诗/poet.tang.2000.json','["寥泬敞延英，朝班立位橫。", "宣傳無草動，拜舞有衣聲。", "鴛瓦雲消濕，蟲絲日照明。", "辛勤自不到，遙見似前生。"]'),
('515a01f6-41e7-4625-ba41-eb834abe7803','雜曲歌辭 昇平樂 三','薛能','唐','唐诗','tang','','[]','處處足歡聲，時康歲已深。',48,'全唐诗/poet.tang.2000.json','["處處足歡聲，時康歲已深。", "不同三尺劒，應似五絃琴。", "壽笑山猶盡，明嫌日有陰。", "何當憐一物，亦遣斷愁吟。"]'),
('d97b17ac-4563-4046-a953-42837eb64a8f','雜曲歌辭 昇平樂 四','薛能','唐','唐诗','tang','','[]','曙質絕埃氛，彤庭列禁軍。',48,'全唐诗/poet.tang.2000.json','["曙質絕埃氛，彤庭列禁軍。", "聖顏初對日，龍尾競緣雲。", "珮響交成韻，簾陰暖帶紋。", "逍遙豈有事，於此詠南薰。"]'),
('73d5a3e5-e678-458d-b62a-8d73ca6043dc','雜曲歌辭 昇平樂 五','薛能','唐','唐诗','tang','','[]','一物周天至，洪纖盡晏然。',48,'全唐诗/poet.tang.2000.json','["一物周天至，洪纖盡晏然。", "車書無異俗，甲子竝豐年。", "奇技皆歸朴，征夫亦服田。", "君王故不有，台鼎合韋弦。"]'),
('9b7e0702-6145-454a-9e1b-4c64fb357804','雜曲歌辭 昇平樂 六','薛能','唐','唐诗','tang','','[]','日日聽歌謠，區中盡祝堯。',48,'全唐诗/poet.tang.2000.json','["日日聽歌謠，區中盡祝堯。", "蟲蝗初不害，夷狄近全銷。", "史筆唯書瑞，天臺絕見祆。", "因令匹夫志，轉欲事清朝。"]'),
('4396e12f-b7af-4d77-980b-8ada24e1009e','雜曲歌辭 昇平樂 七','薛能','唐','唐诗','tang','','[]','品物盡昭蘇，神功復帝謨。',48,'全唐诗/poet.tang.2000.json','["品物盡昭蘇，神功復帝謨。", "他時應有壽，當代且無虞。", "賜曆通遐俗，移關入半胡。", "鷦鷯一何幸，於此寄微軀。"]'),
('0a7b745a-4764-4c5d-bc09-f1d06da27bb0','雜曲歌辭 昇平樂 八','薛能','唐','唐诗','tang','','[]','無戰復無私，堯時即此時。',48,'全唐诗/poet.tang.2000.json','["無戰復無私，堯時即此時。", "焚香臨極早，待月卷簾遲。", "端拱乾坤內，何言黈纊垂。", "君看聖明驗，只此是神龜。"]'),
('133d8de1-7491-465f-b6e5-8aa16c7fcb29','雜曲歌辭 昇平樂 九','薛能','唐','唐诗','tang','','[]','旭日上清穹，明堂坐聖聰。',48,'全唐诗/poet.tang.2000.json','["旭日上清穹，明堂坐聖聰。", "衣裳承瑞氣，冠冕蓋重曈。", "花木經宵露，旌旗立仗風。", "何期於此地，見說似仙宮。"]'),
('1505b3fd-6f22-4fb6-aa75-c11e19a160ce','雜曲歌辭 昇平樂 十','薛能','唐','唐诗','tang','','[]','五帝三皇主，蕭曹魏邴臣。',48,'全唐诗/poet.tang.2000.json','["五帝三皇主，蕭曹魏邴臣。", "文章惟反朴，戈甲盡生塵。", "諫紙應無用，朝綱自有倫。", "昇平不可紀，所見是閑人。"]'),
('a8617715-ad59-4da8-8071-e9aeb1760e6a','雜曲歌辭 金縷衣','不詳','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u60dc\u65f6", "\u52b1\u5fd7", "\u4e50\u5e9c"]','勸君莫惜金縷衣，勸君惜取少年時。',32,'全唐诗/poet.tang.2000.json','["勸君莫惜金縷衣，勸君惜取少年時。", "花開堪折直須折，莫待無花空折枝。"]'),
('d80df557-f7fa-4a5c-89f5-29722daf7412','雜曲歌辭 鳳歸雲 一','滕潛','唐','唐诗','tang','','[]','金井欄邊見羽儀，梧桐樹上宿寒枝。',32,'全唐诗/poet.tang.2000.json','["金井欄邊見羽儀，梧桐樹上宿寒枝。", "五陵公子憐文綵，畫與佳人刺繡衣。"]'),
('bd22b9a5-8bcc-48db-8572-276d97b97b38','雜曲歌辭 鳳歸雲 二','滕潛','唐','唐诗','tang','','[]','飲啄蓬山最上頭，和烟飛下禁城秋。',32,'全唐诗/poet.tang.2000.json','["飲啄蓬山最上頭，和烟飛下禁城秋。", "曾將弄玉歸雲去，金翿斜開十二樓。"]'),
('b22991a8-329e-4ec2-9c1e-b0648d7ab01b','雜曲歌辭 拜新月','李端','唐','唐诗','tang','','["\u5199\u4eba", "\u6708\u4eae"]','開簾見新月，便即下階拜。',24,'全唐诗/poet.tang.2000.json','["開簾見新月，便即下階拜。", "細語人不聞，北風吹裙帶。"]'),
('452ca2e5-a3f8-4dd1-b262-6ba2af5f3ea3','雜曲歌辭 拜新月','吉中孚妻張氏','唐','唐诗','tang','','[]','拜新月，拜月出堂前。',120,'全唐诗/poet.tang.2000.json','["拜新月，拜月出堂前。", "暗魄深籠桂，虛弓未引弦。", "拜新月，拜月妝樓上。", "鸞鏡未安臺，蛾眉已相向。", "拜新月，拜月不勝情，庭前風露清。", "月臨人自老，望月更長生。", "東家阿母亦拜月，一拜一悲聲斷絕。", "昔年拜月逞容儀，如今拜月雙淚垂。", "回看衆女拜新月，却憶紅閨年少時。"]'),
('ae558bdc-1af9-404f-887e-d65e4c57a166','雜曲歌辭 憶江南 一','白居易','唐','唐诗','tang','','[]','江南好，風景舊曾諳。',10,'全唐诗/poet.tang.2000.json','["江南好，風景舊曾諳。"]'),
('fccef71a-e31a-4cc4-980b-f1122d7043e2','雜曲歌辭 憶江南 二','白居易','唐','唐诗','tang','','[]','江南憶，最憶是杭州。',10,'全唐诗/poet.tang.2000.json','["江南憶，最憶是杭州。"]'),
('03cfc7ce-df84-4edb-a044-a169d1535f89','雜曲歌辭 憶江南 三','白居易','唐','唐诗','tang','','[]','江南憶，其次憶吳宮。',32,'全唐诗/poet.tang.2000.json','["江南憶，其次憶吳宮。", "吳酒一杯春竹葉，吳娃雙舞醉芙蓉，早晚復相逢。"]'),
('636705d2-4664-4762-b616-0857814bba5e','雜曲歌辭 憶江南 一','劉禹錫','唐','唐诗','tang','','[]','春過也，共惜豔陽年。',32,'全唐诗/poet.tang.2000.json','["春過也，共惜豔陽年。", "猶有桃花流水上，無辭竹葉醉樽前，惟待見青天。"]'),
('2f23cbd2-c44c-4e09-af67-32bf12a463a2','雜曲歌辭 憶江南 二','劉禹錫','唐','唐诗','tang','','[]','春去也，多謝洛城人。',32,'全唐诗/poet.tang.2000.json','["春去也，多謝洛城人。", "弱柳從風疑舉袂，叢蘭裛露似霑巾，獨笑亦含嚬。"]'),
('f5ca6564-0ee2-4b05-8666-b0208aebe17b','雜曲歌辭 宮中調笑 一','王建','唐','唐诗','tang','','["\u548f\u7269", "\u65f6\u5149", "\u4e50\u5e9c", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u548f\u7269\u8bd7", "\u611f\u6168"]','團扇，團扇，美人病來遮面。',40,'全唐诗/poet.tang.2000.json','["團扇，團扇，美人病來遮面。", "玉顏憔悴三年，誰復商量管弦。", "弦管，弦管，春草昭陽路斷。"]'),
('3116d012-d687-422e-8414-7fed23074cb6','雜曲歌辭 宮中調笑 二','王建','唐','唐诗','tang','','[]','胡蝶，胡蝶，飛上金花枝葉。',40,'全唐诗/poet.tang.2000.json','["胡蝶，胡蝶，飛上金花枝葉。", "君前對舞春風，百葉桃花樹紅。", "紅樹，紅樹，燕語鶯啼日暮。"]'),
('bb619ecf-2c06-4948-a889-2fffd1cc1585','雜曲歌辭 宮中調笑 三','王建','唐','唐诗','tang','','[]','羅袖，羅袖，暗舞春風依舊。',40,'全唐诗/poet.tang.2000.json','["羅袖，羅袖，暗舞春風依舊。", "遙看歌舞玉樓，好日新妝坐愁。", "愁坐，愁坐，一世虛生虛過。"]'),
('6e6f3108-c72f-47d8-8fdf-42db8151d952','雜曲歌辭 宮中調笑 四','王建','唐','唐诗','tang','','[]','楊柳，楊柳，日暮白沙渡口。',40,'全唐诗/poet.tang.2000.json','["楊柳，楊柳，日暮白沙渡口。", "船頭江水茫茫，商人少婦斷腸。", "腸斷，腸斷，鷓鴣夜飛失伴。"]'),
('51458e21-16fe-46dd-bbce-466d8995dcec','雜曲歌辭 宮中調笑 一','韋應物','唐','唐诗','tang','','["\u5bd3\u4eba", "\u5b64\u72ec", "\u8c6a\u653e", "\u9a6c", "\u5199\u9a6c"]','胡馬，胡馬，遠放燕支山下。',40,'全唐诗/poet.tang.2000.json','["胡馬，胡馬，遠放燕支山下。", "咆沙咆雪獨嘶，東望西望路迷。", "迷路，迷路，邊草無窮日暮。"]'),
('7dc254a8-0711-4e88-aa48-908d50d48364','雜曲歌辭 宮中調笑 二','韋應物','唐','唐诗','tang','','[]','河漢，河漢，曉挂秋城漫漫。',40,'全唐诗/poet.tang.2000.json','["河漢，河漢，曉挂秋城漫漫。", "愁人起望相思，江南塞北別離。", "離別，離別，河漢雖同路絕。"]'),
('64465c81-e318-49a7-9a36-924b59803c38','雜曲歌辭 轉應詞','戴叔倫','唐','唐诗','tang','','["\u8c6a\u653e", "\u5199\u666f", "\u8fb9\u585e", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u601d\u4e61", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','邊草，邊草，邊草盡來兵老。',40,'全唐诗/poet.tang.2000.json','["邊草，邊草，邊草盡來兵老。", "山南山北雪晴，千里萬里月明。", "明月，明月，胡笳一聲愁絕。"]'),
('107c1af3-4705-4b89-850e-e084085f36a4','雜曲歌辭 宮中行樂詞 一','李白','唐','唐诗','tang','','[]','小小生金屋，盈盈在紫微。',48,'全唐诗/poet.tang.2000.json','["小小生金屋，盈盈在紫微。", "山花插寶髻，石竹繡羅衣。", "每出深宮裏，常隨步輦歸。", "只愁歌舞散，化作綵雲飛。"]'),
('20ca3373-a182-4906-985f-fd8e187fb57f','雜曲歌辭 宮中行樂詞 二','李白','唐','唐诗','tang','','[]','柳色黃金嫩，梨花白雪香。',48,'全唐诗/poet.tang.2000.json','["柳色黃金嫩，梨花白雪香。", "玉樓巢翡翠，金殿鎖鴛鴦。", "選妓隨雕輦，徵歌出洞房。", "宮中誰第一，飛燕在昭陽。"]'),
('badc4095-7a06-4a24-ac6e-e341cede2f2c','雜曲歌辭 宮中行樂詞 三','李白','唐','唐诗','tang','','[]','盧橘爲秦樹，蒲萄出漢宮。',48,'全唐诗/poet.tang.2000.json','["盧橘爲秦樹，蒲萄出漢宮。", "煙花宜落日，絲管醉春風。", "笛奏龍鳴水，簫吟鳳下空。", "君王多樂事，何必向回中。"]'),
('fd80c5d5-5ad6-4c2c-bb23-cafb578a4295','雜曲歌辭 宮中行樂詞 四','李白','唐','唐诗','tang','','[]','玉樹春歸日，金宮樂事多。',48,'全唐诗/poet.tang.2000.json','["玉樹春歸日，金宮樂事多。", "後庭朝未入，輕輦夜相過。", "笑出花間語，嬌來燭下歌。", "莫教明月去，留著醉姮娥。"]'),
('da8ea895-4886-4fd0-891b-02ef16d12f60','雜曲歌辭 宮中行樂詞 五','李白','唐','唐诗','tang','','[]','繡戶香風暖，紗窗曙色新。',48,'全唐诗/poet.tang.2000.json','["繡戶香風暖，紗窗曙色新。", "宮花爭笑日，池草暗生春。", "綠樹聞歌鳥，青樓見舞人。", "昭陽桃李月，羅綺自相親。"]'),
('edf61fdf-ce02-4340-bb24-10f87e94b019','雜曲歌辭 宮中行樂詞 六','李白','唐','唐诗','tang','','[]','今日明光裏，還須結伴遊。',48,'全唐诗/poet.tang.2000.json','["今日明光裏，還須結伴遊。", "春風開紫殿，天樂下珠樓。", "豔舞全知巧，嬌歌半欲羞。", "更憐花月夜，宮女笑藏鉤。"]'),
('ba15a6be-da1e-427f-9d4e-aa440f9951bc','雜曲歌辭 宮中行樂詞 七','李白','唐','唐诗','tang','','[]','寒雪梅中盡，春風柳上歸。',48,'全唐诗/poet.tang.2000.json','["寒雪梅中盡，春風柳上歸。", "宮鶯嬌欲醉，簷燕語還飛。", "遲日明歌席，新花豔舞衣。", "晚來移綵仗，行樂泥光輝。"]'),
('a67fa3fa-c2d8-4a9d-a4bf-142cbb7abb20','雜曲歌辭 宮中行樂詞 八','李白','唐','唐诗','tang','','[]','水綠南薰殿，花紅北闕樓。',48,'全唐诗/poet.tang.2000.json','["水綠南薰殿，花紅北闕樓。", "鶯歌聞太液，鳳吹遶瀛洲。", "素女鳴珠佩，天人弄綵毬。", "今朝風日好，宜入未央遊。"]'),
('285f3aa7-dd99-4093-82d7-d1169be93f25','雜曲歌辭 宮中樂 一','令狐楚','唐','唐诗','tang','','[]','楚塞金陵靜，巴山玉壘空。',24,'全唐诗/poet.tang.2000.json','["楚塞金陵靜，巴山玉壘空。", "萬方無一事，端拱大明宮。"]'),
('1a80692d-16d6-4815-91d1-9ccdfbbd88fc','雜曲歌辭 宮中樂 二','令狐楚','唐','唐诗','tang','','[]','霜霽長楊苑，冰開太液池。',24,'全唐诗/poet.tang.2000.json','["霜霽長楊苑，冰開太液池。", "宮中行樂日，天下盛明時。"]'),
('bb80cdf8-51f3-4c21-bc0c-0d91a06cf5aa','雜曲歌辭 宮中樂 三','令狐楚','唐','唐诗','tang','','[]','柳色烟相似，梨花雪不如。',24,'全唐诗/poet.tang.2000.json','["柳色烟相似，梨花雪不如。", "春風真有意，一一麗皇居。"]'),
('809956a8-dcaf-4277-9a71-fbce74051301','雜曲歌辭 宮中樂 四','令狐楚','唐','唐诗','tang','','[]','月上宮花靜，煙含苑樹深。',24,'全唐诗/poet.tang.2000.json','["月上宮花靜，煙含苑樹深。", "銀臺門已閉，仙漏夜沈沈。"]'),
('3d97707a-791b-48dd-be26-9672cbdb6327','雜曲歌辭 宮中樂 五','令狐楚','唐','唐诗','tang','','[]','九重青鎖闥，百尺碧雲樓。',24,'全唐诗/poet.tang.2000.json','["九重青鎖闥，百尺碧雲樓。", "明月秋風起，珠簾上玉鉤。"]'),
('ac7c3a76-6aca-4818-8dd0-a2d6eb49fb21','雜曲歌辭 宮中樂 一','張仲素','唐','唐诗','tang','','[]','網戶交如綺，紗窗薄似烟。',24,'全唐诗/poet.tang.2000.json','["網戶交如綺，紗窗薄似烟。", "樂吹天上曲，人是月中仙。"]'),
('c52423cc-8f28-4e64-b673-61a8d66bfe5e','雜曲歌辭 宮中樂 二','張仲素','唐','唐诗','tang','','[]','翠匣開寒鏡，珠釵挂步搖。',24,'全唐诗/poet.tang.2000.json','["翠匣開寒鏡，珠釵挂步搖。", "妝成秖畏曉，更漏促春宵。"]'),
('5347fb05-5700-4f05-8caa-ec40bcbaa3e0','雜曲歌辭 宮中樂 三','張仲素','唐','唐诗','tang','','[]','江果瑤池實，金盤露井冰。',24,'全唐诗/poet.tang.2000.json','["江果瑤池實，金盤露井冰。", "甘泉將避暑，臺殿曉光凝。"]'),
('32dce2a2-9ad9-4af4-b523-9fa5e5d0bbc1','雜曲歌辭 宮中樂 四','張仲素','唐','唐诗','tang','','[]','月彩浮鸞殿，砧聲隔鳳樓。',24,'全唐诗/poet.tang.2000.json','["月彩浮鸞殿，砧聲隔鳳樓。", "笙歌臨水檻，紅燭乍迎秋。"]'),
('e7c05ead-1324-449f-a2c2-2736f0e19526','雜曲歌辭 宮中樂 五','張仲素','唐','唐诗','tang','','["\u9ec4\u5c71"]','奇樹留寒翠，神池結夕波。',24,'全唐诗/poet.tang.2000.json','["奇樹留寒翠，神池結夕波。", "黃山一夜雪，渭水雁聲多。"]'),
('61e4f760-45f1-4231-9a19-e69c0010edb1','雜曲歌辭 踏歌詞 一','崔液','唐','唐诗','tang','','[]','綵女迎金屋，仙姬出畫堂。',36,'全唐诗/poet.tang.2000.json','["綵女迎金屋，仙姬出畫堂。", "鴛鴦裁錦袖，翡翠帖花黃。", "歌響舞分行，豔色動流光。"]'),
('638c7caa-e512-4b6a-8c8e-f3ce5d708454','雜曲歌辭 踏歌詞 二','崔液','唐','唐诗','tang','','[]','庭際花微落，樓前漢已橫。',36,'全唐诗/poet.tang.2000.json','["庭際花微落，樓前漢已橫。", "金壺催夜盡，羅袖拂寒輕。", "樂笑暢歡情，未半著天明。"]'),
('fd4a5522-a206-4223-98e1-f19ad8b34496','雜曲歌辭 踏歌詞 一','謝偃','唐','唐诗','tang','','[]','春景嬌春臺，新露泣新梅。',48,'全唐诗/poet.tang.2000.json','["春景嬌春臺，新露泣新梅。", "春葉參差吐，新花重疊開。", "花影飛鶯去，歌聲度鳥來。", "倩看飄颻雪，何如舞袖迴。"]'),
('d514b940-ba90-4240-b574-ce212f15803d','雜曲歌辭 踏歌詞 二','謝偃','唐','唐诗','tang','','[]','逶迤度香閣，顧步出蘭閨。',48,'全唐诗/poet.tang.2000.json','["逶迤度香閣，顧步出蘭閨。", "欲遶鴛鴦殿，先過桃李蹊。", "風帶舒還卷，簪花舉復低。", "欲問今宵樂，但聽歌聲齊。"]'),
('f0c41f11-ee59-48d4-a426-c3aefd113ae3','雜曲歌辭 踏歌詞 三','謝偃','唐','唐诗','tang','','[]','夜久星沈沒，更深月影斜。',48,'全唐诗/poet.tang.2000.json','["夜久星沈沒，更深月影斜。", "裙輕纔動佩，鬟薄不勝花。", "細風吹寶袜，輕露濕紅紗。", "相看樂未已，蘭燈照九華。"]'),
('639eeff6-4209-44c7-a7b7-e1fe5f80f0de','雜曲歌辭 踏歌詞 一','張說','唐','唐诗','tang','','[]','花蕚樓前雨露新，長安城裏太平人。',32,'全唐诗/poet.tang.2000.json','["花蕚樓前雨露新，長安城裏太平人。", "龍銜火樹千燈豔，雞踏蓮花萬歲春。"]'),
('5e998972-8925-45e1-a3bd-e7f8ab5c26a5','雜曲歌辭 踏歌詞 二','張說','唐','唐诗','tang','','[]','帝宮三五戲春臺，行雨流風莫妒來。',32,'全唐诗/poet.tang.2000.json','["帝宮三五戲春臺，行雨流風莫妒來。", "西域燈輪千影合，東華金闕萬重開。"]'),
('577b61e8-7a6a-4622-88b2-d789149910e2','雜曲歌辭 踏歌行 一','劉禹錫','唐','唐诗','tang','','["\u7231\u60c5", "\u6c11\u6b4c"]','春江月出大堤平，堤上女郎連袂行。',32,'全唐诗/poet.tang.2000.json','["春江月出大堤平，堤上女郎連袂行。", "唱盡新詞看不見，紅霞影樹鷓鴣鳴。"]'),
('805963b8-7066-4be3-8aea-e95562dcab80','雜曲歌辭 踏歌行 二','劉禹錫','唐','唐诗','tang','','[]','桃蹊柳陌好經過，燈下妝成月下歌。',32,'全唐诗/poet.tang.2000.json','["桃蹊柳陌好經過，燈下妝成月下歌。", "爲是襄王故宮地，至今猶自細腰多。"]'),
('ffc94cde-e10c-45f8-b663-40a2f40b2014','雜曲歌辭 踏歌行 三','劉禹錫','唐','唐诗','tang','','[]','新詞宛轉遞相傳，振袖傾鬟風露前。',32,'全唐诗/poet.tang.2000.json','["新詞宛轉遞相傳，振袖傾鬟風露前。", "月落烏啼雲雨散，遊童陌上拾花鈿。"]'),
('dba2d290-6910-4676-813c-02b622d559a1','雜曲歌辭 踏歌行 四','劉禹錫','唐','唐诗','tang','','[]','日暮江頭聞竹枝，南人行樂北人悲。',32,'全唐诗/poet.tang.2000.json','["日暮江頭聞竹枝，南人行樂北人悲。", "自從雪裏唱新曲，直至三春花盡時。"]'),
('b5286243-fe81-45de-8dd0-2c9b10612a43','雜曲歌辭 天長地久詞 一','盧綸','唐','唐诗','tang','','[]','玉砌紅花樹，香風不敢吹。',24,'全唐诗/poet.tang.2000.json','["玉砌紅花樹，香風不敢吹。", "春光解天意，偏發殿南枝。"]'),
('d95eff32-3f6e-4f15-95a1-6b87be854b5d','雜曲歌辭 天長地久詞 二','盧綸','唐','唐诗','tang','','[]','虹橋千步廊，半在水中央。',24,'全唐诗/poet.tang.2000.json','["虹橋千步廊，半在水中央。", "天子方清暑，宮人重暮妝。"]'),
('a1a7867a-1613-459e-bc85-9a7a97d24a4e','雜曲歌辭 天長地久詞 三','盧綸','唐','唐诗','tang','','[]','辭輦復當熊，傾心奉上宮。',24,'全唐诗/poet.tang.2000.json','["辭輦復當熊，傾心奉上宮。", "君王若看貌，甘在衆妃中。"]'),
('41bab4a4-f0f9-461b-b886-e36f04532da9','雜曲歌辭 天長地久詞 四','盧綸','唐','唐诗','tang','','[]','雲日呈祥禮物殊，北庭生獻五單于。',32,'全唐诗/poet.tang.2000.json','["雲日呈祥禮物殊，北庭生獻五單于。", "塞天萬里無飛鳥，可在邊城用郅都。"]'),
('f1181c21-874a-4a68-94a2-536a7149656f','雜曲歌辭 天長地久詞 五','盧綸','唐','唐诗','tang','','[]','臺殿雲涼風日微，君王初賜六宮衣。',32,'全唐诗/poet.tang.2000.json','["臺殿雲涼風日微，君王初賜六宮衣。", "樓船罷泛歸猶早，行道才人鬬射飛。"]'),
('09997a32-f020-4acc-8f09-4fe811150ef6','雜曲歌辭 欸乃曲 一','元結','唐','唐诗','tang','','[]','偏存名跡在人間，順俗與時未安閑。',32,'全唐诗/poet.tang.2000.json','["偏存名跡在人間，順俗與時未安閑。", "來謁大官兼問政，扁舟却入九疑山。"]'),
('5d1f2587-bac2-4b2a-89e5-626edd8188f5','雜曲歌辭 欸乃曲 二','元結','唐','唐诗','tang','','[]','湘江二月春水平，滿月和風宜夜行。',32,'全唐诗/poet.tang.2000.json','["湘江二月春水平，滿月和風宜夜行。", "唱橈欲過平陽戍，守吏相呼問姓名。"]'),
('6b6e3b4f-dbcd-4132-8942-9ac825f88aa8','雜曲歌辭 欸乃曲 三','元結','唐','唐诗','tang','','[]','千里楓林煙雨深，無朝無暮有猨吟。',32,'全唐诗/poet.tang.2000.json','["千里楓林煙雨深，無朝無暮有猨吟。", "停橈靜聽曲中意，好是雲山韶濩音。"]'),
('72c3b7a8-351d-4621-8c12-c0391e566d3a','雜曲歌辭 欸乃曲 四','元結','唐','唐诗','tang','','[]','零陵郡北湘水東，浯溪形勝滿湘中。',32,'全唐诗/poet.tang.2000.json','["零陵郡北湘水東，浯溪形勝滿湘中。", "溪口石顛堪自逸，誰能相伴作漁翁。"]'),
('78891fad-2452-41fa-b710-b7c0433a8a53','雜曲歌辭 欸乃曲 五','元結','唐','唐诗','tang','','[]','下瀧船似入深淵，上瀧船似欲昇天。',32,'全唐诗/poet.tang.2000.json','["下瀧船似入深淵，上瀧船似欲昇天。", "瀧南始到九疑郡，應絕高人乘興船。"]'),
('8def6541-16ab-4f82-a669-17b2bb5195c7','雜曲歌辭 十二月樂辭 正月','李賀','唐','唐诗','tang','','[]','上樓迎春新春歸，暗黃著柳宮漏遲。',64,'全唐诗/poet.tang.2000.json','["上樓迎春新春歸，暗黃著柳宮漏遲。", "薄薄淡靄弄野姿，寒綠幽泥生短絲。", "錦牀曉臥玉肌冷，露臉未開對朝暝。", "官街柳帶不堪折，早晚菖蒲勝綰結。"]'),
('1164451a-78ce-4ced-b45a-a0cab3dacd1e','雜曲歌辭 十二月樂辭 二月','李賀','唐','唐诗','tang','','[]','二月飲酒采桑津，宜男草生蘭笑人。',72,'全唐诗/poet.tang.2000.json','["二月飲酒采桑津，宜男草生蘭笑人。", "蒲如交劒風如薰，勞勞胡燕怨酣春。", "薇帳逗烟生綠塵，金翅峨髻愁暮雲。", "沓颯起舞真珠裙，津頭送別唱流水。", "酒客背寒南山死。"]'),
('6edb4622-4f09-4d1c-bc71-a7f284956462','雜曲歌辭 十二月樂辭 三月','李賀','唐','唐诗','tang','','[]','東方風來滿眼春，花城柳暗愁幾人，複宮深殿竹風起。',80,'全唐诗/poet.tang.2000.json','["東方風來滿眼春，花城柳暗愁幾人，複宮深殿竹風起。", "新翠舞襟靜如水，光風轉蕙百餘里。", "暖霧驅雲撲天地，軍裝宮妓掃蛾淺。", "搖搖錦旗夾城暖，曲水飄香去不歸。", "梨花落盡成秋苑。"]'),
('1d92df58-5c25-4916-a6c7-15c92e0a5240','雜曲歌辭 十二月樂辭 四月','李賀','唐','唐诗','tang','','[]','曉涼暮涼樹如蓋，千山濃綠生雲外。',56,'全唐诗/poet.tang.2000.json','["曉涼暮涼樹如蓋，千山濃綠生雲外。", "依微香雨青氛氳，膩葉蟠花照曲門。", "金塘閑水搖碧漪，老景沈重無驚飛，墮紅殘蕚暗參差。"]'),
('a8acb4e2-2db4-47e8-97e4-6f8f3239654d','雜曲歌辭 十二月樂辭 五月','李賀','唐','唐诗','tang','','[]','雕玉押簾上，輕縠籠虛門。',48,'全唐诗/poet.tang.2000.json','["雕玉押簾上，輕縠籠虛門。", "井汲鉛華水，扇織鴛鴦文。", "回雪舞涼殿，甘露洗空綠。", "羅袖從徊翔，香汗霑寶粟。"]'),
('3063abd2-4d18-4f71-aebe-3f433607900a','雜曲歌辭 十二月樂辭 六月','李賀','唐','唐诗','tang','','[]','裁生羅，伐湘竹。',40,'全唐诗/poet.tang.2000.json','["裁生羅，伐湘竹。", "帔拂疎霜簟秋玉，炎炎紅鏡東方開。", "暈如車輪上徘徊，啾啾赤帝騎龍來。"]'),
('1168acab-dc79-42cd-82a8-439ee1fc51ae','雜曲歌辭 十二月樂辭 七月','李賀','唐','唐诗','tang','','[]','星依雲渚冷，露滴盤中圓。',60,'全唐诗/poet.tang.2000.json','["星依雲渚冷，露滴盤中圓。", "好花生木末，衰蕙愁空園。", "夜天如玉砌，池葉極青錢。", "僅厭舞衫薄，稍知花簟寒。", "曉風何拂拂，北斗光闌干。"]'),
('387c1c09-f29d-47b3-8a4b-34b6956497e0','雜曲歌辭 十二月樂辭 八月','李賀','唐','唐诗','tang','','[]','孀妾怨長夜，獨客夢歸家。',48,'全唐诗/poet.tang.2000.json','["孀妾怨長夜，獨客夢歸家。", "傍簷蟲緝絲，向壁燈垂花。", "簷外月光吐，簾中樹影斜。", "悠悠飛露姿，點綴池中荷。"]'),
('72c72576-060e-4185-88c2-f4b31c9dcc89','雜曲歌辭 十二月樂辭 九月','李賀','唐','唐诗','tang','','[]','離宮散螢天似水，竹黃池冷芙蓉死。',64,'全唐诗/poet.tang.2000.json','["離宮散螢天似水，竹黃池冷芙蓉死。", "月綴金鋪光脉脉，涼苑虛庭空澹白。", "霜花飛飛風草草，翠錦斕斑滿層道。", "雞人罷唱曉瓏璁，鴉啼金井下疎桐。"]'),
('3250a75a-201d-4c4c-a3ac-4b0bb4a246f8','雜曲歌辭 十二月樂辭 十月','李賀','唐','唐诗','tang','','[]','玉壺銀箭稍難傾，釭花夜笑凝幽明。',56,'全唐诗/poet.tang.2000.json','["玉壺銀箭稍難傾，釭花夜笑凝幽明。", "碎霜斜舞上羅幕，燭籠兩行照飛閣。", "珠帷怨臥不成眠，金鳳刺衣著體寒，長眉對月鬬彎環。"]'),
('5eb2ce8a-906f-4f7f-8025-8f5cf56a692d','雜曲歌辭 十二月樂辭 十一月','李賀','唐','唐诗','tang','','[]','宮城團回凜嚴光，白光碎碎墮瓊芳。',32,'全唐诗/poet.tang.2000.json','["宮城團回凜嚴光，白光碎碎墮瓊芳。", "撾鍾高飲千日酒，却天凝寒作君壽。"]'),
('0d6a9883-9575-42d7-ba2e-43cd44086f87','雜曲歌辭 十二月樂辭 十二月','李賀','唐','唐诗','tang','','[]','日脚淡光紅灑灑，薄霜不銷桂枝下。',32,'全唐诗/poet.tang.2000.json','["日脚淡光紅灑灑，薄霜不銷桂枝下。", "依稀和氣解冬嚴，已就長日辭長夜。"]'),
('d3b1201d-f671-428d-867e-0eecc02e47ca','雜曲歌辭 十二月樂辭 閏月','李賀','唐','唐诗','tang','','[]','帝重光，年重時，七十二候回環推。',48,'全唐诗/poet.tang.2000.json','["帝重光，年重時，七十二候回環推。", "天官玉琯灰剩飛，今歲何長來歲遲。", "王母移桃獻天子，羲氏和氏迂龍轡。"]'),
('a02551b7-28e1-4a79-8e2c-a185c70cffcb','雜曲歌辭 桃花行 一','李嶠','唐','唐诗','tang','','[]','歲去無言忽顦顇，時來含笑吐氛氳。',32,'全唐诗/poet.tang.2000.json','["歲去無言忽顦顇，時來含笑吐氛氳。", "不能擁路迷仙客，故欲開蹊侍聖君。"]'),
('6685502b-4f24-4ab8-82db-c0b0b155c13e','雜曲歌辭 桃花行 二','李嶠','唐','唐诗','tang','','[]','綺蕚成蹊遍籞芳，紅英撲地滿筵香。',32,'全唐诗/poet.tang.2000.json','["綺蕚成蹊遍籞芳，紅英撲地滿筵香。", "莫將秋宴傳王母，來比春華壽聖皇。"]'),
('065b8cb6-8cbd-461e-8ed8-62ee4ba449e8','雜曲歌辭 桃花行 三','李嶠','唐','唐诗','tang','','[]','源水叢花無數開，丹跗紅蕚間青梅。',32,'全唐诗/poet.tang.2000.json','["源水叢花無數開，丹跗紅蕚間青梅。", "從今結子三千歲，預喜仙游復摘來。"]'),
('39588d10-121c-4f20-aace-8cd5392070a7','雜曲歌辭 桃花行 四','李嶠','唐','唐诗','tang','','[]','桃花灼灼有光輝，無數成蹊點更飛。',32,'全唐诗/poet.tang.2000.json','["桃花灼灼有光輝，無數成蹊點更飛。", "爲見芳林含笑待，遂同溫樹不言歸。"]'),
('17097de0-b154-43fd-9213-91d38353eb8c','雜曲歌辭 桃花行 五','李嶠','唐','唐诗','tang','','[]','紅蕚競妍春苑曙，粉茸新向御筵開。',32,'全唐诗/poet.tang.2000.json','["紅蕚競妍春苑曙，粉茸新向御筵開。", "長年願奉西王宴，近侍慙無東朔才。"]'),
('03af6588-16af-493e-8988-e64b86562558','雜曲歌辭 蘇摩遮 一','張說','唐','唐诗','tang','','[]','摩遮本出海西胡，琉璃寶服紫髯胡。',32,'全唐诗/poet.tang.2000.json','["摩遮本出海西胡，琉璃寶服紫髯胡。", "聞道皇恩遍宇宙，來時歌舞助歡娛。"]'),
('31890cda-050b-4716-a248-2489f7552a6f','雜曲歌辭 蘇摩遮 二','張說','唐','唐诗','tang','','[]','繡裝帕額寶花冠，夷歌騎舞借人看。',32,'全唐诗/poet.tang.2000.json','["繡裝帕額寶花冠，夷歌騎舞借人看。", "自能激水成陰氣，不慮今年寒不寒。"]'),
('cf878bf1-cd9c-4c41-b35d-02c122cbb1d3','雜曲歌辭 蘇摩遮 三','張說','唐','唐诗','tang','','[]','臘月凝陰積帝臺，豪歌擊鼓送寒來。',32,'全唐诗/poet.tang.2000.json','["臘月凝陰積帝臺，豪歌擊鼓送寒來。", "油囊取得天河水，將添上壽萬年杯。"]'),
('a9983abd-6e12-4219-aa38-ee9b3226f257','雜曲歌辭 蘇摩遮 四','張說','唐','唐诗','tang','','[]','寒氣宜人最可憐，故將寒水散庭前。',32,'全唐诗/poet.tang.2000.json','["寒氣宜人最可憐，故將寒水散庭前。", "惟願聖君無限壽，長取新年續舊年。"]'),
('9ef4403b-b3ba-438f-bd74-2d502ebafb9a','雜曲歌辭 蘇摩遮 五','張說','唐','唐诗','tang','','[]','昭成皇后帝家親，榮樂諸人不比倫。',32,'全唐诗/poet.tang.2000.json','["昭成皇后帝家親，榮樂諸人不比倫。", "往日霜前花委地，今年雪後樹逢春。"]'),
('2cf94db2-1392-40b4-9e1d-773601af0411','雜曲歌辭 舞馬詞 一','張說','唐','唐诗','tang','','[]','萬玉朝宗鳳扆，千金率領龍媒。',28,'全唐诗/poet.tang.2000.json','["萬玉朝宗鳳扆，千金率領龍媒。", "眄鼓凝驕躞蹀，聽歌弄影徘徊。"]'),
('96e24608-9aef-4bbf-ae5a-5a27e6883a14','雜曲歌辭 舞馬詞 二','張說','唐','唐诗','tang','','[]','天祿遙徵衛叔，日龍上借羲和。',28,'全唐诗/poet.tang.2000.json','["天祿遙徵衛叔，日龍上借羲和。", "將共兩驂爭舞，來隨八駿齊歌。"]'),
('e29b8b64-cab1-44e4-a8ec-665bc16f9915','雜曲歌辭 舞馬詞 三','張說','唐','唐诗','tang','','[]','綵旄八佾成行，時龍五色因方。',28,'全唐诗/poet.tang.2000.json','["綵旄八佾成行，時龍五色因方。", "屈膝銜杯赴節，傾心獻壽無疆。"]'),
('8c4f456b-e653-4474-8eb6-d72ba31bf034','雜曲歌辭 舞馬詞 四','張說','唐','唐诗','tang','','[]','帝皁龍駒沛艾，星蘭驥子權奇。',28,'全唐诗/poet.tang.2000.json','["帝皁龍駒沛艾，星蘭驥子權奇。", "騰倚驤洋應節，繁驕接迹不移。"]'),
('cf5279f1-ea02-48a0-a04d-6ebaf54c4c45','雜曲歌辭 舞馬詞 五','張說','唐','唐诗','tang','','[]','二聖先天合德，羣靈率土可封。',28,'全唐诗/poet.tang.2000.json','["二聖先天合德，羣靈率土可封。", "擊石驂驔紫燕，摐金顧步蒼龍。"]'),
('9600d61f-6d07-4fa1-809f-113485971356','雜曲歌辭 舞馬詞 六','張說','唐','唐诗','tang','','[]','聖君出震應籙，神馬浮河獻圖。',28,'全唐诗/poet.tang.2000.json','["聖君出震應籙，神馬浮河獻圖。", "足踏天庭鼓舞，心將帝樂蜘躊。"]'),
('f2d06cba-a215-48cd-861a-1d0c2edba893','雜曲歌辭 舞馬千秋萬歲樂府詞 一','張說','唐','唐诗','tang','','[]','金天誕聖千秋節，玉醴還分萬壽觴。',64,'全唐诗/poet.tang.2000.json','["金天誕聖千秋節，玉醴還分萬壽觴。", "試聽紫騮歌樂府，何如騄驥舞華岡。", "連騫勢出魚龍變，蹀躞驕生鳥獸行。", "歲歲相傳指樹日，翩翩來伴慶雲翔。"]'),
('ebfcec9f-998b-4132-af84-34467c59f754','雜曲歌辭 舞馬千秋萬歲樂府詞 二','張說','唐','唐诗','tang','','[]','聖王至德與天齊，天馬來儀自海西。',64,'全唐诗/poet.tang.2000.json','["聖王至德與天齊，天馬來儀自海西。", "腕足齊行拜兩膝，繁驕不進蹈千蹄。", "䯱髵奮鬣時蹲踏，鼓怒驤身忽上躋。", "更有銜杯終宴曲，垂頭掉尾醉如泥。"]'),
('2c82f04b-e75b-4136-8905-f66fd3d33361','雜曲歌辭 舞馬千秋萬歲樂府詞 三','張說','唐','唐诗','tang','','[]','遠聽明君愛逸才，玉鞭金翅引龍媒。',64,'全唐诗/poet.tang.2000.json','["遠聽明君愛逸才，玉鞭金翅引龍媒。", "不因茲白人間有，定是飛黃天上來。", "影弄日華相照耀，噴含雲色且徘徊。", "莫言闕下桃花舞，別有河中蘭葉開。"]'),
('44b0ad0f-0619-4b48-9f77-63be8c086cc5','雜曲歌辭 小曲新詞 一','白居易','唐','唐诗','tang','','[]','霽色鮮宮殿，秋聲脆管弦。',24,'全唐诗/poet.tang.2000.json','["霽色鮮宮殿，秋聲脆管弦。", "聖明千歲樂，歲歲似今年。"]'),
('c6040755-04d0-4eed-a189-573ee13f56e6','雜曲歌辭 小曲新詞 二','白居易','唐','唐诗','tang','','[]','紅裙明月夜，碧殿早秋時。',24,'全唐诗/poet.tang.2000.json','["紅裙明月夜，碧殿早秋時。", "好向昭陽宿，天涼玉漏遲。"]'),
('6a01bda7-e94e-4968-b635-0697fabe823f','雜曲歌辭 閨怨詞 一','白居易','唐','唐诗','tang','','[]','朝憎鶯百囀，夜妒燕雙棲。',24,'全唐诗/poet.tang.2000.json','["朝憎鶯百囀，夜妒燕雙棲。", "不慣經春別，誰知到曉啼。"]'),
('3a1c0b7b-5f64-4136-ba4c-3f9b2ffdc98b','雜曲歌辭 閨怨詞 二','白居易','唐','唐诗','tang','','[]','珠箔籠寒月，紗窗背曉燈。',24,'全唐诗/poet.tang.2000.json','["珠箔籠寒月，紗窗背曉燈。", "夜來巾上淚，一半是春冰。"]'),
('d872e96e-c064-4fa4-a3f3-8f74a61116e7','雜曲歌辭 閨怨詞 三','白居易','唐','唐诗','tang','','[]','關山征戍遠，閨閣別離難。',24,'全唐诗/poet.tang.2000.json','["關山征戍遠，閨閣別離難。", "苦戰應顦顇，寒衣不要寬。"]'),
('624d5fb5-98fb-41af-9dbd-be9367d82630','雜曲歌辭 皇帝感詞 一','盧綸','唐','唐诗','tang','','[]','提劒雲雷動，垂衣日月明。',48,'全唐诗/poet.tang.2000.json','["提劒雲雷動，垂衣日月明。", "禁花呈瑞色，國老見星精。", "發棹魚先躍，窺巢鳥不驚。", "山呼一萬歲，直入九重城。"]'),
('9a58f543-bac5-42c3-834b-fd6781a18a18','雜曲歌辭 皇帝感詞 二','盧綸','唐','唐诗','tang','','[]','天衣五鳳彩，御馬六龍文。',48,'全唐诗/poet.tang.2000.json','["天衣五鳳彩，御馬六龍文。", "雨露清馳道，風雷翊上軍。", "高旍花外轉，行漏樂前聞。", "時見金鞭舉，空中指瑞雲。"]'),
('b05eada0-57c8-43aa-a739-94ebfbfaf250','雜曲歌辭 皇帝感詞 三','盧綸','唐','唐诗','tang','','[]','妙算干戈止，神謀宇宙清。',48,'全唐诗/poet.tang.2000.json','["妙算干戈止，神謀宇宙清。", "兩階文物盛，七德武功成。", "校獵長楊苑，屯軍細柳營。", "歸來獻明主，歌舞隘春城。"]'),
('b7df3122-f82a-4ff5-a7c0-ab8b766f448b','雜曲歌辭 皇帝感詞 四','盧綸','唐','唐诗','tang','','[]','天樂下天中，雲軿儼在空。',48,'全唐诗/poet.tang.2000.json','["天樂下天中，雲軿儼在空。", "鉛黃豔河漢，語笑合笙鏞。", "已見長隨鳳，仍聞不避熊。", "君王親試舞，閶闔靜無風。"]'),
('9c5c45b3-3e85-4eeb-b9de-eba380e530b6','雜歌謠辭 漁父歌 一','張志和','唐','唐诗','tang','','["\u5199\u4eba", "\u70ed\u7231", "\u7530\u56ed", "\u5199\u666f", "\u81ea\u7136"]','西塞山邊白鷺飛，桃花流水鱖魚肥。',32,'全唐诗/poet.tang.2000.json','["西塞山邊白鷺飛，桃花流水鱖魚肥。", "青箬笠，綠蓑衣，春江細雨不須歸。"]'),
('7393bcdc-a605-4f44-ab7f-506000d4a052','雜歌謠辭 漁父歌 二','張志和','唐','唐诗','tang','','["\u957f\u6c5f"]','釣臺漁父褐爲裘，兩兩三三舴艋舟。',32,'全唐诗/poet.tang.2000.json','["釣臺漁父褐爲裘，兩兩三三舴艋舟。", "能縱棹，慣乘流，長江白浪不曾憂。"]'),
('a9286dac-14c5-4239-8c1b-bd90bc91baa2','雜歌謠辭 漁父歌 三','張志和','唐','唐诗','tang','','[]','霅溪灣裏釣漁翁，舴艋爲家西復東。',32,'全唐诗/poet.tang.2000.json','["霅溪灣裏釣漁翁，舴艋爲家西復東。", "江上雪，浦邊風，笑著荷衣不歎窮。"]'),
('d40b60b9-c4c1-4dc2-8d4a-b4d5122bf03a','雜歌謠辭 漁父歌 四','張志和','唐','唐诗','tang','','[]','松江蟹舍主人歡，菰飯莼羹亦共餐。',32,'全唐诗/poet.tang.2000.json','["松江蟹舍主人歡，菰飯莼羹亦共餐。", "楓葉落，荻花乾，醉宿漁舟不覺寒。"]'),
('7e4ea5d5-bb63-41ce-81c1-44716ae9dcbf','雜歌謠辭 漁父歌 五','張志和','唐','唐诗','tang','','[]','青草湖中月正圓，巴陵漁父棹歌連。',32,'全唐诗/poet.tang.2000.json','["青草湖中月正圓，巴陵漁父棹歌連。", "釣車子，掘頭船，樂在風波不用仙。"]'),
('1e3e1062-ee73-4c2e-9fcf-9554fae22e1e','雜歌謠辭 漁父歌','和凝','唐','唐诗','tang','','[]','白芷汀寒立鷺[鷥]，蘋風輕翦浪花時。',34,'全唐诗/poet.tang.2000.json','["白芷汀寒立鷺[鷥]，蘋風輕翦浪花時。", "煙冪冪，日遲遲，香引芙蓉惹釣絲。"]'),
('f8bbfe74-0389-473a-a93d-abe9690a4761','雜歌謠辭 漁父歌','歐陽炯','唐','唐诗','tang','','[]','風浩寒溪照膽明，小君山上玉蟾生。',34,'全唐诗/poet.tang.2000.json','["風浩寒溪照膽明，小君山上玉蟾生。", "荷露墜，翠煙輕，撥[拉]遊魚幾處驚。"]'),
('82a70b6e-d6a8-4155-a043-64664ff6a496','雜歌謠辭 漁父歌 一','李珣','唐','唐诗','tang','','[]','水接衡門十里餘，信船歸去臥看書。',32,'全唐诗/poet.tang.2000.json','["水接衡門十里餘，信船歸去臥看書。", "輕爵祿，慕玄虛，莫道漁人只爲魚。"]'),
('a9b365df-54d9-4b2a-b63a-327ecc746a89','雜歌謠辭 漁父歌 二','李珣','唐','唐诗','tang','','[]','避世垂綸不記年，官高爭得似君閑。',32,'全唐诗/poet.tang.2000.json','["避世垂綸不記年，官高爭得似君閑。", "傾白酒，對青山，笑指柴門待月還。"]'),
('eaca9abf-2fae-4634-8f47-89acf32a72a1','雜歌謠辭 漁父歌 三','李珣','唐','唐诗','tang','','[]','棹警鷗飛水濺袍，影侵潭面柳垂絛。',32,'全唐诗/poet.tang.2000.json','["棹警鷗飛水濺袍，影侵潭面柳垂絛。", "終日醉，絕塵勞，曾見錢塘八月濤。"]'),
('83d2e1b3-c1cb-4ac4-be0b-c98532af2ba6','雜歌謠辭 雞鳴曲','王建','唐','唐诗','tang','','[]','雞初鳴，明星照東屋。',102,'全唐诗/poet.tang.2000.json','["雞初鳴，明星照東屋。", "雞再鳴，紅霞生海腹。", "百官待漏雙闕前，聖人亦挂山龍服。", "寶釵命婦燈下起，環珮玲瓏曉光裏。", "直內初燒玉[案]香，司更尚滴銅壺水。", "金吾衛裏直郎妻，到明不睡聽晨雞。", "天頭日月相送迎，夜棲旦鳴人不迷。"]'),
('7e0e651d-6a4a-4d76-8798-10de3225cd48','雜歌謠辭 雞鳴曲','李廓','唐','唐诗','tang','','[]','星稀月沒上五更，膠膠角角雞初鳴。',96,'全唐诗/poet.tang.2000.json','["星稀月沒上五更，膠膠角角雞初鳴。", "征人牽馬出門立，辭妾欲向安西行。", "再鳴引頸簷頭下，月中角聲催上馬。", "纔分地色第三鳴，旌旗紅塵已出城。", "婦人上城亂招手，夫壻不聞遙哭聲。", "長恨雞鳴別時苦，不遣雞栖近窗戶。"]'),
('26d040c0-e9c8-4ab6-9e3e-59613427b5de','雜歌謠辭 吳楚歌','張籍','唐','唐诗','tang','','[]','庭前春鳥啄林聲，紅夾羅襦縫未成。',32,'全唐诗/poet.tang.2000.json','["庭前春鳥啄林聲，紅夾羅襦縫未成。", "今朝社日停針線，起向朱櫻樹下行。"]'),
('f9d855a9-3d50-4905-887c-e05e440a7182','雜歌謠辭 李夫人歌 一','李商隱','唐','唐诗','tang','','[]','一帶不結心，兩股方安髻。',24,'全唐诗/poet.tang.2000.json','["一帶不結心，兩股方安髻。", "慙愧白茅人，月沒教星替。"]'),
('2f163557-30e2-4035-a535-f33d12b6dc19','雜歌謠辭 李夫人歌 二','李商隱','唐','唐诗','tang','','[]','剩結茱萸枝，多擘秋蓮的。',24,'全唐诗/poet.tang.2000.json','["剩結茱萸枝，多擘秋蓮的。", "獨自有波光，綵囊盛不得。"]'),
('33255d95-3c66-4307-9cc9-6918b69b3fb0','雜歌謠辭 李夫人歌 三','李商隱','唐','唐诗','tang','','["\u9ec4\u6cb3"]','蠻絲繫條脫，妍眼和香屑。',78,'全唐诗/poet.tang.2000.json','["蠻絲繫條脫，妍眼和香屑。", "壽宮不惜鑄南人，柔腸早被秋波割。", "清澄有餘幽素香，鰥魚渴鳳真珠房。", "不知瘦骨類冰井，更許夜簾通曉霜。", "土花漠碧雲[茫茫]，黃河欲盡天蒼黃。"]'),
('d28ae53e-8dac-47ac-a610-5a935826e2a9','雜歌謠辭 李夫人歌','李賀','唐','唐诗','tang','','[]','紫皇宮殿重重開，夫人飛入瓊瑤臺。',80,'全唐诗/poet.tang.2000.json','["紫皇宮殿重重開，夫人飛入瓊瑤臺。", "綠香繡帳何時歇，青雲無光宮水咽。", "翩聯桂花墜秋月，孤鸞驚啼商絲發。", "紅璧闌珊懸佩璫，歌臺小妓遙相望。", "玉蟾滴水雞人唱，露華蘭葉參差光。"]'),
('490298b8-51c5-4438-8adf-109d4f642abc','雜歌謠辭 李夫人歌','鮑溶','唐','唐诗','tang','','[]','璿閨羽帳華燭陳，方士夜降夫人神。',124,'全唐诗/poet.tang.2000.json','["璿閨羽帳華燭陳，方士夜降夫人神。", "葳蕤半露芙蓉色，窈窕將期環珮身。", "麗如三五月，可望難親近。", "嚬黛含犀竟不言，春思秋怨誰能問。", "欲求巧笑如生時，歌塵在空瑟銜絲。", "神來未及夢相見，帝比初亡心更悲。", "愛之欲其生又死，東流萬代無回水。", "宮漏丁丁夜向晨，煙銷霧散愁方士。"]'),
('8046faf5-f9d6-47fe-89b1-b2b105400aee','雜歌謠辭 李夫人歌','張祜','唐','唐诗','tang','','[]','延年不語望三星，莫說夫人上涕零。',32,'全唐诗/poet.tang.2000.json','["延年不語望三星，莫說夫人上涕零。", "爭奈世間惆悵在，甘泉宮夜看圖形。"]'),
('8c415df9-f9f3-468d-ae2b-79994ff4a5cf','雜歌謠辭 中山孺子妾歌','李白','唐','唐诗','tang','','["\u4e50\u5e9c", "\u5931\u610f", "\u6742\u6b4c\u8c23\u8f9e"]','中山孺子妾，特以色見珍。',77,'全唐诗/poet.tang.2000.json','["中山孺子妾，特以色見珍。", "雖不如延年妹，亦是當時絕世人。", "桃李出深井，花豔驚上春。", "一貴復一賤，關天豈由身。", "芙蓉老秋霜，團扇羞網塵。", "戚姬髡翦入舂市，萬古共悲辛。"]'),
('e88a20da-6a82-4840-8389-afa8722810ec','雜歌謠辭 臨江王節士歌','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭白波木葉稀，燕鴻始入吳雲飛。',74,'全唐诗/poet.tang.2000.json','["洞庭白波木葉稀，燕鴻始入吳雲飛。", "吳雲寒，燕鴻苦。", "風號沙宿瀟湘浦，節士感秋淚如雨。", "白日當天心，照之可以事明主。", "壯士憤，雄風生。", "安得倚天劒，跨海斬長鯨。"]'),
('c25daef9-1903-4899-a965-231f12448f2b','雜歌謠辭 司馬將軍歌','李白','唐','唐诗','tang','','["\u6218\u58eb", "\u8d5e\u9882", "\u6218\u4e89", "\u6742\u6b4c\u8c23\u8f9e", "\u4e50\u5e9c"]','狂風吹古月，竊弄章華臺。',156,'全唐诗/poet.tang.2000.json','["狂風吹古月，竊弄章華臺。", "北落明星動光彩，南征猛將如雲雷。", "手中電曳倚天劒，直斬長鯨海水開。", "我見樓船壯心目，頗似龍驤下三蜀。", "揚兵習戰張虎旗，江中白浪如銀屋。", "身居玉帳臨河魁，紫髯若戟冠崔嵬。", "細柳開營揖天子，始知灞上爲嬰孩。", "羌笛橫吹阿嚲回，向月樓中吹落梅。", "將軍自起舞長劒，壯士呼聲動九垓。", "功成獻凱見明主，丹青畫像麒麟臺。"]'),
('396cd474-fdac-49f4-9594-f28d013760ac','雜歌謠辭 鄭櫻桃歌','李頎','唐','唐诗','tang','','[]','石季龍，僭天祿。',182,'全唐诗/poet.tang.2000.json','["石季龍，僭天祿。", "擅雄豪，美人姓鄭名櫻桃。", "櫻桃美顏香且澤，娥娥侍寢專宮掖。", "後庭卷衣三萬人，翠眉清鏡不得親。", "官軍女騎一千匹，繁花照耀漳河春。", "織成花映紅綸巾，紅旗掣曳鹵簿新。", "鳴鼙走馬接飛鳥，銅[馱]琴瑟隨去塵。", "鳳陽重門如意館，百尺金梯倚銀漢。", "自言富貴不可量，女爲公主男爲王。", "赤花雙簟珊瑚牀，盤龍斗帳琥珀光。", "淫昏僞位神所惡，滅石者陵終不誤。", "鄴城蒼蒼白露微，世事飜覆黃雲飛。"]'),
('0aeb685d-f7d1-446f-942f-3ad5167cda9b','雜歌謠辭 襄陽歌','李白','唐','唐诗','tang','','[]','落日欲沒峴山西，倒著接䍦花下迷。',253,'全唐诗/poet.tang.2000.json','["落日欲沒峴山西，倒著接䍦花下迷。", "襄陽小兒齊拍手，攔街爭唱白銅鞮。", "傍人借問笑何事，笑殺山公醉似泥。", "鸕鷀杓，鸚鵡杯，百年三萬六千日，一日須傾三百杯。", "遙看漢水鴨頭綠，恰似蒲萄初醱醅。", "此江若變作春酒，壘麴便築糟丘臺。", "千金駿馬換少妾，醉坐雕鞍歌落梅。", "車傍側挂一壺酒，鳳笙龍管行相催。", "咸陽市上歎黃犬，何如月下傾金罍。", "君不見晉朝羊公一片石，龜龍剝落生莓苔。", "淚亦不能爲之墮，心亦不能爲之哀。", "誰能憂彼身後事，金鳧銀鴨葬死灰。", "清風朗月不用一錢買，玉山自倒非人推。", "舒州杓，力士鐺，李白與爾同死生。", "襄王雲雨今安在，江水東流猨夜聲。"]'),
('4e41582e-5f47-43e7-a146-5db2dd908a3d','雜歌謠辭 襄陽曲 一','李白','唐','唐诗','tang','','[]','襄陽行樂處，歌舞白銅鞮。',24,'全唐诗/poet.tang.2000.json','["襄陽行樂處，歌舞白銅鞮。", "江城回淥水，花月使人迷。"]'),
('9eb7ecb4-fb52-417b-869a-b0abaab68dd9','雜歌謠辭 襄陽曲 二','李白','唐','唐诗','tang','','[]','山公醉酒時，酩酊襄陽下。',24,'全唐诗/poet.tang.2000.json','["山公醉酒時，酩酊襄陽下。", "頭上白接䍦，倒著還騎馬。"]'),
('52efc05d-16c8-4a3d-895b-729e4ff185a7','雜歌謠辭 襄陽曲 三','李白','唐','唐诗','tang','','[]','峴山臨漢江，水淥沙如雪。',24,'全唐诗/poet.tang.2000.json','["峴山臨漢江，水淥沙如雪。", "上有墮淚碑，青苔久磨滅。"]'),
('57174957-5250-4879-83ca-38637fa8ae0d','雜歌謠辭 襄陽曲 四','李白','唐','唐诗','tang','','[]','且醉習家池，莫看墮淚碑。',24,'全唐诗/poet.tang.2000.json','["且醉習家池，莫看墮淚碑。", "山公欲上馬，笑殺襄陽兒。"]'),
('586765d4-d654-4d4b-ae42-ddf1d407b0ec','雜歌謠辭 蘇小小歌','李賀','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u9b3c", "\u5199\u666f"]','幽蘭露，如啼眼。',60,'全唐诗/poet.tang.2000.json','["幽蘭露，如啼眼。", "無物結同心，煙花不堪翦。", "草如茵，松如蓋。", "風爲裳，水爲佩。", "油壁車，久相待。", "冷翠燭，勞光彩。", "西陵下，風吹雨。"]'),
('d83f293a-4450-4e24-88d2-1a2982c39954','雜歌謠辭 蘇小小歌','溫庭筠','唐','唐诗','tang','','[]','買蓮莫破券，買酒莫解金。',60,'全唐诗/poet.tang.2000.json','["買蓮莫破券，買酒莫解金。", "酒裏春容抱離恨，水中蓮子懷芳心。", "吳公女兒腰似束，家在錢塘小江曲。", "一自檀郎逐便風，門前春水年年綠。"]'),
('fd515d96-d07b-4570-bace-388ee60058fa','雜歌謠辭 蘇小小歌 一','張祜','唐','唐诗','tang','','[]','車輪不可遮，馬足不可絆。',24,'全唐诗/poet.tang.2000.json','["車輪不可遮，馬足不可絆。", "長怨十字街，使郎心四散。"]'),
('61db4e7e-e0ec-4b52-9364-5666e4a009a5','雜歌謠辭 蘇小小歌 二','張祜','唐','唐诗','tang','','[]','新人千里去，故人千里來。',24,'全唐诗/poet.tang.2000.json','["新人千里去，故人千里來。", "翦刀橫眼底，方覺淚難裁。"]'),
('f88e80a3-43e2-444f-a79e-87e461bc0e35','雜歌謠辭 蘇小小歌 三','張祜','唐','唐诗','tang','','[]','登山不愁峻，涉海不愁深。',24,'全唐诗/poet.tang.2000.json','["登山不愁峻，涉海不愁深。", "中擘庭前棗，教郎見赤心。"]'),
('4f6be926-a548-417f-8d4f-0a4b6a7c97fc','雜歌謠辭 挾瑟歌','陸龜蒙','唐','唐诗','tang','','[]','挾瑟爲君撫，君嫌聲太古。',36,'全唐诗/poet.tang.2000.json','["挾瑟爲君撫，君嫌聲太古。", "寥寥倚浪絲，㗫㗫沈湘語。", "賴有秋風知，清泠吹玉柱。"]'),
('14f51fdf-af33-4359-9f89-f521724a9d0e','雜歌謠辭 勅勒歌','不詳','唐','唐诗','tang','','[]','敕勒金隤壁，陰山無歲華。',48,'全唐诗/poet.tang.2000.json','["敕勒金隤壁，陰山無歲華。", "帳外風飄雪，營前月照沙。", "羌兒吹玉管，胡姬踏錦花。", "却笑江南客，梅落不歸家。"]'),
('0a9ce3e6-afc6-4795-9744-9fe046c20acb','雜歌謠辭 黃麞歌','不詳','唐','唐诗','tang','','[]','黃麞黃麞草裏藏，彎弓射爾傷。',14,'全唐诗/poet.tang.2000.json','["黃麞黃麞草裏藏，彎弓射爾傷。"]'),
('73afcd7d-4d62-49ea-96dc-b7a780311361','雜歌謠辭 得体歌','不詳','唐','唐诗','tang','','[]','得体紇那也，紇囊得体那。',36,'全唐诗/poet.tang.2000.json','["得体紇那也，紇囊得体那。", "潭裏船車鬧，揚州銅器多。", "三郎當殿坐，聽唱得体歌。"]'),
('bf12a3f4-93d1-436f-a7ec-c1c128cf326c','雜歌謠辭 得寶歌','不詳','唐','唐诗','tang','','[]','得寶弘農野，弘農得寶那。',36,'全唐诗/poet.tang.2000.json','["得寶弘農野，弘農得寶那。", "潭裏船車鬧，揚州銅器多。", "三郎當殿坐，聽唱得寶歌。"]'),
('ac94232f-5510-466a-bac5-5a443c504a7b','雜歌謠辭 黃臺瓜辭','章懷太子','唐','唐诗','tang','','[]','種瓜黃臺下，瓜熟子離離。',36,'全唐诗/poet.tang.2000.json','["種瓜黃臺下，瓜熟子離離。", "一摘使瓜好，再摘令瓜稀。", "三摘尚自可，摘絕抱蔓歸。"]'),
('a05bf553-aa6e-49b8-8988-a104d0207473','雜歌謠辭 古歌','沈佺期','唐','唐诗','tang','','[]','落葉流風向玉臺，夜寒秋思洞房開。',96,'全唐诗/poet.tang.2000.json','["落葉流風向玉臺，夜寒秋思洞房開。", "水精簾外金波下，雲母窗前銀漢迴。", "玉階陰陰苔蘚色，君王履綦難再得。", "璇閨窈窕秋夜長，繡戶徘徊秋月光。", "燕姬綵帳芙蓉色，秦子金爐蘭麝香。", "北斗七星橫夜半，清歌一曲斷君腸。"]'),
('8c3a6775-c5e3-49e6-9164-ddce72b05365','雜歌謠辭 古歌 一','薛維翰','唐','唐诗','tang','','[]','美人怨何深，含情倚金閣。',24,'全唐诗/poet.tang.2000.json','["美人怨何深，含情倚金閣。", "不嚬復不語，紅淚雙雙落。"]'),
('99febbb4-c89d-4dd3-b5b0-34f214cc495f','雜歌謠辭 古歌 二','薛維翰','唐','唐诗','tang','','[]','美人閉紅燭，獨坐裁新錦。',24,'全唐诗/poet.tang.2000.json','["美人閉紅燭，獨坐裁新錦。", "頻放翦刀聲，夜寒知未寢。"]'),
('a41b75c5-bd7f-48a5-b58f-a0f222e529ee','雜歌謠辭 黃曇子歌','溫庭筠','唐','唐诗','tang','','[]','參差綠蒲短，搖豔雲塘滿。',48,'全唐诗/poet.tang.2000.json','["參差綠蒲短，搖豔雲塘滿。", "紅瀲蕩融融，鶯翁鸂鶒暖。", "萋芊小城路，馬上脩蛾懶。", "羅衫褭向風，點粉金鸝卵。"]'),
('cb9ac257-b84c-46fc-a19f-6e9ef2dae523','雜歌謠辭 邯鄲郭公辭','溫庭筠','唐','唐诗','tang','','[]','金笳悲故曲，玉座積深塵。',48,'全唐诗/poet.tang.2000.json','["金笳悲故曲，玉座積深塵。", "言是邯鄲伎，不易鄴城人。", "青苔竟埋骨，紅粉自傷神。", "唯有漳河柳，還向舊營春。"]'),
('1a9b92e2-c6ef-40fd-bf31-1bee53d208b7','雜歌謠辭 箜篌謠','李白','唐','唐诗','tang','','["\u54f2\u7406", "\u6742\u6b4c\u8c23\u8f9e", "\u53cb\u60c5"]','攀天莫登龍，走山莫騎虎。',112,'全唐诗/poet.tang.2000.json','["攀天莫登龍，走山莫騎虎。", "貴賤結交心不移，唯有嚴陵及光武。", "周公稱大聖，管蔡寧相容。", "漢謠一斗粟，不與淮南舂。", "兄弟尚路人，吾心安所從。", "它人方寸間，山海幾千重。", "輕言託朋友，對面九疑峰。", "多花必早落，桃李不如松。", "管鮑久已死，何人繼其蹤。"]'),
('a8d92958-dde2-4799-a5e0-0dab8a19f730','雜歌謠辭 鄴城童子謠','李賀','唐','唐诗','tang','','[]','鄴城中，暮塵起。',64,'全唐诗/poet.tang.2000.json','["鄴城中，暮塵起。", "將黑丸，斫文吏。", "棘爲鞭，虎爲馬。", "團團走，鄴城下。", "切玉劒，射日弓。", "獻何人，奉相公。", "扶轂來，關右兒。", "香掃塗，相公歸。"]'),
('3e618dad-49ae-4159-acf0-afe65cd2a9c5','雜歌謠辭 大麥行','杜甫','唐','唐诗','tang','','[]','大麥乾枯小麥黃，婦人行泣夫走藏。',64,'全唐诗/poet.tang.2000.json','["大麥乾枯小麥黃，婦人行泣夫走藏。", "東至集壁西梁洋，問誰腰鎌胡與羌。", "豈無蜀兵三千人，部領辛苦江山長。", "安得如鳥有羽翅，託身白雲還故鄉。"]'),
('f19b2b91-a9b0-483a-97f8-020e1578bc7a','雜歌謠辭 白鼉鳴','張籍','唐','唐诗','tang','','[]','天欲雨，有東風，南谿白鼉鳴窟中。',32,'全唐诗/poet.tang.2000.json','["天欲雨，有東風，南谿白鼉鳴窟中。", "六月人家井無水，夜聞白鼉人盡起。"]'),
('6a6a3a76-5ac9-40f2-adfd-6f44708f4af7','雜歌謠辭 步虛詞','陳羽','唐','唐诗','tang','','[]','漢武清齋讀鼎書，內官扶上畫雲車。',32,'全唐诗/poet.tang.2000.json','["漢武清齋讀鼎書，內官扶上畫雲車。", "壇上月明宮殿閉，仰看星斗禮空虛。"]'),
('e915b2ba-e270-407f-82ef-581a2251363a','雜歌謠辭 步虛詞','顧況','唐','唐诗','tang','','[]','逈步遊三洞，清心禮七真。',48,'全唐诗/poet.tang.2000.json','["逈步遊三洞，清心禮七真。", "飛符超羽翼，禁火醮星辰。", "殘藥霑雞犬，靈香出鳳麟。", "壺中無窄處，願得一容身。"]'),
('1419a84b-2586-444b-b987-5b874c580d0f','雜歌謠辭 步虛詞 一','劉禹錫','唐','唐诗','tang','','[]','阿母種桃雲海際，花落子成二千歲。',32,'全唐诗/poet.tang.2000.json','["阿母種桃雲海際，花落子成二千歲。", "海風吹折最繁枝，跪捧瓊盤獻天帝。"]'),
('80d83153-fbd8-42df-8bd5-86adda8647f0','雜歌謠辭 步虛詞 二','劉禹錫','唐','唐诗','tang','','[]','華表千年鶴一歸，凝丹爲頂雪爲衣。',32,'全唐诗/poet.tang.2000.json','["華表千年鶴一歸，凝丹爲頂雪爲衣。", "星星仙語人聽盡，卻向五雲翻翅飛。"]'),
('d3866dfc-b35f-4509-b5f8-5982afc6f8e9','雜歌謠辭 步虛詞 一','韋渠牟','唐','唐诗','tang','','[]','玉簡真人降，金書道籙通。',48,'全唐诗/poet.tang.2000.json','["玉簡真人降，金書道籙通。", "煙霞方蔽日，雲雨已生風。", "四極威儀異，三天使命同。", "那將人世戀，不去上清宮。"]'),
('3da3bd0b-1b39-466b-b993-6c443efa6eda','雜歌謠辭 步虛詞 二','韋渠牟','唐','唐诗','tang','','[]','羽駕正翩翩，雲鴻最自然。',48,'全唐诗/poet.tang.2000.json','["羽駕正翩翩，雲鴻最自然。", "霞冠將月曉，珠佩與星連。", "鏤玉留新訣，雕金得舊編。", "不知飛鳥學，更有幾人仙。"]'),
('a2b83ec7-0da0-466f-bb58-1760e11c5db1','雜歌謠辭 步虛詞 三','韋渠牟','唐','唐诗','tang','','[]','上帝求仙使，真符取玉郎。',48,'全唐诗/poet.tang.2000.json','["上帝求仙使，真符取玉郎。", "三才閑布象，二景鬱生光。", "騎吏排龍虎，笙歌走鳳凰。", "天高人不見，暗入白雲鄉。"]'),
('bbbb2201-0886-4e21-9a12-97df21b3e7d1','雜歌謠辭 步虛詞 四','韋渠牟','唐','唐诗','tang','','[]','鸞鶴共徘徊，仙官使者催。',48,'全唐诗/poet.tang.2000.json','["鸞鶴共徘徊，仙官使者催。", "香花三洞啓，風雨百神來。", "鳳篆文初定，龍泥印已開。", "何須生羽翼，始得上瑤臺。"]'),
('0517b13e-619d-4ba5-997d-3e292a687710','雜歌謠辭 步虛詞 五','韋渠牟','唐','唐诗','tang','','[]','羽節忽排煙，蘇君已得仙。',48,'全唐诗/poet.tang.2000.json','["羽節忽排煙，蘇君已得仙。", "命風驅日月，縮地走山川。", "幾處留丹竈，何時種玉田。", "一朝騎白虎，直上紫微天。"]'),
('8083909a-98a6-41c4-9af4-9a6340fe0803','雜歌謠辭 步虛詞 六','韋渠牟','唐','唐诗','tang','','[]','靜發降靈香，思神意智長。',48,'全唐诗/poet.tang.2000.json','["靜發降靈香，思神意智長。", "虎存時促步，龍想更成章。", "扣齒風雷響，挑燈日月光。", "仙雲在何處？髣髴滿空堂。"]'),
('43156b03-9cf2-4570-ba54-39e7703d013c','雜歌謠辭 步虛詞 七','韋渠牟','唐','唐诗','tang','','[]','幾度遊三洞，何方召百神。',48,'全唐诗/poet.tang.2000.json','["幾度遊三洞，何方召百神。", "風雲皆守一，龍虎亦全真。", "執節仙童小，燒香玉女春。", "應須絕巖內，委曲問皇人。"]'),
('5ba7df95-43d1-4edc-97fa-67d1c5a04670','雜歌謠辭 步虛詞 八','韋渠牟','唐','唐诗','tang','','[]','上法杳無營，玄脩似有情。',48,'全唐诗/poet.tang.2000.json','["上法杳無營，玄脩似有情。", "道宮瓊作想，真帝玉爲名。", "召岳驅旌節，馳雷發吏兵。", "雲車降何處，齋室有仙卿。"]'),
('6ac905a3-45b5-4f3d-bbc8-41e5c013c536','雜歌謠辭 步虛詞 九','韋渠牟','唐','唐诗','tang','','[]','羽衛一何鮮，香雲起莫煙。',48,'全唐诗/poet.tang.2000.json','["羽衛一何鮮，香雲起莫煙。", "方朝太素帝，更向玉清天。", "鳳曲凝猶吹，龍驂儼欲前。", "真文幾時降，知在永和年。"]'),
('cbeb1985-4ecd-414c-b1fa-93291d9a3584','雜歌謠辭 步虛詞 十','韋渠牟','唐','唐诗','tang','','[]','大道何年學，真符此日催。',48,'全唐诗/poet.tang.2000.json','["大道何年學，真符此日催。", "還持金作印，未要玉爲臺。", "羽節分明授，霞衣整頓裁。", "應緣五雲使，教上列仙來。"]'),
('b022e6f1-f198-4b97-9bb9-abbf7d5f449d','雜歌謠辭 步虛詞 十一','韋渠牟','唐','唐诗','tang','','[]','獨自授金書，蕭條詠紫虛。',48,'全唐诗/poet.tang.2000.json','["獨自授金書，蕭條詠紫虛。", "龍行還當馬，雲起自成車。", "九轉風煙合，千年井竈餘。", "參差從太一，壽等混元初。"]'),
('69dd2b05-b6db-4c1f-8bd4-25eb2f0e52da','雜歌謠辭 步虛詞 十二','韋渠牟','唐','唐诗','tang','','[]','道學已通神，香花會女真。',48,'全唐诗/poet.tang.2000.json','["道學已通神，香花會女真。", "霞牀珠斗帳，金薦玉輿輪。", "一室心偏靜，三天夜正春。", "靈官竟誰降，仙相有夫人。"]'),
('96b7348a-f58e-45d9-b189-a44006b6cbf9','雜歌謠辭 步虛詞 十三','韋渠牟','唐','唐诗','tang','','[]','上界有黃房，仙家道路長。',48,'全唐诗/poet.tang.2000.json','["上界有黃房，仙家道路長。", "神來知位次，樂變協宮商。", "競把瑠璃椀，誰傾白玉漿。", "霞衣最芬馥，蘇合是靈香。"]'),
('0d1aca20-ff6b-4fee-a980-51837a113859','雜歌謠辭 步虛詞 十四','韋渠牟','唐','唐诗','tang','','[]','珠佩紫霞纓，夫人會八靈。',48,'全唐诗/poet.tang.2000.json','["珠佩紫霞纓，夫人會八靈。", "太霄猶有觀，絕宅豈無形。", "暮雨徘徊降，仙歌宛轉聽。", "誰逢玉妃輦，應檢九真經。"]'),
('0ba8aaa0-cfe6-43e7-8719-37788175ab51','雜歌謠辭 步虛詞 十五','韋渠牟','唐','唐诗','tang','','[]','西海辭金母，東方拜木公。',48,'全唐诗/poet.tang.2000.json','["西海辭金母，東方拜木公。", "雲行疑帶雨，星步欲凌風。", "羽袖揮丹鳳，霞巾曳彩虹。", "飄颻九霄外，下視望仙宮。"]'),
('ad936cc9-207f-4294-82ef-8e9c33c9af77','雜歌謠辭 步虛詞 十六','韋渠牟','唐','唐诗','tang','','[]','玉樹雜金花，天河織女家。',48,'全唐诗/poet.tang.2000.json','["玉樹雜金花，天河織女家。", "月邀丹鳳舄，風送紫鸞車。", "霧縠籠綃帶，雲屏列錦霞。", "瑤臺千萬里，不覺往來賒。"]'),
('0a98b4ea-6579-4c08-a8ce-06acde7b0969','雜歌謠辭 步虛詞 十七','韋渠牟','唐','唐诗','tang','','[]','舞鳳凌天出，歌麟入夜聽。',48,'全唐诗/poet.tang.2000.json','["舞鳳凌天出，歌麟入夜聽。", "雲容衣眇眇，風韻曲泠泠。", "扣齒端金簡，焚香檢玉經。", "仙宮知不遠，只近太微星。"]'),
('d971bf7f-46c9-4db7-bf96-a5e2aaaaeac3','雜歌謠辭 步虛詞 十八','韋渠牟','唐','唐诗','tang','','[]','紫府與玄洲，誰來物外遊。',48,'全唐诗/poet.tang.2000.json','["紫府與玄洲，誰來物外遊。", "無煩騎白鹿，不用駕青牛。", "金化顏應駐，雲飛鬢不秋。", "仍聞碧海上，更用玉爲樓。"]'),
('d135fc0c-6b64-4717-a622-dd8364180d8a','雜歌謠辭 步虛詞 十九','韋渠牟','唐','唐诗','tang','','[]','轡鶴復驂鸞，全家去不難。',48,'全唐诗/poet.tang.2000.json','["轡鶴復驂鸞，全家去不難。", "雞聲隨羽化，犬影入雲看。", "釀玉當成酒，燒金且轉丹。", "何妨五色綬，次第給仙官。"]'),
('a2b2d4ae-5cfb-4466-b83f-8eac8698c4de','雜歌謠辭 步虛詞','僧皎然','唐','唐诗','tang','','[]','予因覽真訣，遂感西域君。',72,'全唐诗/poet.tang.2000.json','["予因覽真訣，遂感西域君。", "玉笙下青冥，人間未曾聞。", "日華鍊魂魄，皎皎無垢氛。", "謂我有仙骨，且令餌氤氳。", "俯仰媿靈顏，願隨鸞鶴羣。", "俄然動風馭，縹眇歸青雲。"]'),
('d1c6ad53-fd93-491b-9813-403ffa980c9c','雜歌謠辭 步虛詞','高駢','唐','唐诗','tang','','[]','青溪道士人不識，上天下天鶴一隻。',34,'全唐诗/poet.tang.2000.json','["青溪道士人不識，上天下天鶴一隻。", "洞門深[鎖]碧窗寒，滴露妍朱寫周易。"]'),
('1bc078f6-329e-4946-9119-45a21dc0b296','雜歌謠辭 步虛引','陳陶','唐','唐诗','tang','','[]','小隱山人十洲客，莓苔爲衣雙耳白。',64,'全唐诗/poet.tang.2000.json','["小隱山人十洲客，莓苔爲衣雙耳白。", "青編爲我忽降書，暮雨虹蜺一千尺。", "赤城門閉六丁直，曉日已燒東海色。", "朝天半夜聞玉雞，星斗離離礙龍翼。"]'),
('eca656c4-d936-46cb-8630-b2dae6251766','詠漢高祖','王珪','唐','唐诗','tang','','[]','漢祖起豐沛，乘運以躍鱗。',108,'全唐诗/poet.tang.2000.json','["漢祖起豐沛，乘運以躍鱗。", "手奮三尺劒，西滅無道秦。", "十月五星聚，七年四海賓。", "高抗威宇宙，貴有天下人。", "憶昔與項王，契闊時未伸。", "鴻門既薄蝕，滎陽亦蒙塵。", "蟣虱生介胄，將卒多苦辛。", "爪牙驅信越，腹心謀張陳。", "赫赫西楚國，化爲丘與榛。"]'),
('d2b4d9df-6414-4a7a-8a4b-ee05830d0371','詠淮陰侯','王珪','唐','唐诗','tang','','[]','秦王日凶慝，豪傑爭共亡。',120,'全唐诗/poet.tang.2000.json','["秦王日凶慝，豪傑爭共亡。", "信亦胡爲者，劍歌從項梁。", "項羽不能用，脫身歸漢王。", "道契君臣合，時來名位彰。", "北討燕承命，東驅楚絕糧。", "斬龍堰濉水，擒豹熸夏陽。", "功成享天祿，建旗還南昌。", "千金答漂母，百錢酬下鄉。", "吉凶成糾纏，倚伏難預詳。", "弓藏狡兔盡，慷慨念心傷。"]'),
('0d0056af-ad39-4df9-adf3-aed70b2c3ac0','早春桂林殿應詔','陳叔達','唐','唐诗','tang','','[]','金鋪照春色，玉律動年華。',48,'全唐诗/poet.tang.2000.json','["金鋪照春色，玉律動年華。", "朱樓雲似蓋，丹桂雪如花。", "水岸銜階轉，風條出柳斜。", "輕輿臨太液，湛露酌流霞。"]'),
('1ce59dfc-a30e-4e52-a9c7-f2e77552e7d8','後渚置酒','陳叔達','唐','唐诗','tang','','[]','大渚初驚夜，中流沸鼓鼙。',48,'全唐诗/poet.tang.2000.json','["大渚初驚夜，中流沸鼓鼙。", "寒沙滿曲浦，夕霧上邪谿。", "岸廣鳧飛急，雲深鴈度低。", "嚴關猶未遂，此夕待晨雞。"]'),
('da6fb81c-3737-4c6a-9762-b278d6148a14','聽鄰人琵琶','陳叔達','唐','唐诗','tang','','[]','本是龍門桐，因妍入漢宮。',60,'全唐诗/poet.tang.2000.json','["本是龍門桐，因妍入漢宮。", "香緣羅袖裏，聲逐朱弦中。", "雖有相思韻，翻將入塞同。", "關山臨却月，花蘂散迴風。", "爲將金谷引，添令曲未終。"]'),
('79dff142-77e3-45b2-8760-27629772a923','州城西園入齋祠社','陳叔達','唐','唐诗','tang','','[]','升壇預潔祀，詰早肅分司。',96,'全唐诗/poet.tang.2000.json','["升壇預潔祀，詰早肅分司。", "達氣風霜積，登光日色遲。", "農教先八政，陽和秩四時。", "祈年服垂冕，告幣動褰帷。", "瘞地尊餘奠，人天庶有資。", "椒蘭卒清酌，簠簋徹香萁。", "折俎分歸胙，充庭降受釐。", "方憑知禮節，況奉化雍熙。"]'),
('883d2200-4f5e-4961-9844-e33ec60c592c','春首','陳叔達','唐','唐诗','tang','','[]','雪花聯玉樹，冰彩散瑤池。',24,'全唐诗/poet.tang.2000.json','["雪花聯玉樹，冰彩散瑤池。", "翔禽遙出沒，積翠遠參差。"]'),
('d30d32b3-3fcb-421a-b6fe-220633ce047d','初年','陳叔達','唐','唐诗','tang','','[]','和風起天路，嚴氣消冰井。',24,'全唐诗/poet.tang.2000.json','["和風起天路，嚴氣消冰井。", "索索枝未柔，厭厭漏猶永。"]'),
('fc114608-fa50-4999-8471-217ef1936685','詠菊','陳叔達','唐','唐诗','tang','','[]','霜間開紫蔕，露下發金英。',24,'全唐诗/poet.tang.2000.json','["霜間開紫蔕，露下發金英。", "但令逢採摘，寧辭獨晚榮。"]'),
('38bc9397-7390-4011-8e08-9b0dc66b9288','自君之出矣','王融','唐','唐诗','tang','','[]','自君之出矣，金爐香不然。',24,'全唐诗/poet.tang.2000.json','["自君之出矣，金爐香不然。", "思君當明燭，終宵空自煎。"]'),
('2ba4c2e3-c8e8-44f3-97db-8185dba8db72','自君之出矣  一','陳叔達','唐','唐诗','tang','','[]','自君之出矣，紅顏轉憔悴。',24,'全唐诗/poet.tang.2000.json','["自君之出矣，紅顏轉憔悴。", "思君如明燭，煎心且銜淚。"]'),
('d1210127-bddc-42f8-bd1b-8bd84f016114','自君之出矣  二','陳叔達','唐','唐诗','tang','','[]','自君之出矣，明鏡罷紅妝。',24,'全唐诗/poet.tang.2000.json','["自君之出矣，明鏡罷紅妝。", "思君如夜燭，煎淚幾千行。"]'),
('3c6f3b8e-01b6-4086-ad0c-5342311fafb1','賦飲馬長城窟','袁朗','唐','唐诗','tang','','[]','朔風動秋草，清蹕長安道。',180,'全唐诗/poet.tang.2000.json','["朔風動秋草，清蹕長安道。", "長城連不窮，所以隔華戎。", "規模惟聖作，負荷曉成功。", "鳥庭已向內，龍荒更鑿空。", "玉關塵卷靜，金微路已通。", "湯征隨北怨，舜詠起南風。", "畫地功初立，綏邊事云集。", "朝服踐狼居，凱歌旋馬邑。", "山響傳鳳吹，霜華藻瓊鈒。", "屬國擁節歸，單于款關入。", "日落寒風起，驚蓬被原隰。", "零落葉已寒，河流清且急。", "四時徭役盡，千載干戈戢。", "太平今若斯，汗馬竟無施。", "唯當事筆硯，歸去草封禪。"]'),
('b1e06d6d-3965-450a-8705-4a9a9a907aa0','和洗掾登城南坂望京邑','袁朗','唐','唐诗','tang','','[]','二華連陌塞，九隴統金方。',288,'全唐诗/poet.tang.2000.json','["二華連陌塞，九隴統金方。", "奧區稱富貴，重險擅雄強。", "龍飛灞水上，鳳集岐山陽。", "神皐多瑞蹟，列代有興王。", "我后膺靈命，爰求宅茲土。", "宸居法太微，建國資天府。", "玄風叶黎庶，德澤浸區宇。", "醒醉各相扶，謳歌從聖主。", "南登少陵岸，還望帝城中。", "帝城何鬱鬱，佳氣乃蔥蔥。", "金鳳凌綺觀，璇題敞蘭宮。", "複道東西合，交衢南北通。", "萬國朝前殿，羣公議宣室。", "鳴珮含早風，華蟬曜朝日。", "栢梁宴初罷，千鍾歡未畢。", "端拱肅巖廊，思賢聽琴瑟。", "逶迤萬雉列，隱軫千閭布。", "飛甍夾御溝，曲臺臨上路。", "處處歌鐘鳴，喧闐車馬度。", "日落長楸間，含情兩相顧。", "是月冬之季，陰寒晝不開。", "驚風四面集，飛雪千里迴。", "狐白登廊廟，牛衣出草萊。", "詎知韓長孺，無復重然灰。"]'),
('f8790539-a9ff-4935-b413-02b36e109943','秋日應詔','袁朗','唐','唐诗','tang','','[]','玉樹涼風舉，金塘細草萎。',48,'全唐诗/poet.tang.2000.json','["玉樹涼風舉，金塘細草萎。", "葉落商飆觀，鴻歸明月池。", "迎寒桂酒熟，含露菊花垂。", "一奉章臺宴，千秋長願斯。"]'),
('81e33d15-96d6-41a8-b473-067d61204335','秋夜獨坐','袁朗','唐','唐诗','tang','','[]','危弦斷客心，虛彈落驚禽。',48,'全唐诗/poet.tang.2000.json','["危弦斷客心，虛彈落驚禽。", "新秋百慮淨，獨夜九愁深。", "枯蓬唯逐吹，墜葉不歸林。", "如何悲此曲，坐作白頭吟。"]'),
('c7f6bafd-608d-456f-a3b7-b83a99baebc5','出塞曲','竇威','唐','唐诗','tang','','[]','匈奴屢不平，漢將欲縱橫。',48,'全唐诗/poet.tang.2000.json','["匈奴屢不平，漢將欲縱橫。", "看雲方結陣，却月始連營。", "潛軍度馬邑，揚斾掩龍城。", "會勒燕然石，方傳車騎名。"]'),
('5d640d9f-392a-462d-8c28-2d491b55a855','新曲二首 一','長孫無忌','唐','唐诗','tang','','[]','阿儂家住朝歌下，早傳名。',56,'全唐诗/poet.tang.2000.json','["阿儂家住朝歌下，早傳名。", "結伴來游淇水上，舊長情。", "玉珮金鈿隨步遠，雲羅霧縠逐風輕。", "轉目機心懸自許，何須更待聽琴聲。"]'),
('b24f270a-b351-4b5e-b576-3ced55cd14f9','新曲二首 二','長孫無忌','唐','唐诗','tang','','[]','迴雪凌波游洛浦，遇陳王。',56,'全唐诗/poet.tang.2000.json','["迴雪凌波游洛浦，遇陳王。", "婉約娉婷工語笑，侍蘭房。", "芙蓉綺帳還開揜，翡翠珠被爛齊光。", "長願今宵奉顏色，不愛吹簫逐鳳皇。"]'),
('a1948620-90a5-4133-a42a-4d7724a2e518','灞橋待李將軍','長孫無忌','唐','唐诗','tang','','[]','颯颯風葉下，遙遙煙景曛。',24,'全唐诗/poet.tang.2000.json','["颯颯風葉下，遙遙煙景曛。", "霸陵無醉尉，誰滯李將軍。"]'),
('bf9a5f31-2b78-46fb-9217-3d51e10af5bf','奉和正日臨朝','顏師古','唐','唐诗','tang','','[]','七府璿衡始，三元寶曆新。',48,'全唐诗/poet.tang.2000.json','["七府璿衡始，三元寶曆新。", "負扆延百辟，垂旒御九賓。", "肅肅皆鵷鷺，濟濟盛簪紳。", "天涯致重譯，日域獻奇珍。"]'),
('1e6ba48f-a140-4e73-9f1d-f00a55c2c9bd','召拜御史大夫贈袁天綱','杜淹','唐','唐诗','tang','','[]','伊呂深可慕，松喬定是虛。',48,'全唐诗/poet.tang.2000.json','["伊呂深可慕，松喬定是虛。", "繫風終不得，脫屣欲安如。", "且珍紈素美，當與薜蘿疎。", "既逢楊得意，非復久閑居。"]'),
('b0212665-b88b-4425-8c17-9c78aaca8203','詠寒食鬬雞應秦王教','杜淹','唐','唐诗','tang','','[]','寒食東郊道，揚鞲競出籠。',72,'全唐诗/poet.tang.2000.json','["寒食東郊道，揚鞲競出籠。", "花冠初照日，芥羽正生風。", "顧敵知心勇，先鳴覺氣雄。", "長翹頻掃陣，利爪屢通中。", "飛毛遍綠野，灑血漬芳叢。", "雖然百戰勝，會自不論功。"]'),
('3270b5d8-2783-41fe-9868-ad4cbab63477','寄贈齊公','杜淹','唐','唐诗','tang','','[]','冠蓋游梁日，詩書問志年。',120,'全唐诗/poet.tang.2000.json','["冠蓋游梁日，詩書問志年。", "佩蘭長坂上，攀桂小山前。", "結交澹若水，履道直如弦。", "此歡終未極，于茲獨播遷。", "赭衣登蜀道，白首別秦川。", "淚隨溝水逝，心逐曉旌懸。", "去去逾千里，悠悠隔九天。", "郊野間長薄，城闕隱凝煙。", "關門共月對，山路與雲連。", "此時寸心裏，難用尺書傳。"]'),
('36c15a70-31d9-4e06-92c1-d3363a58a937','五郊樂章 黃帝宮音','魏徵','唐','唐诗','tang','','[]','黃中正位，含章居貞。',40,'全唐诗/poet.tang.2000.json','["黃中正位，含章居貞。", "既長六律，兼和五聲。", "畢陳萬舞，乃薦斯牲。", "神其下降，永祚休平。"]'),
('e5acfc1c-dc8a-46a0-8be1-6d03c83b50a7','五郊樂章 黃帝宮音 肅和','魏徵','唐','唐诗','tang','','[]','眇眇方輿，蒼蒼圜蓋。',40,'全唐诗/poet.tang.2000.json','["眇眇方輿，蒼蒼圜蓋。", "至哉樞紐，宅中圖大。", "氣調四序，風和萬籟。", "祚我明德，時雍道泰。"]'),
('c3d63b68-644c-48ef-b1f7-be8c09a68c76','五郊樂章 黃帝宮音 雍和','魏徵','唐','唐诗','tang','','[]','金懸夕肆，玉俎朝陳。',40,'全唐诗/poet.tang.2000.json','["金懸夕肆，玉俎朝陳。", "饗薦黃道，芬流紫辰。", "廼誠廼敬，載享載禋。", "崇薦斯在，惟皇是賓。"]'),
('bba78c6c-280c-4775-bf56-953cb976e743','五郊樂章 黃帝宮音 舒和','魏徵','唐','唐诗','tang','','[]','御徵乘宮出郊甸，安歌率舞逓將迎。',32,'全唐诗/poet.tang.2000.json','["御徵乘宮出郊甸，安歌率舞逓將迎。", "自有雲門符帝賞，猶持雷鼓荅天成。"]'),
('5bcd14f2-8b14-48f3-9be8-a49ccb2985d1','五郊樂章 青帝角音','魏徵','唐','唐诗','tang','','[]','鶴雲旦起，鳥星昏集。',40,'全唐诗/poet.tang.2000.json','["鶴雲旦起，鳥星昏集。", "律候新風，陽開初蟄。", "至德可饗，行潦斯挹。", "錫以無疆，烝人乃粒。"]'),
('51b4011f-a3cb-4d7a-bbc5-bfbb382dd23b','五郊樂章 青帝角音 肅和','魏徵','唐','唐诗','tang','','[]','玄鳥司春，蒼龍登歲。',40,'全唐诗/poet.tang.2000.json','["玄鳥司春，蒼龍登歲。", "節物變柳，光風轉蕙。", "瑤席降神，朱弦饗帝。", "誠備祝嘏，禮殫珪幣。"]'),
('3e5e0fdf-9fcb-4228-b07e-332764956a0b','五郊樂章 青帝角音 雍和','魏徵','唐','唐诗','tang','','[]','大樂稀音，至誠簡禮。',40,'全唐诗/poet.tang.2000.json','["大樂稀音，至誠簡禮。", "文物棣棣，聲名濟濟。", "六變有成，三登無體。", "廼眷豐絜，恩覃愷悌。"]'),
('f90090ac-d9c6-42f1-840f-9a09f4db1448','五郊樂章 青帝角音 舒和','魏徵','唐','唐诗','tang','','[]','笙歌籥舞屬年韶，鷺鼓鳧鐘展時豫。',32,'全唐诗/poet.tang.2000.json','["笙歌籥舞屬年韶，鷺鼓鳧鐘展時豫。", "調露初迎綺春節，承雲遽踐蒼霄馭。"]'),
('101e2502-ed57-4e83-b18f-b8d2529933be','五郊樂章 赤帝徵音','魏徵','唐','唐诗','tang','','[]','青陽告謝，朱明戒序。',40,'全唐诗/poet.tang.2000.json','["青陽告謝，朱明戒序。", "咸長是祈，敬陳椒醑。", "博碩斯薦，笙鏞備舉。", "庶盡肅恭，非馨稷黍。"]'),
('cc4c33d7-2981-4377-8468-5bc401128ffc','五郊樂章 赤帝徵音 肅和','魏徵','唐','唐诗','tang','','[]','離位克明，火中宵見。',40,'全唐诗/poet.tang.2000.json','["離位克明，火中宵見。", "峯雲暮起，景風晨扇。", "木槿初榮，含桃可薦。", "芬馥百品，鏗鏘三變。"]'),
('904bb636-f948-4ace-9822-ee7eb54a525c','五郊樂章 赤帝徵音 雍和','魏徵','唐','唐诗','tang','','[]','昭昭丹陸，帟帟炎方。',40,'全唐诗/poet.tang.2000.json','["昭昭丹陸，帟帟炎方。", "禮陳牲幣，樂備箎簧。", "瓊羞溢俎，玉𨣧浮觴。", "恭惟正直，歆此馨香。"]'),
('8068673e-5d5b-48be-8474-96204ac348ef','五郊樂章 赤帝徵音 舒和','魏徵','唐','唐诗','tang','','[]','千里溫風飄降羽，十枝炎景媵朱干。',32,'全唐诗/poet.tang.2000.json','["千里溫風飄降羽，十枝炎景媵朱干。", "陳觴薦俎歌三獻，拊石摐金會七盤。"]'),
('2f1dafdd-8251-46d8-a703-e7422bec309d','五郊樂章 白帝商音','魏徵','唐','唐诗','tang','','[]','白藏應節，天高氣清。',40,'全唐诗/poet.tang.2000.json','["白藏應節，天高氣清。", "歲功既阜，庶類收成。", "萬方靜謐，九土和平。", "馨香是薦，受祚聰明。"]'),
('c6a7bd4e-421b-409c-ba86-5511f9738184','五郊樂章 白帝商音 肅和','魏徵','唐','唐诗','tang','','[]','金行在節，素靈居正。',40,'全唐诗/poet.tang.2000.json','["金行在節，素靈居正。", "氣肅霜嚴，林凋草勁。", "豺祭隼擊，潦收川鏡。", "九穀已登，萬箱流詠。"]'),
('13b5b795-87d8-43eb-b05a-7a704d4797ed','五郊樂章 白帝商音 雍和','魏徵','唐','唐诗','tang','','[]','律應西成，氣躔南呂。',40,'全唐诗/poet.tang.2000.json','["律應西成，氣躔南呂。", "珪幣咸列，笙竽備舉。", "苾苾蘭羞，芬芬桂醑。", "式資宴貺，用調霜序。"]'),
('76f7c1a8-e4db-4732-8dcc-5238520ef773','五郊樂章 白帝商音 舒和','魏徵','唐','唐诗','tang','','[]','璿儀氣爽驚緹籥，玉呂灰飛含素商。',32,'全唐诗/poet.tang.2000.json','["璿儀氣爽驚緹籥，玉呂灰飛含素商。", "鳴鞞奏管芳羞薦，會舞安歌葆眊揚。"]'),
('4b395577-7cc4-4fbb-ab36-9165fd1bc743','五郊樂章 黑帝羽音','魏徵','唐','唐诗','tang','','[]','嚴冬季月，星迴風厲。',20,'全唐诗/poet.tang.2000.json','["嚴冬季月，星迴風厲。", "享祀報功，方祚來歲。"]'),
('16da4545-4983-4058-90a0-3358e343c732','五郊樂章 黑帝羽音 肅和','魏徵','唐','唐诗','tang','','[]','律周玉琯，星回金度。',40,'全唐诗/poet.tang.2000.json','["律周玉琯，星回金度。", "次極陽烏，紀窮陰兔。", "火林霰雪，陽泉凝冱。", "八蜡已登，三農息務。"]'),
('bec2d117-726f-46cd-9822-6161ce1554c5','五郊樂章 黑帝羽音 雍和','魏徵','唐','唐诗','tang','','[]','陽月斯紀，應鍾在候。',40,'全唐诗/poet.tang.2000.json','["陽月斯紀，應鍾在候。", "載絜牲牷，爰登俎豆。", "既高既遠，無聲無臭。", "靜言格思，惟神保祐。"]'),
('8aefd176-e102-43cf-a731-1c73427ae9f8','五郊樂章 黑帝羽音 舒和','魏徵','唐','唐诗','tang','','[]','執籥持羽初終曲，朱干玉鏚始分行。',32,'全唐诗/poet.tang.2000.json','["執籥持羽初終曲，朱干玉鏚始分行。", "七德九功咸已暢，明靈降福具穰穰。"]'),
('6467fb7f-094f-4c66-96f8-8b02ace07db4','享太廟樂章 永和','魏徵','唐','唐诗','tang','','[]','於穆烈祖，弘此丕基。',40,'全唐诗/poet.tang.2000.json','["於穆烈祖，弘此丕基。", "永言配命，子孫保之。", "百神既洽，萬國在茲。", "是用孝享，神其格思。"]'),
('b2cf9832-0b09-4085-8a27-40aea6d0745d','享太廟樂章 肅和','魏徵','唐','唐诗','tang','','[]','大哉至德，允茲明聖。',40,'全唐诗/poet.tang.2000.json','["大哉至德，允茲明聖。", "格于上下，聿遵誠敬。", "嘉樂斯登，鳴球以詠。", "神其降止，式隆景命。"]'),
('ce96d9d5-069c-4bf3-97bc-71c7e919f03b','享太廟樂章 雍和','魏徵','唐','唐诗','tang','','[]','崇茲享祀，誠敬兼至。',40,'全唐诗/poet.tang.2000.json','["崇茲享祀，誠敬兼至。", "樂以感靈，禮以昭事。", "粢盛咸絜，牲牷孔備。", "永言孝思，庶幾不匱。"]'),
('5d7a169a-2803-4d8d-b6ac-f7183f316a32','享太廟樂章 長發舞','魏徵','唐','唐诗','tang','','[]','濬哲惟唐，長發其祥。',40,'全唐诗/poet.tang.2000.json','["濬哲惟唐，長發其祥。", "帝命斯祐，王業克昌。", "配天載德，就日重光。", "本枝百代，申錫無疆。"]'),
('df80ac1b-a18f-48ce-a1eb-dde0a22fcd79','享太廟樂章 大基舞','魏徵','唐','唐诗','tang','','[]','猗與祖業，皇矣帝先。',40,'全唐诗/poet.tang.2000.json','["猗與祖業，皇矣帝先。", "剪商德厚，封唐慶延。", "在姬猶稷，方晉踰宣。", "基我鼎運，于斯萬年。"]'),
('7d001393-f402-4cce-9c09-666c24bb6e1d','享太廟樂章 大成舞','魏徵','唐','唐诗','tang','','[]','周穆王季，晉美帝文。',40,'全唐诗/poet.tang.2000.json','["周穆王季，晉美帝文。", "明明盛德，穆穆齊芬。", "藏用四履，屈道參分。", "鏗鏘鐘石，載紀鴻勳。"]'),
('cea9f2c3-df03-40db-8607-e18fa81d25f9','享太廟樂章 大明舞','魏徵','唐','唐诗','tang','','[]','五紀更運，三正逓升。',120,'全唐诗/poet.tang.2000.json','["五紀更運，三正逓升。", "勛華既沒，禹湯勃興。", "神武命代，靈睠是膺。", "望雲彰德，察緯告徵。", "上紐天維，下安地軸。", "徵師涿野，萬國咸服。", "偃伯靈臺，九官允穆。", "殊域委贐，懷生介福。", "大禮既飾，大樂已和。", "黑章擾囿，赤字浮河。", "功宣載籍，德被詠歌。", "克昌厥後，百祿是荷。"]'),
('f50edb58-c2da-4b4c-8313-cb0228bf8421','享太廟樂章 壽和','魏徵','唐','唐诗','tang','','[]','八音斯奏，三獻畢陳。',20,'全唐诗/poet.tang.2000.json','["八音斯奏，三獻畢陳。", "寶祚惟永，暉光日新。"]'),
('14f70ec7-e472-4803-a619-06874f28567a','享太廟樂章 舒和','魏徵','唐','唐诗','tang','','[]','聖敬通神光七廟，靈心薦祚和萬方。',32,'全唐诗/poet.tang.2000.json','["聖敬通神光七廟，靈心薦祚和萬方。", "嚴禋克配鴻基遠，明德惟馨鳳曆昌。"]'),
('7c09e229-cfc8-4a2d-a3fa-d01c6a0dbfbe','享太廟樂章 雍和','魏徵','唐','唐诗','tang','','[]','於穆清廟，聿脩嚴祀。',40,'全唐诗/poet.tang.2000.json','["於穆清廟，聿脩嚴祀。", "四縣載陳，三獻斯止。", "籩豆撤薦，人祗介祉。", "神惟格思，錫祚不已。"]'),
('fa3acb17-3c28-4d18-a11d-0b44b5552970','享太廟樂章 永和','魏徵','唐','唐诗','tang','','[]','肅肅清祀，烝烝孝思。',40,'全唐诗/poet.tang.2000.json','["肅肅清祀，烝烝孝思。", "薦享昭備，虔恭在茲。", "雍歌撤俎，祝嘏陳辭。", "用光武志，永固鴻基。"]'),
('c3c25975-9405-4c66-af2d-0d9a080dbc8e','賦西漢','魏徵','唐','唐诗','tang','','[]','受降臨軹道，爭長趣鴻門。',48,'全唐诗/poet.tang.2000.json','["受降臨軹道，爭長趣鴻門。", "驅傳渭橋上，觀兵細柳屯。", "夜宴經柏谷，朝遊出杜原。", "終藉叔孫禮，方知皇帝尊。"]'),
('e19050d3-c051-46cc-b1a7-fd0e64c776ab','暮秋言懷','魏徵','唐','唐诗','tang','','[]','首夏別京輔，杪秋滯三河。',48,'全唐诗/poet.tang.2000.json','["首夏別京輔，杪秋滯三河。", "沈沈蓬萊閣，日夕鄉思多。", "霜剪涼階蕙，風捎幽渚荷。", "歲芳坐淪歇，感此式微歌。"]'),
('5de65084-28e0-44c9-b2fc-3bb7a1e2db6d','述懷','魏徵','唐','唐诗','tang','','[]','中原初逐鹿，投筆事戎軒。',120,'全唐诗/poet.tang.2000.json','["中原初逐鹿，投筆事戎軒。", "縱橫計不就，慷慨志猶存。", "杖策謁天子，驅馬出關門。", "請纓繫南粵，憑軾下東藩。", "鬱紆陟高岫，出沒望平原。", "古木鳴寒鳥，空山啼夜猿。", "既傷千里目，還驚九折魂。", "豈不憚艱險，深懷國士恩。", "季布無二諾，侯嬴重一言。", "人生感意氣，功名誰復論。"]'),
('8c4672e3-4f3d-46c3-afd3-bddc1a48aa73','奉和正日臨朝應詔','魏徵','唐','唐诗','tang','','[]','百靈侍軒后，萬國會塗山。',96,'全唐诗/poet.tang.2000.json','["百靈侍軒后，萬國會塗山。", "豈如今睿哲，邁古獨光前。", "聲教溢四海，朝宗引百川。", "鏘洋鳴玉珮，灼爍耀金蟬。", "淑景輝雕輦，高旌揚翠煙。", "庭實超王會，廣樂盛鈞天。", "既欣東日戶，復詠南風篇。", "願奉光華慶，從斯億萬年。"]'),
('61eb5ea5-7deb-4c42-adf0-b3d6cac9e569','祈穀樂章 肅和','褚亮','唐','唐诗','tang','','[]','履艮斯繩，居中體正。',40,'全唐诗/poet.tang.2000.json','["履艮斯繩，居中體正。", "龍運垂祉，昭符啓聖。", "式事嚴禋，聿懷嘉慶。", "惟帝永錫，時皇休命。"]'),
('51b150eb-0a37-4885-bd6b-367808236532','祈穀樂章 雍和','褚亮','唐','唐诗','tang','','[]','殷薦乘春，太壇臨曙。',40,'全唐诗/poet.tang.2000.json','["殷薦乘春，太壇臨曙。", "八簋盈和，六瑚登御。", "嘉稷匪歆，德馨斯飫。", "祝嘏無易，靈心有豫。"]'),
('e2313b75-6c38-4707-8631-936ab9a87df1','祈穀樂章 舒和','褚亮','唐','唐诗','tang','','[]','玉帛犧牲申敬享，金絲鏚羽盛音容。',32,'全唐诗/poet.tang.2000.json','["玉帛犧牲申敬享，金絲鏚羽盛音容。", "庶俾億齡禔景福，長欣萬宇洽時邕。"]'),
('062bf763-b5d0-4b3d-97ff-3cf51b77fee7','明堂樂章 肅和','褚亮','唐','唐诗','tang','','[]','象天御宇，乘時布政。',40,'全唐诗/poet.tang.2000.json','["象天御宇，乘時布政。", "嚴配申虔，宗禋展敬。", "罇罍盈列，樹羽交暎。", "玉幣通誠，祚隆皇聖。"]'),
('43b881a7-13af-4ad0-aa42-a18adc6872bd','明堂樂章 雍和','褚亮','唐','唐诗','tang','','[]','八牖晨披，五精朝奠。',42,'全唐诗/poet.tang.2000.json','["八牖晨披，五精朝奠。", "霧凝璇篚，風清金縣。", "神滌備全，明粢豐衍。", "載[絜]彝俎，陳誠以薦。"]'),
('39b5664c-a547-40b6-9526-9c78006bb151','明堂樂章 舒和','褚亮','唐','唐诗','tang','','[]','御扆合宮承寶曆，席圖重館奉明靈。',32,'全唐诗/poet.tang.2000.json','["御扆合宮承寶曆，席圖重館奉明靈。", "偃武修文九圍泰，沈烽靜柝八荒寧。"]'),
('e0eef0a0-bbe6-45c6-a18f-086a92af4234','雩祀樂章 肅和','褚亮','唐','唐诗','tang','','[]','朱鳥開辰，蒼龍啓暎。',40,'全唐诗/poet.tang.2000.json','["朱鳥開辰，蒼龍啓暎。", "大帝昭饗，羣生展敬。", "禮備懷柔，功宣舞詠。", "旬液應序，年祥叶慶。"]'),
('3950db34-3491-4a51-b6c6-3f14c63f66d8','雩祀樂章 雍和','褚亮','唐','唐诗','tang','','[]','紺筵分彩，珤圖吐絢。',40,'全唐诗/poet.tang.2000.json','["紺筵分彩，珤圖吐絢。", "鳳管晨凝，雲歌曉囀。", "肅事蘋藻，虔申桂奠。", "百穀斯登，萬箱攸薦。"]'),
('eb7a703d-e2ee-4d2b-9994-b69ca125d56f','雩祀樂章 舒和','褚亮','唐','唐诗','tang','','[]','鳳曲登歌調令序，龍雩集舞泛祥風。',32,'全唐诗/poet.tang.2000.json','["鳳曲登歌調令序，龍雩集舞泛祥風。", "綵旞雲迴昭睿德，朱干電發表神功。"]'),
('3b0605e8-43a2-4763-8c62-bbb8e3afd186','享先農樂章 誠和','褚亮','唐','唐诗','tang','','[]','粒食伊始，農之所先。',40,'全唐诗/poet.tang.2000.json','["粒食伊始，農之所先。", "古今攸賴，是曰人天。", "耕斯帝籍，播厥公田。", "式崇明祀，神其福焉。"]'),
('b0076a66-ee4f-4bd2-9f05-1cc30fc694db','享先農樂章 肅和','褚亮','唐','唐诗','tang','','[]','罇彝既列，瑚簋方薦。',40,'全唐诗/poet.tang.2000.json','["罇彝既列，瑚簋方薦。", "歌工載登，幣禮斯奠。", "肅肅享祀，顒顒纓弁。", "神之聽之，福流寰縣。"]'),
('8594acb1-1052-41f5-a2b3-77be32b002ed','享先農樂章 雍和','褚亮','唐','唐诗','tang','','[]','前夕視牲，質明奉俎。',40,'全唐诗/poet.tang.2000.json','["前夕視牲，質明奉俎。", "沐芳整弁，其儀式序。", "盛禮畢陳，嘉樂備舉。", "歆我懿德，非馨稷黍。"]'),
('05065565-9306-4524-ba88-52621f4c1431','享先農樂章 舒和','褚亮','唐','唐诗','tang','','[]','羽籥低昂文綴已，干戚蹈厲武行初。',32,'全唐诗/poet.tang.2000.json','["羽籥低昂文綴已，干戚蹈厲武行初。", "望歲祈農神所聽，延祥介福豈云虛。"]'),
('fb1e7d92-ba37-417f-a4eb-f5d5eb1307be','祭神州樂章 肅和','褚亮','唐','唐诗','tang','','[]','大矣坤儀，至哉神縣。',40,'全唐诗/poet.tang.2000.json','["大矣坤儀，至哉神縣。", "包含日域，牢籠月竁。", "露絜三清，風調六變。", "皇祗届止，式歆恭薦。"]'),
('0b24addb-6986-4eb1-ae0a-e7fbfb72e243','祭神州樂章 雍和','褚亮','唐','唐诗','tang','','[]','泰圻嚴享，陰郊展敬。',40,'全唐诗/poet.tang.2000.json','["泰圻嚴享，陰郊展敬。", "禮以導神，樂以和性。", "黝牲在列，黃琮俯暎。", "九土既平，萬邦貽慶。"]'),
('e3a25609-1ade-477a-8eb6-b28394686b83','祭神州樂章 舒和','褚亮','唐','唐诗','tang','','[]','坤道降祥和庶品，靈心載德厚羣生。',32,'全唐诗/poet.tang.2000.json','["坤道降祥和庶品，靈心載德厚羣生。", "水土既調三極泰，文武畢備九區平。"]'),
('d74f48a9-4a52-429e-b2ff-1ceb5c6eb8ad','祭方丘樂章 順和','褚亮','唐','唐诗','tang','','[]','萬物資以化，交泰屬昇平。',48,'全唐诗/poet.tang.2000.json','["萬物資以化，交泰屬昇平。", "易從業惟簡，得一道斯寧。", "具儀光玉帛，送舞變咸英。", "黍稷良非貴，明德信惟馨。"]'),
('ffecaa96-c386-42c9-a448-da003bf1be10','祭方丘樂章 肅和','褚亮','唐','唐诗','tang','','[]','至矣坤德，皇哉地祗。',40,'全唐诗/poet.tang.2000.json','["至矣坤德，皇哉地祗。", "開元統紐，合大承規。", "九宮肅列，六典相儀。", "永言配命，長保無虧。"]'),
('def95fdf-e5f0-4ac5-a803-ea969cccb395','祭方丘樂章 雍和','褚亮','唐','唐诗','tang','','[]','柔而能方，直而能敬。',40,'全唐诗/poet.tang.2000.json','["柔而能方，直而能敬。", "厚載以德，大亨以正。", "有滌斯牷，有馨斯盛。", "介茲景福，祚我休慶。"]'),
('5b22c264-5ba8-4583-b2c3-b170681e4eec','祭方丘樂章 舒和','褚亮','唐','唐诗','tang','','[]','玉幣牲牷分薦享，羽旄干鏚遰成容。',32,'全唐诗/poet.tang.2000.json','["玉幣牲牷分薦享，羽旄干鏚遰成容。", "一德惟寧兩儀泰，三材保合四時邕。"]'),
('88a2901c-330a-4ad5-a082-4dbf2c28c87f','祭方丘樂章 順和','褚亮','唐','唐诗','tang','','[]','陰祗協贊，厚載方貞。',40,'全唐诗/poet.tang.2000.json','["陰祗協贊，厚載方貞。", "牲幣具舉，簫管備成。", "其禮惟肅，其德惟明。", "神之聽矣，式鑒虔誠。"]'),
('56ba6ccc-ed3b-41f5-8995-2d506fcad31f','臨高臺','褚亮','唐','唐诗','tang','','[]','高臺暫俯臨，飛翼聳輕音。',48,'全唐诗/poet.tang.2000.json','["高臺暫俯臨，飛翼聳輕音。", "浮光隨日度，漾影逐波深。", "迴瞰周平野，開懷暢遠襟。", "獨此三休上，還傷千歲心。"]'),
('d8f9cbbe-1916-4d4f-acec-9d4faf669916','賦得蜀都','褚亮','唐','唐诗','tang','','[]','列宿光參井，分芒跨梁岷。',60,'全唐诗/poet.tang.2000.json','["列宿光參井，分芒跨梁岷。", "沈犀對江浦，駟馬入城闉。", "英圖多霸跡，歷選有名臣。", "連騎簪纓滿，含章詞賦新。", "得上仙槎路，無待訪嚴遵。"]'),
('2a900189-b746-4fca-bbf6-ec056ea29d63','奉和詠日午','褚亮','唐','唐诗','tang','','[]','曦車日亭午，浮箭未移暉。',48,'全唐诗/poet.tang.2000.json','["曦車日亭午，浮箭未移暉。", "日光無落照，樹影正中圍。", "草萎看稍靡，葉燥望疑稀。", "晝寢慙經笥，暫解入朝衣。"]'),
('bdfbb09a-d41f-49bc-a7e7-4ed6c9335d71','奉和望月應魏王教','褚亮','唐','唐诗','tang','','[]','層軒登皎月，流照滿中天。',48,'全唐诗/poet.tang.2000.json','["層軒登皎月，流照滿中天。", "色共梁珠遠，光隨趙璧圓。", "落影臨秋扇，虛輪入夜弦。", "所欣東館裏，預奉西園篇。"]'),
('2907d5c7-28c9-457d-9b1d-eae0cabb5cc7','詠花燭','褚亮','唐','唐诗','tang','','[]','蘭逕香風滿，梅梁暖日斜。',48,'全唐诗/poet.tang.2000.json','["蘭逕香風滿，梅梁暖日斜。", "言是東方騎，來尋南陌車。", "靨星臨夜燭，眉月隱輕紗。", "莫言春稍晚，自有鎮開花。"]'),
('035d3b86-2369-4700-b853-2b1c55db3600','在隴頭哭潘學士','褚亮','唐','唐诗','tang','','[]','隴底嗟長別，流襟一慟君。',48,'全唐诗/poet.tang.2000.json','["隴底嗟長別，流襟一慟君。", "何言幽咽所，更作死生分。", "轉蓬飛不息，悲松斷更聞。", "誰能駐征馬，回首望孤墳。"]'),
('b8dd378c-a8ad-449f-8382-ea370477e289','奉和禁苑餞別應令','褚亮','唐','唐诗','tang','','[]','大藩初錫瑞，出牧邇皇京。',120,'全唐诗/poet.tang.2000.json','["大藩初錫瑞，出牧邇皇京。", "暫以綠車重，言承朱傳榮。", "舒桃臨遠騎，垂柳映京營。", "惠化宣千里，威風動百城。", "禁籞芳嘉節，神襟餞送情。", "金笳催別景，玉琯切離聲。", "野花開更落，山鳥哢還驚。", "微臣夙多幸，薄宦奉儲明。", "釣臺慙作賦，伊水濫聞笙。", "懷德良知久，酬恩識命輕。"]'),
('d31e0ffc-0463-4e84-aaf4-7e50db6fda6c','和御史韋大夫喜霽之作','褚亮','唐','唐诗','tang','','[]','晴天度旅雁，斜影照殘虹。',74,'全唐诗/poet.tang.2000.json','["晴天度旅雁，斜影照殘虹。", "野淨餘煙盡，山明遠色同。", "沙平寒水落，葉脆晚枝空。", "白簡光朝幰，彤騶出禁中。", "息駕遊蘭[坂]，雕文折桂叢。", "無因輕羽扇，徒自仰仁風。"]'),
('2d657619-0d58-46c1-9e1f-3af22bf57230','晚別樂記室彥','褚亮','唐','唐诗','tang','','[]','窮途屬歲晚，臨水忽分悲。',60,'全唐诗/poet.tang.2000.json','["窮途屬歲晚，臨水忽分悲。", "抱影同爲客，傷情共此時。", "霧色侵虛牖，霜氛冷薄帷。", "舉袂慘將別，停杯悵不怡。", "風嚴征雁遠，雪暗去篷遲。"]'),
('60de425a-6756-42a6-a0ef-8eb2b8f34699','傷始平李少府正己','褚亮','唐','唐诗','tang','','[]','勞息本相循，悲歡理自均。',168,'全唐诗/poet.tang.2000.json','["勞息本相循，悲歡理自均。", "誰能免玄夜，惜爾正青春。", "邁德惟家寶，生才諒國珍。", "高文綴翡翠，茂學掩麒麟。", "述作紛無已，言談妙入神。", "斷腸雖累月，分手未盈旬。", "輔嗣俄長往，顏生即短辰。", "聲華滿昭代，形影委窮塵。", "禪草迴中使，生芻引弔賓。", "同遊祕府日，方駕直城闉。", "並拜黃圖右，分曹清渭濱。", "風期嵇呂好，存歿范張親。", "虛座憐王述，遺篇慟景純。", "精靈與毫翰，千祀壽何人。"]'),
('9d3d8ac4-987d-4978-920a-fac094a709d2','秋鴈','褚亮','唐','唐诗','tang','','[]','日暮霜風急，羽翮轉難任。',24,'全唐诗/poet.tang.2000.json','["日暮霜風急，羽翮轉難任。", "爲有傳書意，翩翩入上林。"]'),
('935d8505-f3c1-4cbc-867c-d10b3a52a620','句','褚亮','唐','唐诗','tang','','[]','神羊既不觸，夕鳥欲依人。',12,'全唐诗/poet.tang.2000.json','["神羊既不觸，夕鳥欲依人。"]'),
('2d36a855-49b6-41d7-8fc7-3c83e20031e2','冬日宴羣公於宅各賦一字得杯','于志寧','唐','唐诗','tang','','[]','陋巷朱軒擁，衡門緹騎來。',48,'全唐诗/poet.tang.2000.json','["陋巷朱軒擁，衡門緹騎來。", "俱裁七步詠，同傾三雅杯。", "色動迎春柳，花發犯寒梅。", "賓筵未半醉，驪歌不用催。"]'),
('9d7fd022-1305-438f-9189-c263d7a9e7c9','冬日宴于庶子宅各賦一字得趣','令狐德棻','唐','唐诗','tang','','[]','高門聊命賞，羣英於此遇。',48,'全唐诗/poet.tang.2000.json','["高門聊命賞，羣英於此遇。", "放曠山水情，留連文酒趣。", "夕煙起林蘭，霜枝殞庭樹。", "落景雖已傾，歸軒幸能駐。"]'),
('52f0553b-299b-4f5a-afe3-bd4fa740ad73','冬日宴于庶子宅各賦一字得色','封行高','唐','唐诗','tang','','[]','夫君敬愛重，歡言情不極。',48,'全唐诗/poet.tang.2000.json','["夫君敬愛重，歡言情不極。", "雅引發清音，麗藻窮雕飾。", "水結曲池冰，日暖平亭色。", "引滿既杯傾，終之以弁側。"]'),
('25f2e98f-1527-4a5d-aece-4474b716209a','冬日宴于庶子宅各賦一字得節','杜正倫','唐','唐诗','tang','','[]','李門余妄進，徐榻君恆設。',48,'全唐诗/poet.tang.2000.json','["李門余妄進，徐榻君恆設。", "清論暢玄言，雅琴飛白雪。", "寒雲曖落景，朔風淒暮節。", "方欣投轄情，且駐當歸別。"]'),
('278abb55-9c5e-4456-a748-64639a55ad7e','玄武門侍宴','杜正倫','唐','唐诗','tang','','[]','大君端扆暇，睿賞狎林泉。',120,'全唐诗/poet.tang.2000.json','["大君端扆暇，睿賞狎林泉。", "開軒臨禁籞，藉野列芳筵。", "參差歌管颺，容裔羽旗懸。", "玉池流若醴，雲閣聚非煙。", "湛露晞堯日，熏風入舜弦。", "大德侔玄造，微物荷陶甄。", "謬陪瑤水宴，仍廁栢梁篇。", "闞名徒上月，鄒辯詎談天。", "既喜光華旦，還傷遲暮年。", "猶冀升中日，簪裾奉肅然。"]'),
('a4a73922-2acd-41b8-aebc-91d6c82938aa','奉和正日臨朝','岑文本','唐','唐诗','tang','','["\u6cf0\u5c71"]','時雍表昌運，日正叶靈符。',96,'全唐诗/poet.tang.2000.json','["時雍表昌運，日正叶靈符。", "德兼三代禮，功包四海圖。", "踰沙紛在列，執玉儼相趨。", "清蹕喧輦道，張樂駭天衢。", "拂蜺九旗暎，儀鳳八音殊。", "佳氣浮仙掌，熏風繞帝梧。", "天文光七政，皇恩被九區。", "方陪瘞玉禮，珥筆岱山隅。"]'),
('56a1301a-de61-4570-96f8-9764d72b362b','奉述飛白書勢','岑文本','唐','唐诗','tang','','[]','六文開玉篆，八體曜銀書。',48,'全唐诗/poet.tang.2000.json','["六文開玉篆，八體曜銀書。", "飛毫列錦繡，拂素起龍魚。", "鳳舉崩雲絕，鸞驚遊霧疎。", "別有臨池草，恩霑垂露餘。"]'),
('d90209d5-cce5-4548-9317-5c05ade10b8d','冬日宴于庶子宅各賦一字得平','岑文本','唐','唐诗','tang','','[]','金蘭篤惠好，尊酒暢生平。',48,'全唐诗/poet.tang.2000.json','["金蘭篤惠好，尊酒暢生平。", "既欣投轄賞，暫緩望鄉情。", "愛景含霜晦，落照帶風輕。", "於茲歡宴洽，寵辱詎相驚。"]'),
('bf662230-6124-427a-9050-9a57938c9986','安德山池宴集','岑文本','唐','唐诗','tang','','[]','甲第多清賞，芳辰命羽巵。',72,'全唐诗/poet.tang.2000.json','["甲第多清賞，芳辰命羽巵。", "書帷通竹徑，琴臺枕槿籬。", "池疑夜壑徙，山似鬱洲移。", "雕楹網蘿薜，激瀨合塤篪。", "鳥戲翻新葉，魚躍動清漪。", "自得淹留趣，寧勞攀桂枝。"]'),
('1898e009-3428-440a-9559-884dfc68e5d3','安德山池宴集','劉洎','唐','唐诗','tang','','[]','平陽擅歌舞，金谷盛招攜。',72,'全唐诗/poet.tang.2000.json','["平陽擅歌舞，金谷盛招攜。", "何如兼往烈，會賞叶幽栖。", "已均朝野致，還欣物我齊。", "春晚花方落，蘭深徑漸迷。", "蒲新節尚短，荷小蓋猶低。", "無勞拂長袖，直待夜烏啼。"]'),
('fbfd3cf4-87b3-4f1d-ab4e-a094aec724de','安德山池宴集','褚遂良','唐','唐诗','tang','','[]','伏櫪丹霞外，遮園煥景舒。',72,'全唐诗/poet.tang.2000.json','["伏櫪丹霞外，遮園煥景舒。", "行雲泛層阜，蔽月下清渠。", "亭中奏趙瑟，席上舞燕裾。", "花落春鶯晚，風光夏葉初。", "良朋比蘭蕙，雕藻邁瓊琚。", "獨有狂歌客，來承歡宴餘。"]'),
('6afd5890-6b81-47f0-8896-ef82623a1dbd','安德山池宴集','楊續','唐','唐诗','tang','','[]','狹斜通鳳闕，上路抵青樓。',72,'全唐诗/poet.tang.2000.json','["狹斜通鳳闕，上路抵青樓。", "簪紱啓賓館，軒蓋臨御溝。", "西城多妙舞，主第出名謳。", "列峰疑宿霧，疏壑擬藏舟。", "花蝶辭風影，蘋藻含春流。", "酒闌高宴畢，自反山之幽。"]'),
('35775b11-83ef-458b-9358-4f05285db0b1','遊清都觀尋沈道士得仙字','劉孝孫','唐','唐诗','tang','','[]','紛吾因暇豫，行樂極留連。',96,'全唐诗/poet.tang.2000.json','["紛吾因暇豫，行樂極留連。", "尋真謁紫府，披霧覿青天。", "緬懷金闕外，遐想玉京前。", "飛軒俯松柏，抗殿接雲煙。", "滔滔清夏景，嘒嘒早秋蟬。", "橫琴對危石，酌醴臨寒泉。", "聊祛塵俗累，寧希龜鶴年。", "無勞生羽翼，自可狎神仙。"]'),
('055bba81-4c1a-46a0-bb05-67739d1cc395','早發成皐望河','劉孝孫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','清晨發巖邑，車馬走轘轅。',72,'全唐诗/poet.tang.2000.json','["清晨發巖邑，車馬走轘轅。", "迴瞰黃河上，惝怳屢飛魂。", "鴻流遵積石，驚浪下龍門。", "仙槎不辨處，沈璧想猶存。", "遠近洲渚出，颯沓鳧鴈喧。", "懷古空延佇，歎逝將何言。"]'),
('d9666ac5-1ab3-49e1-9a02-8a61381fd21d','遊靈山寺','劉孝孫','唐','唐诗','tang','','[]','吾王遊勝地，驂駕歷祗園。',72,'全唐诗/poet.tang.2000.json','["吾王遊勝地，驂駕歷祗園。", "臨風畫角憤，耀日采旗翻。", "永懷筌了義，寂念啓玄門。", "深谿窮地脉，高嶂接雲根。", "信美諧心賞，幽邃且攀援。", "曳裾欣扈從，方悟屏塵諠。"]'),
('59005266-3c8a-486e-afae-43f553681f8b','冬日宴于庶子宅各賦一字得鮮','劉孝孫','唐','唐诗','tang','','[]','解襟遊勝地，披雲促宴筵。',48,'全唐诗/poet.tang.2000.json','["解襟遊勝地，披雲促宴筵。", "清文振筆妙，高論寫言泉。", "凍柳含風落，寒梅照日鮮。", "驪歌雖欲奏，歸駕且留連。"]'),
('74a21db3-2b30-4688-b9d9-bb604db9d956','送劉散員同賦陳思王詩游人久不歸','劉孝孫','唐','唐诗','tang','','[]','鄉關渺天末，引領悵懷歸。',48,'全唐诗/poet.tang.2000.json','["鄉關渺天末，引領悵懷歸。", "羈旅久淫滯，物色屢芳菲。", "稍覺私意盡，行看蓬鬢衰。", "如何千里外，佇立霑裳衣。"]'),
('483d4cf0-c0f0-4df3-b145-098a121ba615','詠笛','劉孝孫','唐','唐诗','tang','','[]','涼秋夜笛鳴，流風韻九成。',48,'全唐诗/poet.tang.2000.json','["涼秋夜笛鳴，流風韻九成。", "調高時慷慨，曲變或淒清。", "征客懷離緒，鄰人思舊情。", "幸以知音顧，千載有奇聲。"]'),
('e904647d-47cc-42e7-9f6a-820b95e305bf','賦得春鶯送友人','劉孝孫','唐','唐诗','tang','','[]','流鶯拂繡羽，二月上林期。',48,'全唐诗/poet.tang.2000.json','["流鶯拂繡羽，二月上林期。", "待雪消金禁，銜花向玉墀。", "翅掩飛燕舞，啼惱婕妤悲。", "料取金閨意，因君問所思。"]'),
('1ea9c7f4-fb9a-4f4d-89a8-6baa6e7639ee','巫山高','陸敬','唐','唐诗','tang','','[]','巫岫鬱岧嶤，高高入紫霄。',48,'全唐诗/poet.tang.2000.json','["巫岫鬱岧嶤，高高入紫霄。", "白雲抱危石，玄猨挂迥條。", "懸崖激巨浪，脆葉隕驚飆。", "別有陽臺處，風雨共飄颻。"]'),
('3f850538-6564-463b-acb3-9c9566e01c07','遊隋故都','陸敬','唐','唐诗','tang','','[]','洛城聊顧步，長想遂留連。',192,'全唐诗/poet.tang.2000.json','["洛城聊顧步，長想遂留連。", "水鬬宮初毀，風變鼎將遷。", "皐陶德不建，汾隅祀忽焉。", "宗祊曠無象，聲朔緬誰傳。", "枌榆何冷落，禾黍鬱芊緜。", "悲歌盡商頌，太息憫周篇。", "來蘇佇聖德，濡足乃乘乾。", "正始淳風被，人勞用息肩。", "舞象文思澤，偃伯武功宣。", "則百昌厥後，於萬永斯年。", "茲辰素商節，灰管變星躔。", "平原悴秋草，喬木斂寒煙。", "翻黃墜疎葉，凝翠積高天。", "參差海曲鴈，寂寞柳門蟬。", "興悼今如此，悲愁復在旃。", "彷徨不忍去，杖策屢迴邅。"]'),
('706ffc71-758d-423a-b2af-f71864b4b506','遊清都觀尋沈道士得都字','陸敬','唐','唐诗','tang','','[]','聊排靈瑣闥，徐步入清都。',96,'全唐诗/poet.tang.2000.json','["聊排靈瑣闥，徐步入清都。", "青谿冥寂士，思玄徇道樞。", "十芒生藥笥，七燄發丹爐。", "縹袠桐君錄，朱書王母符。", "宮槐散綠穗，日槿落青柎。", "矯翰雷門鶴，飛來葉縣鳧。", "凌風自可御，安事迫中區。", "方追羽化侶，從此得玄珠。"]'),
('3f100fea-4315-4080-8697-036e1daef99b','七夕賦詠成篇','陸敬','唐','唐诗','tang','','[]','夙駕鳴鸞啓閶闔，霓裳遙裔儼天津。',64,'全唐诗/poet.tang.2000.json','["夙駕鳴鸞啓閶闔，霓裳遙裔儼天津。", "五明霜紈開羽扇，百和香車動畫輪。", "婉孌夜分能幾許，靚妝冶服爲誰新。", "片時歡娛自有極，已復長望隔年人。"]'),
('06f6c725-bf53-4a76-9bb3-4aea454900f0','七夕賦詠成篇','沈叔安','唐','唐诗','tang','','[]','皎皎宵月麗秋光，耿耿天津橫復長。',64,'全唐诗/poet.tang.2000.json','["皎皎宵月麗秋光，耿耿天津橫復長。", "停梭且復留殘緯，拂鏡及早更新妝。", "彩鳳齊駕初成輦，雕鵲填河已作梁。", "雖喜得同今夜枕，還愁重空明日牀。"]'),
('32a56143-74fd-4375-97a4-148dee929cd1','七夕賦詠成篇','何仲宣','唐','唐诗','tang','','[]','日日思歸勤理鬢，朝朝佇望嬾調梭。',64,'全唐诗/poet.tang.2000.json','["日日思歸勤理鬢，朝朝佇望嬾調梭。", "凌風寶扇遙臨月，映水仙車遠渡河。", "歷歷珠星疑拖珮，冉冉雲衣似曳羅。", "通宵道意終無盡，向曉離愁已復多。"]'),
('aea8bf82-2fa6-4242-9bbb-38ad78c180a4','遊清都觀尋沈道士得芳字','趙中虛','唐','唐诗','tang','','[]','青谿阻千仞，姑射藐汾陽。',96,'全唐诗/poet.tang.2000.json','["青谿阻千仞，姑射藐汾陽。", "未若游茲境，探玄衆妙場。", "鶴來疑羽客，雲泛似霓裳。", "寓目雖靈宇，遊神乃帝鄉。", "道存真理得，心灰俗累忘。", "煙霞凝抗殿，松桂肅長廊。", "早蟬清暮響，崇蘭散晚芳。", "即此翔寥廓，非復控榆枋。"]'),
('73a55acf-cc0a-4b6f-aae1-24663b8b8fa4','送劉散員賦得陳思王詩明月照高樓','楊濬','唐','唐诗','tang','','[]','高樓一何綺，素月復流明。',48,'全唐诗/poet.tang.2000.json','["高樓一何綺，素月復流明。", "重軒望不極，餘暉攬詎盈。", "鏡華當牖照，鉤影隔簾生。", "逆愁異尊酒，對此難爲情。"]'),
('e1e9364b-9365-4302-a5d0-502cc14ff8fb','隴頭水','楊師道','唐','唐诗','tang','','[]','隴頭秋月明，隴水帶關城。',84,'全唐诗/poet.tang.2000.json','["隴頭秋月明，隴水帶關城。", "笳添離別曲，風送斷腸聲。", "映雪峰猶暗，乘冰馬屢驚。", "霧中寒雁至，沙上轉蓬輕。", "天山傳羽檄，漢地急徵兵。", "陣開都護道，劒聚伏波營。", "於茲覺無渡，方共濯胡纓。"]'),
('d5997748-e6cf-4440-a06b-b5fa8ef41e1d','中書寓直詠雨簡褚起居上官學士','楊師道','唐','唐诗','tang','','[]','雲暗蒼龍闕，沈沈殊未開。',120,'全唐诗/poet.tang.2000.json','["雲暗蒼龍闕，沈沈殊未開。", "窗臨鳳凰沼，颯颯雨聲來。", "電影入飛閣，風威凌吹臺。", "長簷響奔溜，清簟肅浮埃。", "早荷葉稍沒，新篁枝半摧。", "茲晨悵多緒，懷友自難裁。", "況復重城內，日暮獨裴回。", "玉階良史筆，金馬掞天才。", "高甍通散騎，複道駕蓬萊。", "思君贈桃李，於此冀瓊瓌。"]'),
('afbd2efb-1b67-406a-ad86-42794681ac7e','闕題','楊師道','唐','唐诗','tang','','[]','漢家伊洛九重城，御路浮橋萬里平。',160,'全唐诗/poet.tang.2000.json','["漢家伊洛九重城，御路浮橋萬里平。", "桂戶雕梁連綺翼，虹梁繡柱映丹楹。", "朝光欲動千門曙，麗日初照百花明。", "燕趙蛾眉舊傾國，楚宮腰細本傳名。", "二月桑津期結伴，三春淇水逐關情。", "蘭叢有意飛雙蝶，柳葉無趣隱啼鶯。", "扇裏細妝將夜並，風前獨舞共花榮。", "兩鬟百萬誰論價，一笑千金判是輕。", "不爲披圖來侍寢，非因主第奉身迎。", "羊車詎畏青門閉，兔月今宵照後庭。"]'),
('a69be821-9410-4710-bc7b-c63c48d3a6af','初秋夜坐應詔','楊師道','唐','唐诗','tang','','[]','玉琯涼初應，金壺夜漸闌。',48,'全唐诗/poet.tang.2000.json','["玉琯涼初應，金壺夜漸闌。", "滄池流稍潔，仙掌露方漙。", "雁聲風處斷，樹影月中寒。", "爽氣長空淨，高吟覺思寬。"]'),
('5330d140-b84e-4b35-8e50-157998ac1ea8','賦終南山用風字韻應詔','楊師道','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','眷言懷隱逸，輟駕踐幽叢。',48,'全唐诗/poet.tang.2000.json','["眷言懷隱逸，輟駕踐幽叢。", "白雲飛夏雨，碧嶺橫春虹。", "草綠長楊路，花疎五柞宮。", "登臨日將晚，蘭桂起香風。"]'),
('a017cffc-4dbe-49b6-a6c4-bfaf65b91195','詠飲馬應詔','楊師道','唐','唐诗','tang','','[]','清晨控龍馬，弄影出花林。',48,'全唐诗/poet.tang.2000.json','["清晨控龍馬，弄影出花林。", "躞蹀依春澗，聯翩度碧潯。", "苔流染絲絡，水潔寫雕簪。", "一御瑤池駕，詎憶長城陰。"]'),
('adef4522-b5ab-4d44-9dae-28fd27113845','初宵看婚','楊師道','唐','唐诗','tang','','[]','洛城花燭動，戚里畫新蛾。',48,'全唐诗/poet.tang.2000.json','["洛城花燭動，戚里畫新蛾。", "隱扇羞應慣，含情愁已多。", "輕啼濕紅粉，微睇轉橫波。", "更笑巫山曲，空傳暮雨過。"]'),
('3fc68858-9811-42be-b12a-b40f5ed05e71','侍宴賦得起坐彈鳴琴二首 一','楊師道','唐','唐诗','tang','','[]','北林鵲夜飛，南軒月初進。',48,'全唐诗/poet.tang.2000.json','["北林鵲夜飛，南軒月初進。", "調弦發清徵，蕩心祛褊吝。", "變作離鴻聲，還入思歸引。", "長歎未終極，秋風飄素鬢。"]'),
('ceaf311c-4af3-44a3-b0e5-16349e67c380','侍宴賦得起坐彈鳴琴二首 二','楊師道','唐','唐诗','tang','','[]','絲傳園客意，曲奏楚妃情。',24,'全唐诗/poet.tang.2000.json','["絲傳園客意，曲奏楚妃情。", "罕有知音者，空勞流水聲。"]'),
('fc13122c-7420-479d-8ffb-c3ad849367a1','詠琴','楊師道','唐','唐诗','tang','','[]','久擅龍門質，孤竦嶧陽名。',36,'全唐诗/poet.tang.2000.json','["久擅龍門質，孤竦嶧陽名。", "齊娥初發弄，趙女正調聲。", "嘉客勿遽反，繁弦曲未成。"]'),
('4761de38-b930-4792-9c25-b1dca1d9d312','詠笙','楊師道','唐','唐诗','tang','','[]','短長插鳳翼，洪細摹鸞音。',36,'全唐诗/poet.tang.2000.json','["短長插鳳翼，洪細摹鸞音。", "能令楚妃歎，復使荆王吟。", "切切孤竹管，來應雲和琴。"]'),
('7a42884a-9056-4996-bc6f-c0af99a18e0b','應詔詠巢烏','楊師道','唐','唐诗','tang','','[]','桂樹春暉滿，巢烏刷羽儀。',60,'全唐诗/poet.tang.2000.json','["桂樹春暉滿，巢烏刷羽儀。", "朝飛麗城上，夜宿碧林陲。", "背風藏密葉，向日逐疎枝。", "仰德還能哺，依仁遂可窺。", "驚鳴雕輦側，王吉自相知。"]'),
('8b046bdd-e970-4f89-b885-df6e1bc7e51c','奉和夏日晚景應詔','楊師道','唐','唐诗','tang','','[]','輦路夾垂楊，離宮通建章。',72,'全唐诗/poet.tang.2000.json','["輦路夾垂楊，離宮通建章。", "日落橫峰影，雲歸起夕涼。", "雕軒動流吹，羽蓋息迴塘。", "薙草生還綠，殘花落尚香。", "青巖類姑射，碧澗似汾陽。", "幸屬無爲日，歡娛尚未央。"]'),
('4cd3e298-4419-4d67-9f4e-1de0d5971d92','奉和聖製春日望海','楊師道','唐','唐诗','tang','','[]','春山臨渤海，征旅輟晨裝。',120,'全唐诗/poet.tang.2000.json','["春山臨渤海，征旅輟晨裝。", "回瞰盧龍塞，斜瞻肅慎鄉。", "洪波迴地軸，孤嶼映雲光。", "落日驚濤上，浮天駭浪長。", "仙臺隱螭駕，水府汎黿梁。", "碣石朝煙滅，之罘歸雁翔。", "北巡非漢后，東幸異秦皇。", "搴旗羽林客，跋距少年場。", "龍擊驅遼水，鵬飛出帶方。", "將舉青丘繳，安訪白霓裳。"]'),
('48beb384-e597-45fc-ba0b-dcb2c18d6ac1','春朝閑步','楊師道','唐','唐诗','tang','','[]','休沐乘閑豫，清晨步北林。',60,'全唐诗/poet.tang.2000.json','["休沐乘閑豫，清晨步北林。", "池塘藉芳草，蘭芷襲幽衿。", "霧中分曉日，花裏弄春禽。", "野逕香恆滿，山階筍屢侵。", "何須命輕蓋，桃李自成陰。"]'),
('b8dcf4b1-b109-4681-8779-5106966740a5','還山宅','楊師道','唐','唐诗','tang','','[]','暮春還舊嶺，徙倚翫年華。',60,'全唐诗/poet.tang.2000.json','["暮春還舊嶺，徙倚翫年華。", "芳草無行逕，空山正落花。", "垂藤掃幽石，臥柳礙浮槎。", "鳥散茅簷靜，雲披澗戶斜。", "依然此泉路，猶是昔煙霞。"]'),
('f4afbb6e-4d8b-4bcc-b361-a72fd04cc881','詠馬','楊師道','唐','唐诗','tang','','[]','寶馬權奇出未央，雕鞍照曜紫金裝。',64,'全唐诗/poet.tang.2000.json','["寶馬權奇出未央，雕鞍照曜紫金裝。", "春草初生馳上苑，秋風欲動戲長楊。", "鳴珂屢度章臺側，細蹀經向濯龍傍。", "徒令漢將連年去，宛城今已獻名王。"]'),
('d5b98549-0aa4-46a7-a399-de2102b9fddb','奉和詠弓','楊師道','唐','唐诗','tang','','[]','霜重麟膠勁，風高月影圓。',24,'全唐诗/poet.tang.2000.json','["霜重麟膠勁，風高月影圓。", "烏飛隨帝輦，雁落逐鳴弦。"]'),
('19a36191-b1c4-4aaf-ab6e-36f21f4c17fb','詠硯','楊師道','唐','唐诗','tang','','[]','圓池類璧水，輕翰染煙華。',24,'全唐诗/poet.tang.2000.json','["圓池類璧水，輕翰染煙華。", "將軍欲定遠，見棄不應賒。"]'),
('bbad568c-2beb-494a-bb1c-56db0c955b7e','奉和正日臨朝應詔','楊師道','唐','唐诗','tang','','[]','皇猷被寰宇，端扆屬元辰。',24,'全唐诗/poet.tang.2000.json','["皇猷被寰宇，端扆屬元辰。", "九重麗天邑，千門臨上春。"]'),
('da002bef-23f8-4c34-811f-65552c747baf','詠舞','楊師道','唐','唐诗','tang','','[]','二八如回雪，三春類早花。',24,'全唐诗/poet.tang.2000.json','["二八如回雪，三春類早花。", "分行向燭轉，一種逐風斜。"]'),
('bcdd8ee1-7e2d-455c-b288-9bc80d92d13b','奉和執契靜三邊應詔','許敬宗','唐','唐诗','tang','','[]','玄塞隔陰戎，朱光分昧谷。',240,'全唐诗/poet.tang.2000.json','["玄塞隔陰戎，朱光分昧谷。", "地遊窮北際，雲崖盡西陸。", "星次絕軒臺，風衢乖禹服。", "寰區無所外，天覆今咸育。", "竄苗猶有孽，戮負自貽辜。", "疎網妖鯢漏，盤藪怪禽逋。", "髯飛尚假息，乳視暫稽誅。", "乾靈振玉弩，神略運璇樞。", "日羽廓遊氣，天陣清華野。", "升晅光西夜，馳恩溢東瀉。", "揮袂靜崑炎，開關納流赭。", "錦軺凌右地，華纓羇大夏。", "清臺映羅葉，玄沚控瑤池。", "駝鹿輸珍貺，樹羽饗來儀。", "輟餚觀化宇，栖籞萃條支。", "熏風交閬闕，就日泛濛漪。", "充庭延飲至，絢簡敷春藻。", "迎姜已創圖，命力方論道。", "昔託遊河乘，再備商山皓。", "欣逢德化流，思效登封草。"]'),
('c30f647e-39dc-4353-bbb3-379ae66155c6','奉和行經破薛舉戰地應制','許敬宗','唐','唐诗','tang','','[]','混元分大象，長策挫修鯨。',120,'全唐诗/poet.tang.2000.json','["混元分大象，長策挫修鯨。", "於斯建宸極，由此創鴻名。", "一戎乾宇泰，千祀德流清。", "垂衣凝庶績，端拱鑄羣生。", "復整瑤池駕，還臨官渡營。", "周游尋曩跡，曠望動天情。", "帷宮面丹浦，帳殿矚宛城。", "虜場棲九穗，前歌被六英。", "戰地甘泉涌，陣處景雲生。", "普天霑凱澤，相攜欣頌平。"]'),
('aaf16564-4a01-4b21-9c54-9dc09ef65f13','奉和入潼關','許敬宗','唐','唐诗','tang','','[]','曦馭循黃道，星陳引翠旗。',84,'全唐诗/poet.tang.2000.json','["曦馭循黃道，星陳引翠旗。", "濟潼紆萬乘，臨河耀六師。", "前旌彌陸海，後騎發通伊。", "勢踰迴地軸，威盛轉天機。", "是節歲窮紀，關樹蕩涼颸。", "仙露含靈掌，瑞鼎照川湄。", "沖襟賞臨睨，高詠入京畿。"]'),
('0bc74210-d744-41d2-a894-ae58f203514e','奉和春日望海','許敬宗','唐','唐诗','tang','','[]','韓夷愆奉賮，憑險亂天常。',120,'全唐诗/poet.tang.2000.json','["韓夷愆奉賮，憑險亂天常。", "乃神弘廟畧，橫海剪吞航。", "電野清玄菟，騰笳振白狼。", "連雲飛巨艦，編石架浮梁。", "周游臨大壑，降望極遐荒。", "桃門通山抃，蓬渚降霓裳。", "驚濤含蜃闕，駭浪掩晨光。", "青丘絢春組，丹谷耀華桑。", "長驅七萃卒，成功百戰場。", "俄且旋戎路，飲至肅巖廊。"]'),
('a4622c56-5ce4-463d-a4a9-7417388eeb6c','奉和元日應制','許敬宗','唐','唐诗','tang','','[]','天正開初節，日觀上重輪。',98,'全唐诗/poet.tang.2000.json','["天正開初節，日觀上重輪。", "百靈滋景祚，萬玉慶惟新。", "待旦敷玄造，韜旒御紫宸。", "武帳臨光宅，文衛象鉤陳。", "廣庭揚九奏，大帛麗三辰。", "發生同化育，播物體陶鈞。", "霜空澄曉氣，霞景瑩芳春。", "德輝覃率[土]，相賀奉還淳。"]'),
('ba13fe6f-d354-4b9d-ac1e-2f24f6b7ee02','奉和初春登樓即目應詔','許敬宗','唐','唐诗','tang','','[]','旭日臨重壁，天眷極中京。',96,'全唐诗/poet.tang.2000.json','["旭日臨重壁，天眷極中京。", "春暉發芳甸，佳氣滿層城。", "去鳥隨看沒，來雲逐望生。", "歌裏非煙颺，琴上凱風清。", "文波浮鏤檻，摛景煥雕楹。", "璇璣體寬政，隆棟象端衡。", "創規雖有作，凝拱遂無營。", "沐恩空改鬢，將何謝夏成。"]'),
('2fa81a42-710b-4491-813a-257c6655e09a','奉和秋日即目應制','許敬宗','唐','唐诗','tang','','[]','玉露交珠網，金風度綺錢。',96,'全唐诗/poet.tang.2000.json','["玉露交珠網，金風度綺錢。", "昆明秋景淡，岐岫落霞然。", "辭燕歸寒海，來鴻出遠天。", "葉動羅帷颺，花映繡裳鮮。", "規空升闇魄，籠野散輕煙。", "鵲度林光起，鳧沒水文圓。", "無機絡秋緯，如管奏寒蟬。", "乃睠情何極，宸襟豫有旃。"]'),
('1efdaee9-7b98-4c2f-a859-46d616ddb3a6','奉和秋暮言志應制','許敬宗','唐','唐诗','tang','','[]','秋深桂初發，寒窗菊餘菲。',60,'全唐诗/poet.tang.2000.json','["秋深桂初發，寒窗菊餘菲。", "波擁羣鳧至，秋飄朔雁歸。", "月莢生還落，雲枝似復非。", "凝宸閱栖畝，觀文佇少微。", "聖敬韜前哲，先天諒不違。"]'),
('1484ed6f-9509-4b5f-b81e-cd7ac268154d','奉和喜雪應制','許敬宗','唐','唐诗','tang','','[]','嵰州表奇貺，閟竹應遐巡。',132,'全唐诗/poet.tang.2000.json','["嵰州表奇貺，閟竹應遐巡。", "何如御京洛，流霰下天津。", "忽若瓊林曙，俄同李徑春。", "姑峯映仙質，郢路雜歌塵。", "伏檻觀花瑞，稱觴慶冬積。", "飄河共瀉銀，委樹還重璧。", "連山分掩翠，綿霄遠韜碧。", "千里徧浮空，五軔咸淪跡。", "機前輝裂素，池上伴凌波。", "騰華承玉宇，凝照混金娥。", "是日松筠性，欣奉柏梁歌。"]'),
('195b47b5-84e3-427a-84a1-cb4eca36d7d6','奉和登陝州城樓應制','許敬宗','唐','唐诗','tang','','[]','挹河澂綠宇，御溝映朱宮。',60,'全唐诗/poet.tang.2000.json','["挹河澂綠宇，御溝映朱宮。", "辰旂翻麗景，星蓋曳雕虹。", "學嚬齊柳嫩，妍笑發春藂。", "錦鱗文碧浪，繡羽絢青空。", "眷念三階靜，遙想二南風。"]'),
('fc061549-ee44-4ddc-88ab-56fa4e3c4e71','遊清都觀尋沈道士得清字','許敬宗','唐','唐诗','tang','','[]','幽人蹈箕潁，方士訪蓬瀛。',96,'全唐诗/poet.tang.2000.json','["幽人蹈箕潁，方士訪蓬瀛。", "豈若逢真氣，齊契體無名。", "既詮衆妙理，聊暢遠遊情。", "縱心馳貝闕，怡神想玉京。", "或命餘杭酒，時聽洛濱笙。", "風衢通閬苑，星使下層城。", "蕙帳晨飆動，芝房夕露清。", "方叶棲遲趣，於此聽鐘聲。"]'),
('494db3da-3155-4b47-8a6a-82691a2f0ed4','奉和七夕宴懸圃應制二首 一','許敬宗','唐','唐诗','tang','','[]','牛閨臨淺漢，鸞駟涉秋河。',48,'全唐诗/poet.tang.2000.json','["牛閨臨淺漢，鸞駟涉秋河。", "兩懷縈別緒，一宿慶停梭。", "星模鉛裏靨，月寫黛中蛾。", "奈許今宵度，長嬰離恨多。"]'),
('2ef10f56-c14a-40e7-bf35-c91dc8c61f89','奉和七夕宴懸圃應制二首 二','許敬宗','唐','唐诗','tang','','[]','婺閨期今夕，娥輪泛淺潢。',48,'全唐诗/poet.tang.2000.json','["婺閨期今夕，娥輪泛淺潢。", "迎秋伴暮雨，待暝合神光。", "薦寢低雲鬢，呈態解霓裳。", "喜中愁漏促，別後怨天長。"]'),
('e67fc4d1-58e1-4d0d-8a37-0a5355dde663','奉和儀鸞殿早秋應制','許敬宗','唐','唐诗','tang','','[]','睿想追嘉豫，臨軒御早秋。',48,'全唐诗/poet.tang.2000.json','["睿想追嘉豫，臨軒御早秋。", "斜暉麗粉壁，清吹肅朱樓。", "高殿凝陰滿，雕窗豔曲流。", "小臣參廣宴，大造諒難酬。"]'),
('7b5f6c74-6b56-42e4-ba49-6805e2b99708','奉和詠雨應詔','許敬宗','唐','唐诗','tang','','[]','舞商初赴節，湘燕遠迎秋。',48,'全唐诗/poet.tang.2000.json','["舞商初赴節，湘燕遠迎秋。", "飄絲交殿網，亂滴起池漚。", "激溜分龍闕，斜飛灑鳳樓。", "崇朝方浹宇，宸盼俯凝旒。"]'),
('5824960d-99b8-4863-a4e5-e03a0fc60576','奉和過慈恩寺應制','許敬宗','唐','唐诗','tang','','[]','鳳闕隣金地，龍旂拂寶臺。',48,'全唐诗/poet.tang.2000.json','["鳳闕隣金地，龍旂拂寶臺。", "雲楣將葉並，風牖送花來。", "月宮清晚桂，虹梁絢早梅。", "梵境留宸矚，掞發麗天才。"]'),
('9424bdf9-8373-4e63-a8e8-370f2ae71af5','冬日宴于庶子宅各賦一字得歸','許敬宗','唐','唐诗','tang','','[]','倦游嗟落拓，短翮慕追飛。',48,'全唐诗/poet.tang.2000.json','["倦游嗟落拓，短翮慕追飛。", "周醪忽同醉，牙弦乃共揮。", "油雲澹寒色，落景靄霜霏。", "累日方投分，茲夕諒無歸。"]'),
('9718208f-558b-4d41-a552-f99f9f5fb5bf','送劉散員同賦得陳思王詩山樹鬱蒼蒼','許敬宗','唐','唐诗','tang','','[]','喬木託危岫，積翠繞連岡。',48,'全唐诗/poet.tang.2000.json','["喬木託危岫，積翠繞連岡。", "葉疎猶漏影，花少未流芳。", "風來聞肅肅，霧罷見蒼蒼。", "此中餞行邁，不異上河梁。"]'),
('5b3b46bf-198f-4cfe-ad1f-3084e44e62f1','侍宴莎冊宮應制得情字','許敬宗','唐','唐诗','tang','','[]','三星希曙景，萬騎翊天行。',60,'全唐诗/poet.tang.2000.json','["三星希曙景，萬騎翊天行。", "葆羽翻風隊，騰吹掩山楹。", "暖日晨光淺，飛煙旦彩輕。", "塞寒桃變色，冰斷箭流聲。", "漸奏長安道，神皐動睿情。"]'),
('2ed6a9c1-f021-47c3-a43e-d83bf0156aa9','奉和過舊宅應制','許敬宗','唐','唐诗','tang','','[]','飛雲臨紫極，出震表青光。',84,'全唐诗/poet.tang.2000.json','["飛雲臨紫極，出震表青光。", "自爾家寰海，今茲返帝鄉。", "情深感代國，樂甚讌譙方。", "白水浮佳氣，黃星聚太常。", "岐鳳鳴層閣，酆雀賀雕梁。", "桂山猶總翠，蘅薄尚流芳。", "攀鱗有遺皓，沐德抃稱觴。"]'),
('e5a427fb-66e9-416b-8d7b-b10c5244ef58','奉和宴中山應制','許敬宗','唐','唐诗','tang','','[]','飛雲旋碧海，解網宥青丘。',72,'全唐诗/poet.tang.2000.json','["飛雲旋碧海，解網宥青丘。", "養賢停八駿，觀風駐五牛。", "張樂臨堯野，揚麾歷舜州。", "中山獻仙酤，趙媛發清謳。", "塞門朱鴈入，郊藪紫麟遊。", "一舉氛霓靜，千齡德化流。"]'),
('c8e13a9b-d59d-4bd7-936c-f8acf5d85999','奉和聖製登三臺言志應制','許敬宗','唐','唐诗','tang','','[]','中天表雲榭，載極聳崑樓。',108,'全唐诗/poet.tang.2000.json','["中天表雲榭，載極聳崑樓。", "聖作規玄造，軒阿復聿修。", "高門符令節，形勝總神州。", "企翼摶禽萃，飛甍燕雀遊。", "綴星羅百拱，緣漢轉三休。", "旦雲生玉舃，初月上銀鉤。", "妙管含秦鳳，仙姿麗斗牛。", "形言防處逸，粹藻發嘉猷。", "荷生無以謝，盡瘁竟何酬。"]'),
('9bcf7cd7-5edd-40cb-9df7-8d2a346bb002','安德山池宴集','許敬宗','唐','唐诗','tang','','[]','戚里歡娛地，園林矚望新。',72,'全唐诗/poet.tang.2000.json','["戚里歡娛地，園林矚望新。", "山庭帶芳杜，歌吹叶陽春。", "臺榭疑巫峽，荷蕖似洛濱。", "風花縈少女，虹梁聚美人。", "宴遊窮至樂，談笑畢良辰。", "獨歎高陽晚，歸路不知津。"]'),
('524e17ad-8a7c-4d8d-b9d9-d587a4a9c49f','奉和聖製送來濟應制','許敬宗','唐','唐诗','tang','','[]','萬乘騰鑣警岐路，百壺供帳餞離宮。',64,'全唐诗/poet.tang.2000.json','["萬乘騰鑣警岐路，百壺供帳餞離宮。", "御溝分水聲難絕，廣宴當歌曲易終。", "興言共傷千里道，俯跡聊示五情同。", "良哉既深留帝念，沃化方有贊天聰。"]'),
('38342568-93bc-4db0-a7b6-a1608f1d2f1d','七夕賦詠成篇','許敬宗','唐','唐诗','tang','','[]','一年抱怨嗟長別，七夕含態始言歸。',64,'全唐诗/poet.tang.2000.json','["一年抱怨嗟長別，七夕含態始言歸。", "飄飄羅襪光天步，灼灼新妝鑒月輝。", "情催巧笑開星靨，不惜呈露解雲衣。", "所歎却隨更漏盡，掩泣還弄昨宵機。"]'),
('8aa4f8e1-26ad-42e7-a486-86b0ea35f14c','擬江令於長安歸揚州九日賦','許敬宗','唐','唐诗','tang','','[]','本逐征鴻去，還隨落葉來。',24,'全唐诗/poet.tang.2000.json','["本逐征鴻去，還隨落葉來。", "菊花應未滿，請待詩人開。"]'),
('6d8da919-c890-41e1-a680-aecc9ca70f43','擬江令於長安歸揚州九日賦','許敬宗','唐','唐诗','tang','','[]','遊人倦蓬轉，鄉思逐雁來。',24,'全唐诗/poet.tang.2000.json','["遊人倦蓬轉，鄉思逐雁來。", "偏想臨潭菊，芳蘂對誰開。"]'),
('099e75cf-5728-437b-b6a5-1b1d6114752d','和邊城秋氣早','李義府','唐','唐诗','tang','','[]','金微凝素節，玉律應清葭。',108,'全唐诗/poet.tang.2000.json','["金微凝素節，玉律應清葭。", "邊馬秋聲急，征鴻曉陣斜。", "關樹凋涼葉，塞草落寒花。", "霧暗長川景，雲昏大漠沙。", "谿深路難越，川平望超忽。", "極望斷煙飄，遙落驚蓬沒。", "霜結龍城吹，水照龜林月。", "日色夏猶冷，霜華春未歇。", "睿作高紫宸，分明映玄闕。"]'),
('9ccef6d7-57b4-457b-9db4-b29cff54ec4c','招諭有懷贈同行人','李義府','唐','唐诗','tang','','[]','遠遊冒艱阻，深入勞存諭。',120,'全唐诗/poet.tang.2000.json','["遠遊冒艱阻，深入勞存諭。", "春去辭國門，秋還在邊戍。", "軒車行未返，節序催難駐。", "陌上悲轉蓬，園中想芳樹。", "蜀山自紛糾，岷水恆奔注。", "臨汎多苦懷，登攀寡歡趣。", "永夕飛淫雨，崇朝蒸毒霧。", "不求綏嶺桃，寧美邛鄉蒟。", "白狼行欲靜，驄馬何常驅。", "願接軺斾塵，聯翩東北騖。"]'),
('652ec4c7-b4e7-462f-8ab7-80180baaa44b','宣正殿芝草','李義府','唐','唐诗','tang','','[]','明王敦孝感，寶殿秀靈芝。',48,'全唐诗/poet.tang.2000.json','["明王敦孝感，寶殿秀靈芝。", "色帶朝陽淨，光涵雨露滋。", "且標宣德重，更引國恩施。", "聖祚今無限，微臣樂未移。"]'),
('01b2ea71-d9bf-4200-abb4-6ff233e05913','詠鸚鵡','李義府','唐','唐诗','tang','','[]','牽弋辭重海，觸網去層巒。',48,'全唐诗/poet.tang.2000.json','["牽弋辭重海，觸網去層巒。", "戢翼雕籠際，延思彩霞端。", "慕侶朝聲切，離羣夜影寒。", "能言殊可貴，相助憶長安。"]'),
('7e0b0608-9117-4935-8e7e-8d63a2be4578','在巂州遙敍封禪','李義府','唐','唐诗','tang','','[]','天齊標巨鎮，日觀啓崇朝。',252,'全唐诗/poet.tang.2000.json','["天齊標巨鎮，日觀啓崇朝。", "岧嶤臨渤澥，隱嶙控河沂。", "眺迥分吳乘，凌高屬漢祠。", "建岳誠爲長，升功諒在茲。", "帝猷符廣運，玄範暢文思。", "飛聲總地絡，騰化撫乾維。", "瑞策開珍鳳，禎圖薦寶龜。", "創封超昔夏，修禪掩前姬。", "東后方肆覲，西都導六師。", "肅駕移星苑，揚罕馭風司。", "沸鼓喧平陸，凝蹕靜通逵。", "汶陽馳月羽，蒙陰警電麾。", "巖花飄曙輦，峰葉蕩春旗。", "石閭環藻衛，金壇映黼帷。", "仙階溢祕秬，靈檢燿祥芝。", "張樂分韶濩，觀禮縱華夷。", "佳氣浮丹谷，榮光泛綠坻。", "三始貽遐貺，萬歲受重釐。", "菲質陶恩獎，趨迹奉軒墀。", "觸網淪幽裔，乘徼限明時。", "周南昔已歎，邛西今復悲。"]'),
('e759e7de-95bf-4284-a859-d91992c5eba9','堂堂詞二首 一','李義府','唐','唐诗','tang','','[]','鏤月成歌扇，裁雲作舞衣。',24,'全唐诗/poet.tang.2000.json','["鏤月成歌扇，裁雲作舞衣。", "自憐迴雪影，好取洛川歸。"]'),
('566d66ff-32e9-4339-8914-6525f5bda71d','堂堂詞二首 二','李義府','唐','唐诗','tang','','[]','嬾整鴛鴦被，羞褰玳瑁牀。',24,'全唐诗/poet.tang.2000.json','["嬾整鴛鴦被，羞褰玳瑁牀。", "春風別有意，密處也尋香。"]'),
('c51aed8e-f8e8-4416-9307-2008ea86785b','詠烏','李義府','唐','唐诗','tang','','[]','日裏颺朝彩，琴中伴夜啼。',24,'全唐诗/poet.tang.2000.json','["日裏颺朝彩，琴中伴夜啼。", "上林如許樹，不借一枝栖。"]'),
('1804f164-cdc0-4e4d-bd04-3b35f4df7eba','從軍行二首 一','虞世南','唐','唐诗','tang','','["\u9ec4\u6cb3"]','塗山烽候驚，弭節度龍城。',108,'全唐诗/poet.tang.2000.json','["塗山烽候驚，弭節度龍城。", "冀馬樓蘭將，燕犀上谷兵。", "劒寒花不落，弓曉月逾明。", "凜凜嚴霜節，冰壯黃河絕。", "蔽日卷征蓬，浮天散飛雪。", "全兵值月滿，精騎乘膠折。", "結髮早驅馳，辛苦事旌麾。", "馬凍重關冷，輪摧九折危。", "獨有西山將，年年屬數奇。"]'),
('fab37680-5df4-4a52-9346-3fc5f0024abb','從軍行二首 二','虞世南','唐','唐诗','tang','','[]','烽火發金微，連營出武威。',96,'全唐诗/poet.tang.2000.json','["烽火發金微，連營出武威。", "孤城塞雲起，絕陣虜塵飛。", "俠客吸龍劒，惡少縵胡衣。", "朝摩骨都壘，夜解谷蠡圍。", "蕭關遠無極，蒲海廣難依。", "沙磴離旌斷，晴川候馬歸。", "交河梁已畢，燕山斾欲揮。", "方知萬里相，侯服見光輝。"]'),
('41b76620-4668-4173-a790-6fcc55193f4a','擬飲馬長城窟','虞世南','唐','唐诗','tang','','[]','馳馬渡河干，流深馬渡難。',96,'全唐诗/poet.tang.2000.json','["馳馬渡河干，流深馬渡難。", "前逢錦車使，都護在樓蘭。", "輕騎猶銜勒，疑兵尚解鞍。", "溫池下絕澗，棧道接危巒。", "拓地勛未賞，亡城律豈寬。", "有月關猶暗，經春隴尚寒。", "雲昏無復影，冰合不聞湍。", "懷君不可遇，聊持報一飱。"]'),
('9a0fe0ce-a9d7-47c7-b348-c5798c181d14','出塞','虞世南','唐','唐诗','tang','','[]','上將三略遠，元戎九命尊。',120,'全唐诗/poet.tang.2000.json','["上將三略遠，元戎九命尊。", "緬懷古人節，思酬明主恩。", "山西多勇氣，塞北有遊魂。", "揚桴上隴坂，勒騎下平原。", "誓將絕沙漠，悠然去玉門。", "輕齎不遑舍，驚策騖戎軒。", "凜凜邊風急，蕭蕭征馬煩。", "雪暗天山道，冰塞交河源。", "霧鋒黯無色，霜旗凍不翻。", "耿介倚長劒，日落風塵昏。"]'),
('171ea258-6b15-4d74-98e3-e0e66539c640','結客少年場行','虞世南','唐','唐诗','tang','','[]','韓魏多奇節，倜儻遺聲利。',132,'全唐诗/poet.tang.2000.json','["韓魏多奇節，倜儻遺聲利。", "共矜然諾心，各負縱橫志。", "結交一言重，相期千里至。", "綠沈明月弦，金絡浮雲轡。", "吹簫入吳市，擊筑遊燕肆。", "尋源博望侯，結客遠相求。", "少年懷一顧，長驅背隴頭。", "燄燄戈霜動，耿耿劒虹浮。", "天山冬夏雪，交河南北流。", "雲起龍沙暗，木落鴈門秋。", "輕生殉知己，非是爲身謀。"]'),
('9cf3501c-d491-4764-bf7e-71030a4cfe1a','怨歌行','虞世南','唐','唐诗','tang','','[]','紫殿秋風冷，雕甍落日沈。',84,'全唐诗/poet.tang.2000.json','["紫殿秋風冷，雕甍落日沈。", "裁紈悽斷曲，織素別離心。", "掖庭羞改畫，長門不惜金。", "寵移恩稍薄，情疎恨轉深。", "香銷翠羽帳，弦斷鳳皇琴。", "鏡前紅粉歇，階上綠苔侵。", "誰言掩歌扇，翻作白頭吟。"]'),
('979c5ba2-7c47-4bf4-aa3f-d803055f4a43','中婦織流黃','虞世南','唐','唐诗','tang','','[]','寒閨織素錦，含怨斂雙蛾。',48,'全唐诗/poet.tang.2000.json','["寒閨織素錦，含怨斂雙蛾。", "綜新交縷澁，經脆斷絲多。", "衣香逐舉袖，釧動應鳴梭。", "還恐裁縫罷，無信達交河。"]'),
('a0cd3f37-c4fb-4cde-827e-744e2bd8d3d5','門有車馬客','虞世南','唐','唐诗','tang','','[]','陳遵重交結，田蚡擅豪華。',136,'全唐诗/poet.tang.2000.json','["陳遵重交結，田蚡擅豪華。", "曲臺臨上路，高軒抵狹斜。", "赭汗千金馬，繡軸五香車。", "白鶴隨飛蓋，朱鷺入鳴笳。", "夏蓮開劒水，春桃發綬花。", "高談辯飛兔，摛藻握靈蛇。", "逢恩出毛羽，失路委泥沙。", "曖曖風煙晚，路長歸騎遠。", "日斜青瑣第，塵飛金谷苑。", "危弦促柱奏巴渝，遺簪墮珥解羅襦。", "如何守直道，翻使谷名愚。"]'),
('a088863e-2ee6-4be9-a8ea-1af19ae06605','飛來雙白鶴','虞世南','唐','唐诗','tang','','[]','飛來雙白鶴，奮翼遠凌煙。',120,'全唐诗/poet.tang.2000.json','["飛來雙白鶴，奮翼遠凌煙。", "俱棲集紫蓋，一舉背青田。", "颺影過伊洛，流聲入管弦。", "鳴羣倒景外，刷羽閬風前。", "暎海疑浮雪，拂澗瀉飛泉。", "燕雀寧知去，蜉蝣不識還。", "何言別儔侶，從此間山川。", "顧步已相失，裴回各自憐。", "危心猶警露，哀響詎聞天。", "無因振六翮，輕舉復隨仙。"]'),
('13d43a14-988d-48a8-86f5-c1b6fa3baced','奉和幽山雨後應令','虞世南','唐','唐诗','tang','','["\u9ec4\u5c71"]','肅城鄰上苑，黃山邇桂宮。',60,'全唐诗/poet.tang.2000.json','["肅城鄰上苑，黃山邇桂宮。", "雨歇連峰翠，煙開竟野通。", "排虛翔戲鳥，跨水落長虹。", "日下林全暗，雲收嶺半空。", "山泉鳴石澗，地籟響巖風。"]'),
('3baa6533-bc54-4764-b5fd-676af37251ad','賦得吳都','虞世南','唐','唐诗','tang','','[]','畫野通淮泗，星躔應斗牛。',72,'全唐诗/poet.tang.2000.json','["畫野通淮泗，星躔應斗牛。", "玉牒宏圖表，黃旗美氣浮。", "三分開霸業，萬里宅神州。", "高臺臨茂苑，飛閣跨澄流。", "江濤如素蓋，海氣似朱樓。", "吳趨自有樂，還似鏡中遊。"]'),
('2de16c9f-78be-47d6-80f1-1cb47b9a1a59','賦得慎罰','虞世南','唐','唐诗','tang','','[]','帝圖光往冊，上德表鴻名。',132,'全唐诗/poet.tang.2000.json','["帝圖光往冊，上德表鴻名。", "道冠二儀始，風高三代英。", "樂和知化洽，訟息表刑清。", "罰輕猶在念，忽喜尚留情。", "明慎全無枉，哀矜在好生。", "五疵過亦察，二辟理彌精。", "幪巾示廉恥，嘉石務詳平。", "每削繁苛性，常深惻隱誠。", "政寬思濟猛，疑罪必從輕。", "于張懲不濫，陳郭憲無傾。", "刑措諒斯在，歡然仰頌聲。"]'),
('42a6bb0b-f307-4d77-a524-25ef78162f5e','奉和詠日午','虞世南','唐','唐诗','tang','','[]','高天淨秋色，長漢轉曦車。',48,'全唐诗/poet.tang.2000.json','["高天淨秋色，長漢轉曦車。", "玉樹陰初正，桐圭影未斜。", "翠蓋飛圓彩，明鏡發輕花。", "再中良表瑞，共仰璧暉賒。"]'),
('c876207a-080d-401c-a2b5-2f3392777069','發營逢雨應詔','虞世南','唐','唐诗','tang','','[]','豫遊欣勝地，皇澤乃先天。',48,'全唐诗/poet.tang.2000.json','["豫遊欣勝地，皇澤乃先天。", "油雲陰御道，膏雨潤公田。", "隴麥霑逾翠，山花濕更然。", "稼穡良所重，方復悅豐年。"]'),
('03ae3687-4641-491d-b7bb-d6aa58f980d0','賦得臨池竹應制','虞世南','唐','唐诗','tang','','[]','蔥翠梢雲質，垂彩暎清池。',48,'全唐诗/poet.tang.2000.json','["蔥翠梢雲質，垂彩暎清池。", "波泛含風影，流搖防露枝。", "龍鱗漾嶰谷，鳳翅拂漣漪。", "欲識凌冬性，唯有歲寒知。"]'),
('d5416790-1c68-4ab1-ba7f-147999ebb6ab','侍宴應詔賦韻得前字','虞世南','唐','唐诗','tang','','[]','芬芳禁林晚，容與桂丹前。',48,'全唐诗/poet.tang.2000.json','["芬芳禁林晚，容與桂丹前。", "橫空一鳥度，照水百花然。", "綠野明斜日，青山澹晚煙。", "濫陪終宴賞，握管類窺天。"]'),
('d94daa5d-f90b-403e-a054-4b784599a4d1','侍宴歸鴈堂','虞世南','唐','唐诗','tang','','[]','歌堂面淥水，舞館接金塘。',48,'全唐诗/poet.tang.2000.json','["歌堂面淥水，舞館接金塘。", "竹開霜後翠，梅動雪前香。", "鳧歸初命侶，鴈起欲分行。", "刷羽同棲集，懷恩愧稻粱。"]'),
('3ee293f0-5404-4cbf-b845-e0c378c41e04','凌晨早朝','虞世南','唐','唐诗','tang','','[]','萬瓦宵光曙，重簷夕霧收。',48,'全唐诗/poet.tang.2000.json','["萬瓦宵光曙，重簷夕霧收。", "玉花停夜燭，金壺送曉籌。", "日暉青瑣殿，霞生結綺樓。", "重門應啓路，通籍引王侯。"]'),
('14f8c2fc-39be-4d6e-b5e5-a9f802d99333','奉和詠風應魏王教','虞世南','唐','唐诗','tang','','[]','逐舞飄輕袖，傳歌共繞梁。',24,'全唐诗/poet.tang.2000.json','["逐舞飄輕袖，傳歌共繞梁。", "動枝生亂影，吹花送遠香。"]'),
('4ae90371-da09-4531-b003-0a731f20fba0','初晴應教','虞世南','唐','唐诗','tang','','[]','初日明燕館，新溜滿梁池。',24,'全唐诗/poet.tang.2000.json','["初日明燕館，新溜滿梁池。", "歸雲半入嶺，殘滴尚懸枝。"]'),
('8570cd7c-4475-4ecf-b65a-5a5d60802288','春夜','虞世南','唐','唐诗','tang','','[]','春苑月裴回，竹堂侵夜開。',24,'全唐诗/poet.tang.2000.json','["春苑月裴回，竹堂侵夜開。", "驚鳥排林度，風花隔水來。"]'),
('05a713f6-13c8-403d-91ac-4c0341bbd9ee','詠舞','虞世南','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','繁弦奏淥水，長袖轉回鸞。',24,'全唐诗/poet.tang.2000.json','["繁弦奏淥水，長袖轉回鸞。", "一雙俱應節，還似鏡中看。"]'),
('a62e6592-862c-46e1-b7c0-788f917783ef','詠螢','虞世南','唐','唐诗','tang','','[]','的歷流光小，飄颻弱翅輕。',24,'全唐诗/poet.tang.2000.json','["的歷流光小，飄颻弱翅輕。", "恐畏無人識，獨自暗中明。"]'),
('f8998cfc-470f-45e6-a06c-5e30c18c0645','蟬','虞世南','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u5bd3\u7406", "\u548f\u7269"]','垂緌飲清露，流響出疎桐。',24,'全唐诗/poet.tang.2000.json','["垂緌飲清露，流響出疎桐。", "居高聲自遠，非是藉秋風。"]'),
('c391ef18-f80a-4816-859b-44b1bf804250','秋鴈','虞世南','唐','唐诗','tang','','[]','日暮霜風急，羽翮轉難任。',24,'全唐诗/poet.tang.2000.json','["日暮霜風急，羽翮轉難任。", "爲有傳書意，聯翩入上林。"]'),
('46b17890-4fbe-4d78-9fae-35ad3bad08e2','奉和月夜觀星應令','虞世南','唐','唐诗','tang','','[]','早秋炎景暮，初弦月彩新。',84,'全唐诗/poet.tang.2000.json','["早秋炎景暮，初弦月彩新。", "清風滌暑氣，零露淨囂塵。", "薄霧銷輕縠，鮮雲卷夕鱗。", "休光灼前曜，瑞彩接重輪。", "緣情摛聖藻，並作命徐陳。", "宿草誠渝濫，吹噓偶搢紳。", "天文豈易述，徒知仰北辰。"]'),
('6b1d200a-d81e-4a4e-8a5e-419b82acd786','和鑾輿頓戲下','虞世南','唐','唐诗','tang','','[]','重輪依紫極，前耀奉丹霄。',98,'全唐诗/poet.tang.2000.json','["重輪依紫極，前耀奉丹霄。", "天經戀宸扆，帝命扈仙鑣。", "乘[星]開鶴禁，帶月下虹橋。", "銀書含曉色，金輅轉晨飆。", "霧澈軒營近，塵暗苑城遙。", "蓮花分秀蕚，竹箭下驚潮。", "撫己慙龍幹，承恩集鳳條。", "瑤山盛風樂，抽簡薦徒謠。"]'),
('a84dc5de-b783-4022-aa4f-d971d60e9c73','奉和至壽春應令','虞世南','唐','唐诗','tang','','[]','瑤山盛風樂，南巡務逸遊。',120,'全唐诗/poet.tang.2000.json','["瑤山盛風樂，南巡務逸遊。", "如何事巡撫，民瘼諒斯求。", "文鶴揚輕蓋，蒼龍飾桂舟。", "泛沫縈沙嶼，寒澌擁急流。", "路指八仙館，途經百尺樓。", "眷言昔遊踐，廻駕且淹留。", "後車喧鳳吹，前旌暎綵旒。", "龍驂駐六馬，飛閣上三休。", "調諧金石奏，歡洽羽觴浮。", "天文徒可仰，何以廁琳球。"]'),
('4ad57948-bcb6-4fa1-86f4-0901414386c8','奉和幸江都應詔','虞世南','唐','唐诗','tang','','[]','南國行周化，稽山秘夏圖。',144,'全唐诗/poet.tang.2000.json','["南國行周化，稽山秘夏圖。", "百王豈殊軌，千載協前謨。", "肆覲遵時豫，順動悅來蘇。", "安流進玉軸，戒道翼金吾。", "龍旂煥辰象，鳳吹溢川塗。", "封唐昔敷錫，分陝被荆吳。", "沐道咸知讓，慕義久成都。", "冬律初飛管，陽鳥正銜蘆。", "嚴飆肅林薄，曖景澹江湖。", "鴻私浹幽遠，厚澤潤凋枯。", "虞琴起歌詠，漢筑動巴歈。", "多幸霑行葦，無庸類散樗。"]'),
('c53a74b3-e54a-47af-aba1-eb775a5e4c5a','奉和獻歲讌宮臣','虞世南','唐','唐诗','tang','','[]','履端初起節，長苑命高筵。',48,'全唐诗/poet.tang.2000.json','["履端初起節，長苑命高筵。", "肆夏喧金奏，重潤響朱弦。", "春光催柳色，日彩泛槐煙。", "微臣同濫吹，謬得仰鈞天。"]'),
('4425fe97-a66c-4f48-bd16-6f506aa20197','奉和出潁至淮應令','虞世南','唐','唐诗','tang','','[]','良晨喜利涉，解纜入淮潯。',48,'全唐诗/poet.tang.2000.json','["良晨喜利涉，解纜入淮潯。", "寒流泛鷁首，霜吹響哀吟。", "潛鱗波裏躍，水鳥浪前沈。", "邗溝非復遠，悵望悅宸襟。"]'),
('bf919565-500a-420f-9350-da5f76c488c5','應詔嘲司花女','虞世南','唐','唐诗','tang','','[]','學畫鴉黃半未成，垂肩軃嚲袖太憨生。',33,'全唐诗/poet.tang.2000.json','["學畫鴉黃半未成，垂肩軃嚲袖太憨生。", "緣憨却得君王惜，長把花枝傍輦行。"]'),
('2c0166ce-92a9-4c70-adf9-6f9855355f18','古意六首 一','王績','唐','唐诗','tang','','[]','幽人在何所？紫巖有仙躅。',84,'全唐诗/poet.tang.2000.json','["幽人在何所？紫巖有仙躅。", "月下橫寶琴，此外將安欲。", "材抽嶧山榦，徽點崑丘玉。", "漆抱蛟龍脣，絲纏鳳凰足。", "前彈廣陵罷，後以明光續。", "百金買一聲，千金傳一曲。", "世無鍾子期，誰知心所屬。"]'),
('7db0317c-07dd-4ce1-a73b-b767e5a19f38','古意六首 二','王績','唐','唐诗','tang','','[]','竹生大夏谿，蒼蒼富奇質。',96,'全唐诗/poet.tang.2000.json','["竹生大夏谿，蒼蒼富奇質。", "綠葉吟風勁，翠莖犯霄密。", "霜霰封其柯，鵷鸞食其實。", "寧知軒轅後，更有伶倫出。", "刀斧俄見尋，根株坐相失。", "裁爲十二管，吹作雄雌律。", "有用雖自傷，無心復招疾。", "不如山上草，離離保終吉。"]'),
('6e06d2cb-be89-4c66-8e62-1eddd4ef0369','古意六首 三','王績','唐','唐诗','tang','','[]','寶龜尺二寸，由來宅深水。',108,'全唐诗/poet.tang.2000.json','["寶龜尺二寸，由來宅深水。", "浮遊五湖內，宛轉三江裏。", "何不深復深，輕然至溱洧。", "溱洧源流狹，春秋不濡軌。", "漁人遞往還，網罟相縈藟。", "一朝失運會，刳腸血流死。", "豐骨輸廟堂，鮮腴籍籩簋。", "棄置誰怨尤，自我招此否。", "餘靈寄明卜，復來欽所履。"]'),
('8604b82d-92f4-4ed1-89a4-77e082c776c8','古意六首 四','王績','唐','唐诗','tang','','[]','松生北巖下，由來人徑絕。',132,'全唐诗/poet.tang.2000.json','["松生北巖下，由來人徑絕。", "布葉捎雲煙，插根擁巖穴。", "自言生得地，獨負凌雲潔。", "何時畏斤斧，幾度經霜雪。", "風驚西北枝，雹隕東南節。", "不知歲月久，稍覺枝榦折。", "藤蘿上下碎，枝榦縱橫裂。", "行當糜爛盡，坐共灰塵滅。", "寧關匠石顧，豈爲王孫折。", "盛衰自有時，聖賢未嘗屑。", "寄言悠悠者，無爲嗟大耋。"]'),
('0307c2ec-224c-4967-aac7-4b84cf4de02a','古意六首 五','王績','唐','唐诗','tang','','[]','桂樹何蒼蒼，秋來花更芳。',96,'全唐诗/poet.tang.2000.json','["桂樹何蒼蒼，秋來花更芳。", "自言歲寒性，不知露與霜。", "幽人重其德，徙植臨前堂。", "連拳八九樹，偃蹇二三行。", "枝枝自相糾，葉葉還相當。", "去來雙鴻鵠，栖息兩鴛鴦。", "榮蔭誠不厚，斤斧亦勿傷。", "赤心許君時，此意那可忘。"]'),
('61ad3ac9-11f4-4d59-a516-a9a18d31fef0','古意六首 六','王績','唐','唐诗','tang','','[]','彩鳳欲將歸，提羅出郊訪。',98,'全唐诗/poet.tang.2000.json','["彩鳳欲將歸，提羅出郊訪。", "羅張大澤已，鳳入重雲颺。", "朝栖崑閬木，夕飲蓬壺漲。", "問鳳那遠飛，賢君坐相望。", "鳳言荷深德，微禽安足尚。", "但使雛卵全，無令[矰]繳放。", "皇臣力牧舉，帝樂簫韶暢。", "自有來巢時，明年阿閣上。"]'),
('2d8669b3-2295-4fe8-9308-de8f863c488c','石竹詠','王績','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u7af9\u5b50", "\u548f\u7269"]','萋萋結綠枝，曄曄垂朱英。',60,'全唐诗/poet.tang.2000.json','["萋萋結綠枝，曄曄垂朱英。", "常恐零露降，不得全其生。", "歎息聊自思，此生豈我情。", "昔我未生時，誰者令我萌。", "棄置勿重陳，委化何足驚。"]'),
('90016a03-6bc5-4d06-b055-7ad10977c73c','田家三首 一','王績','唐','唐诗','tang','','[]','阮籍生涯懶，嵇康意氣疎。',72,'全唐诗/poet.tang.2000.json','["阮籍生涯懶，嵇康意氣疎。", "相逢一醉飽，獨坐數行書。", "小池聊養鶴，閑田且牧豬。", "草生元亮徑，花暗子雲居。", "倚牀看婦織，登壠課兒鋤。", "迴頭尋仙事，併是一空虛。"]'),
('ac3d0f67-39fd-4b49-9bf7-626d08eb5e4d','田家三首 二','王績','唐','唐诗','tang','','[]','家住箕山下，門枕潁川濱。',48,'全唐诗/poet.tang.2000.json','["家住箕山下，門枕潁川濱。", "不知今有漢，唯言昔避秦。", "琴伴前庭月，酒勸後園春。", "自得中林士，何忝上皇人。"]'),
('3723534b-dbdd-415b-81d6-3143a13ee5e5','田家三首 三','王績','唐','唐诗','tang','','[]','平生唯酒樂，作性不能無。',60,'全唐诗/poet.tang.2000.json','["平生唯酒樂，作性不能無。", "朝朝訪鄉里，夜夜遣人酤。", "家貧留客久，不暇道精麤。", "抽簾持益炬，拔簀更燃爐。", "恆聞飲不足，何見有殘壺。"]'),
('9532dec6-d0e9-415d-88ee-58ff440c31ac','贈李徵君大壽','王績','唐','唐诗','tang','','[]','孔淳辭散騎，陸昶謝中郎。',192,'全唐诗/poet.tang.2000.json','["孔淳辭散騎，陸昶謝中郎。", "幅巾朝帝罷，杖策去官忙。", "附車還趙郡，乘船向武昌。", "九徵書未已，十辟譽彌彰。", "副君迎綺季，天子送嚴光。", "灞陵幽徑近，磻谿隱路長。", "編蓬還作室，績草更爲裳。", "會稽置樵處，蘭陵賣藥行。", "看書惟道德，開教止農桑。", "別有幽懷侶，由來高讓王。", "前年辭厚幣，今歲返寒鄉。", "有書橫石架，無氈坐土牀。", "蘭英猶足釀，竹實本無糧。", "澗松寒轉直，山菊秋自香。", "管寧存祭禮，王霸重朝章。", "去去相隨去，披裘驕盛唐。"]'),
('e9dfe173-a9c6-4f9f-82b1-d7bcceb77ce2','山中敍志','王績','唐','唐诗','tang','','[]','物外知何事，山中無所有。',60,'全唐诗/poet.tang.2000.json','["物外知何事，山中無所有。", "風鳴靜夜琴，月照芳春酒。", "直置百年內，誰論千載後。", "張奉娉賢妻，老萊籍嘉偶。", "孟光儻未嫁，梁鴻正須婦。"]'),
('f0aceead-b9c4-4755-95a1-441f4e0927be','贈梁公','王績','唐','唐诗','tang','','[]','我欲圖世樂，斯樂難可常。',120,'全唐诗/poet.tang.2000.json','["我欲圖世樂，斯樂難可常。", "位大招譏嫌，祿極生禍殃。", "聖莫若周公，忠豈踰霍光。", "成王已興誚，宣帝如負芒。", "范蠡何智哉，單舟戒輕裝。", "疏廣豈不懷，策杖還故鄉。", "朱門雖足悅，赤族亦可傷。", "履霜成堅冰，知足勝不祥。", "我今窮家子，自言此見長。", "功成皆能退，在昔誰滅亡。"]'),
('3ea4f2bf-c628-44f9-a29b-523071390e61','薛記室收過莊見尋率題古意以贈','王績','唐','唐诗','tang','','[]','伊昔逢喪亂，曆數閏當餘。',288,'全唐诗/poet.tang.2000.json','["伊昔逢喪亂，曆數閏當餘。", "豺狼塞衢路，桑梓成丘墟。", "余及爾皆亡，東西各異居。", "爾爲背風鳥，我爲涸轍魚。", "逮承雲雷後，欣逢天地初。", "東川聊下釣，南畝試揮鋤。", "資稅幸不及，伏臘常有儲。", "散誕時須酒，蕭條嬾向書。", "朽木不可雕，短翮將焉攄。", "故人有深契，過我蓬高廬。", "曳裾出門迎，握手登前除。", "相看非舊顏，忽若形骸疎。", "追道宿昔事，切切心相於。", "憶我少年時，攜手遊東渠。", "梅李夾兩岸，花枝何扶疏。", "同志亦不多，西莊有姚徐。", "嘗愛陶淵明，酌醴焚枯魚。", "嘗學公孫弘，策杖牧羣豬。", "追念甫如昨，奄忽成空虛。", "人生詎能幾，歲歲常不舒。", "賴有北山僧，教我以真如。", "使我視聽遣，自覺塵累祛。", "何事須筌蹄，今已得兔魚。", "舊遊儻多暇，同此釋紛拏。"]'),
('b6514d6a-a16f-4288-b7f8-fbea9b88bd08','晚年敍志示翟處士','王績','唐','唐诗','tang','','[]','弱齡慕奇調，無事不兼修。',192,'全唐诗/poet.tang.2000.json','["弱齡慕奇調，無事不兼修。", "望氣登重閣，占星上小樓。", "明經思待詔，學劍覓封侯。", "棄繻頻北上，懷刺幾西遊。", "中年逢喪亂，非復昔追求。", "失路青門隱，藏名白社遊。", "風雲私所愛，屠博暗爲儔。", "解紛曾霸越，釋難頗存周。", "晚歲聊長想，生涯太若浮。", "歸來南畝上，更坐北溪頭。", "古岸多磐石，春泉足細流。", "東隅誠已謝，西景懼難收。", "無謂退耕近，伏念已經秋。", "庚桑逢處跪，陶潛見人羞。", "三晨寧舉火，五月鎮披裘。", "自有居常樂，誰知身世憂。"]'),
('a5ba72fa-ea85-4baa-b84c-fbd823fb2a97','春日','王績','唐','唐诗','tang','','[]','前旦出園遊，林華都未有。',60,'全唐诗/poet.tang.2000.json','["前旦出園遊，林華都未有。", "今朝下堂來，池冰開已久。", "雪被南軒梅，風催北庭柳。", "遙呼竈前妾，却報機中婦。", "年光恰恰來，滿甕營春酒。"]'),
('03067213-a3e3-4adc-b5a0-4afdbdb41c54','採藥','王績','唐','唐诗','tang','','[]','野情貪藥餌，郊居倦蓬蓽。',120,'全唐诗/poet.tang.2000.json','["野情貪藥餌，郊居倦蓬蓽。", "青龍護道符，白犬遊仙術。", "腰鎌戊己月，負鍤庚辛日。", "時時斷嶂遮，往往孤峰出。", "行披葛仙經，坐檢神農帙。", "龜蛇採二苓，赤白尋雙朮。", "地凍根難盡，藂枯苗易失。", "從容肉作名，薯蕷高成質。", "家豐松葉酒，器貯參花蜜。", "且復歸去來，刀圭輔衰疾。"]'),
('0fe0a96a-722c-46fc-89ea-e0c64415d0c6','在京思故園見鄉人問','王績','唐','唐诗','tang','','[]','旅泊多年歲，老去不知迴。',144,'全唐诗/poet.tang.2000.json','["旅泊多年歲，老去不知迴。", "忽逢門前客，道發故鄉來。", "斂眉俱握手，破涕共銜杯。", "殷勤訪朋舊，屈曲問童孩。", "衰宗多弟姪，若箇賞池臺。", "舊園今在否，新樹也應栽。", "柳行疎密布，茅齋寬窄裁。", "經移何處竹？別種幾株梅。", "渠當無絕水，石計總生苔。", "院果誰先熟，林花那後開。", "羇心祗欲問，爲報不須猜。", "行當驅下澤，去剪故園萊。"]'),
('63add5cf-ea56-40b1-8a8e-3ddd6c1ab87c','春桂問荅二首 一','王績','唐','唐诗','tang','','[]','問春桂：桃李正芬華，年光隨處滿，何事獨無花。',22,'全唐诗/poet.tang.2000.json','["問春桂：桃李正芬華，年光隨處滿，何事獨無花。"]'),
('0a02c16d-2702-42b3-b9eb-e44f1c658b87','春桂問荅二首 二','王績','唐','唐诗','tang','','[]','春桂荅：春華詎能久，風霜搖落時，獨秀君知不。',22,'全唐诗/poet.tang.2000.json','["春桂荅：春華詎能久，風霜搖落時，獨秀君知不。"]'),
('90982e3f-e8f1-4a18-8e06-bb5d3446c180','北山','王績','唐','唐诗','tang','','[]','舊知山裏絕氛埃，登高日暮心悠哉。',60,'全唐诗/poet.tang.2000.json','["舊知山裏絕氛埃，登高日暮心悠哉。", "子平一去何時返？仲叔長遊遂不來。", "幽蘭獨夜清琴曲，桂樹凌雲濁酒杯。", "槁項同枯木，丹心等死灰。"]'),
('597f5187-ba3e-4094-ae34-52884eb01c84','野望','王績','唐','唐诗','tang','','["\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929", "\u521d\u4e2d\u53e4\u8bd7"]','東皐薄暮望，徙倚欲何依。',48,'全唐诗/poet.tang.2000.json','["東皐薄暮望，徙倚欲何依。", "樹樹皆秋色，山山唯落暉。", "牧人驅犢返，獵馬帶禽歸。", "相顧無相識，長歌懷采薇。"]'),
('08e63631-dccf-4c60-806a-9b3bd39a0822','贈程處士','王績','唐','唐诗','tang','','[]','百年長擾擾，萬事悉悠悠。',48,'全唐诗/poet.tang.2000.json','["百年長擾擾，萬事悉悠悠。", "日光隨意落，河水任情流。", "禮樂囚姬旦，詩書縛孔丘。", "不如高枕枕，時取醉消愁。"]'),
('57ef45ef-afdf-4ede-ab7b-865b64a8eb36','九月九日贈崔使君善爲','王績','唐','唐诗','tang','','[]','野人迷節候，端坐隔塵埃。',48,'全唐诗/poet.tang.2000.json','["野人迷節候，端坐隔塵埃。", "忽見黃花吐，方知素節回。", "映巖千段發，臨浦萬株開。", "香氣徒盈把，無人送酒來。"]'),
('4df36d17-eddd-468a-a3c4-9cd3b3b96ecb','獨坐','王績','唐','唐诗','tang','','[]','問君樽酒外，獨坐更何須。',48,'全唐诗/poet.tang.2000.json','["問君樽酒外，獨坐更何須。", "有客談名理，無人索地租。", "三男婚令族，五女嫁賢夫。", "百年隨分了，未羨陟方壺。"]'),
('87073c74-778d-44e7-9a0a-40d9c0cefbad','遊仙四首 一','王績','唐','唐诗','tang','','[]','暫出東陂路，過訪北巖前。',72,'全唐诗/poet.tang.2000.json','["暫出東陂路，過訪北巖前。", "蔡經新學道，王烈舊成仙。", "駕鶴來無日，乘龍去幾年。", "三山銀作地，八洞玉爲天。", "金精飛欲盡，石髓溜應堅。", "自悲生世促，無暇待桑田。"]'),
('6fadef9d-25b5-4a8c-9eb6-ddd7da1fc012','遊仙四首 二','王績','唐','唐诗','tang','','[]','上月芝蘭徑，中巖紫翠房。',72,'全唐诗/poet.tang.2000.json','["上月芝蘭徑，中巖紫翠房。", "金壺新練乳，玉釜始煎香。", "六局黃公術，三門赤帝方。", "吹沙聊作鳥，動石試爲羊。", "緱氏還程促，瀛洲會日長。", "誰知北巖下，延首詠霓裳。"]'),
('1e2a91c9-fa75-4ae3-a354-96221ee3d1ce','遊仙四首 三','王績','唐','唐诗','tang','','[]','結衣尋野路，負杖入山門。',72,'全唐诗/poet.tang.2000.json','["結衣尋野路，負杖入山門。", "道士言無宅，仙人更有村。", "斜溪橫桂渚，小徑入桃源。", "玉牀塵稍冷，金爐火尚溫。", "心疑遊北極，望似陟西崑。", "逆愁歸舊里，蕭條訪子孫。"]'),
('21cfae19-abd6-4249-817a-50a9cecb0bc2','遊仙四首 四','王績','唐','唐诗','tang','','[]','真經知那是，仙骨定何爲。',72,'全唐诗/poet.tang.2000.json','["真經知那是，仙骨定何爲。", "許邁心長切，嵇康命似奇。", "桑疎金闕迥，苔重石梁危。", "照水然犀角，遊山費虎皮。", "鴨桃聞已種，龍竹未經騎。", "爲向天仙道，棲遑君詎知。"]'),
('85e13219-6895-4025-a559-c90285851565','策杖尋隱士','王績','唐','唐诗','tang','','[]','策杖尋隱士，行行路漸賒。',72,'全唐诗/poet.tang.2000.json','["策杖尋隱士，行行路漸賒。", "石梁橫澗斷，土室映山斜。", "孝然縱有舍，威輦遂無家。", "置酒燒枯葉，披書坐落花。", "新垂滋水釣，舊結茂陵罝。", "歲歲長如此，方知輕世華。"]'),
('479cacba-b602-45dc-bcd2-410f781e13e7','贈學仙者','王績','唐','唐诗','tang','','[]','採藥層城遠，尋師海路賒。',72,'全唐诗/poet.tang.2000.json','["採藥層城遠，尋師海路賒。", "玉壺橫日月，金闕斷煙霞。", "仙人何處在？道士未還家。", "誰知彭澤意，更覔步兵那。", "春釀煎松葉，秋杯浸菊花。", "相逢寧可醉，定不學丹砂。"]'),
('b84e99c8-0865-4a1e-829b-e391a3201075','黃頰山','王績','唐','唐诗','tang','','[]','別有青溪道，斜亙碧巖隈。',72,'全唐诗/poet.tang.2000.json','["別有青溪道，斜亙碧巖隈。", "崩榛橫古蔓，荒石擁寒苔。", "野心長寂寞，山徑本幽迴。", "步步攀藤上，朝朝負藥來。", "幾看松葉秀，頻值菊花開。", "無人堪作伴，歲晚獨悠哉。"]'),
('95ceeb80-774c-471f-b021-e9c444659bee','建德破後入長安詠秋蓬示辛學士','王績','唐','唐诗','tang','','[]','遇坎聊知止，逢風或未歸。',24,'全唐诗/poet.tang.2000.json','["遇坎聊知止，逢風或未歸。", "孤根何處斷？輕葉強能飛。"]'),
('06f7fd5b-bc4e-4676-9dee-6c30993fdc35','過酒家五首 一','王績','唐','唐诗','tang','','[]','洛陽無大宅，長安乏主人。',24,'全唐诗/poet.tang.2000.json','["洛陽無大宅，長安乏主人。", "黃金銷未盡，祗爲酒家貧。"]'),
('433ff654-db7e-4cc0-97e8-5ea94d6ff6a0','過酒家五首 二','王績','唐','唐诗','tang','','[]','此日長昏飲，非關養性靈。',24,'全唐诗/poet.tang.2000.json','["此日長昏飲，非關養性靈。", "眼看人盡醉，何忍獨爲醒。"]'),
('af74ff82-6382-4346-a173-c2b995fe6a56','過酒家五首 三','王績','唐','唐诗','tang','','[]','竹葉連糟翠，蒲萄帶麴紅。',24,'全唐诗/poet.tang.2000.json','["竹葉連糟翠，蒲萄帶麴紅。", "相逢不令盡，別後爲誰空。"]'),
('6714140f-8da2-40e7-aeeb-94611a956b9a','過酒家五首 四','王績','唐','唐诗','tang','','[]','對酒但知飲，逢人莫強牽。',24,'全唐诗/poet.tang.2000.json','["對酒但知飲，逢人莫強牽。", "倚鑪便得睡，橫甕足堪眠。"]'),
('8491c2cf-79a3-4709-b6d9-5e186c7bdc45','過酒家五首 五','王績','唐','唐诗','tang','','[]','有客須教飲，無錢可別沽。',24,'全唐诗/poet.tang.2000.json','["有客須教飲，無錢可別沽。", "來時長道貰，慙媿酒家胡。"]'),
('0dc5b969-4894-402f-b42a-b54e9af2f8a3','夜還東溪','王績','唐','唐诗','tang','','[]','石苔應可踐，叢枝幸易攀。',24,'全唐诗/poet.tang.2000.json','["石苔應可踐，叢枝幸易攀。", "青溪歸路直，乘月夜歌還。"]'),
('29921223-ef30-4e53-8a3f-cd195743e9bf','山中別李處士','王績','唐','唐诗','tang','','[]','爲向東溪道，人來路漸賒。',24,'全唐诗/poet.tang.2000.json','["爲向東溪道，人來路漸賒。", "山中春酒熟，何處得停家。"]'),
('96b4547f-7fee-486c-a402-06409ec5e9eb','初春','王績','唐','唐诗','tang','','[]','春來日漸長，醉客喜年光。',24,'全唐诗/poet.tang.2000.json','["春來日漸長，醉客喜年光。", "稍覺池亭好，偏宜酒甕香。"]'),
('fa0e6280-db9d-4188-8dc5-b3d9a9497e84','醉後','王績','唐','唐诗','tang','','[]','阮籍醒時少，陶潛醉日多。',24,'全唐诗/poet.tang.2000.json','["阮籍醒時少，陶潛醉日多。", "百年何足度，乘興且長歌。"]'),
('a6dce4e7-eb20-4dd0-8ecd-54a7eff6d5dc','題酒店壁','王績','唐','唐诗','tang','','[]','昨夜缾始盡，今朝甕即開。',24,'全唐诗/poet.tang.2000.json','["昨夜缾始盡，今朝甕即開。", "夢中占夢罷，還向酒家來。"]'),
('f8aefaea-ce55-4d2c-98f1-0187e355231c','戲題卜鋪壁','王績','唐','唐诗','tang','','[]','旦逐劉伶去，宵隨畢卓眠。',24,'全唐诗/poet.tang.2000.json','["旦逐劉伶去，宵隨畢卓眠。", "不應長賣卜，須得杖頭錢。"]'),
('663f19ee-dcbf-4a1b-8f52-3763b4bdd13a','嘗春酒','王績','唐','唐诗','tang','','[]','野觴浮鄭酌，山酒漉陶巾。',24,'全唐诗/poet.tang.2000.json','["野觴浮鄭酌，山酒漉陶巾。", "但令千日醉，何惜兩三春。"]'),
('523a39e5-0934-4336-aed8-3b2c7566522c','獨酌','王績','唐','唐诗','tang','','[]','浮生知幾日，無狀逐空名。',24,'全唐诗/poet.tang.2000.json','["浮生知幾日，無狀逐空名。", "不知多釀酒，時向竹林傾。"]'),
('ace4d5a4-1992-4f3c-a3d8-6955925fa0f6','秋夜喜遇王處士','王績','唐','唐诗','tang','','["\u751f\u6d3b", "\u7530\u56ed"]','北場芸藿罷，東皐刈黍歸。',24,'全唐诗/poet.tang.2000.json','["北場芸藿罷，東皐刈黍歸。", "相逢秋月滿，更值夜螢飛。"]'),
('c2efca7a-92fe-4205-93b5-65713fd9c0e8','山夜調琴','王績','唐','唐诗','tang','','[]','促軫乘明月，抽弦對白雲。',24,'全唐诗/poet.tang.2000.json','["促軫乘明月，抽弦對白雲。", "從來山水韻，不使俗人聞。"]'),
('957e7785-b62e-4c6d-b0c2-a455e5ff6ab2','看釀酒','王績','唐','唐诗','tang','','[]','六月調神麴，正朝汲美泉。',24,'全唐诗/poet.tang.2000.json','["六月調神麴，正朝汲美泉。", "從來作春酒，未省不經年。"]'),
('33b6e6d5-6f25-421f-b47b-b4d880bf2ad1','食後','王績','唐','唐诗','tang','','[]','田家無所有，晚食遂爲常。',72,'全唐诗/poet.tang.2000.json','["田家無所有，晚食遂爲常。", "菜剪三秋綠，飧炊百日黃。", "胡麻山麨樣，楚豆野麋方。", "始暴松皮脯，新添杜若漿。", "葛花消酒毒，萸蔕發羹香。", "鼓腹聊乘興，寧知逢世昌。"]'),
('7462c264-4cfe-4bfc-93e5-39a10307d0dd','過漢故城','王績','唐','唐诗','tang','','[]','大漢昔未定，強秦猶擅場。',288,'全唐诗/poet.tang.2000.json','["大漢昔未定，強秦猶擅場。", "中原逐鹿罷，高祖鬱龍驤。", "經始謀帝坐，茲焉壯未央。", "規模窮棟宇，表裏浚城隍。", "羣后崇長樂，中朝增建章。", "鉤陳被蘭錡，樂府奏芝房。", "翡翠明珠帳，鴛鴦白玉堂。", "清晨寶鼎食，閑夜鬱金香。", "天馬來東道，佳人傾北方。", "何其赫隆盛，自謂保靈長。", "歷數有時盡，哀平嗟不昌。", "冰堅成巨猾，火德遂頹綱。", "奧位匪虛校，貪天竟速亡。", "魂神吁社稷，豺虎鬬巖廊。", "金狄移灞岸，銅盤向洛陽。", "君王無處所，年代幾荒涼。", "宮闕誰家域，蓁蕪罥我裳。", "井田唯有草，海水變爲桑。", "在昔高門內，於今岐路傍。", "餘基不可識，古墓列成行。", "狐兔驚魍魎，鴟鴞嚇獝狂。", "空城寒日晚，平野暮雲黃。", "烈烈焚青棘，蕭蕭吹白楊。", "千秋幷萬歲，空使詠歌傷。"]'),
('bfad4c25-27e0-45bb-8045-e46d92418046','益州城西張超亭觀妓','王績','唐','唐诗','tang','','[]','落日明歌席，行雲逐舞人。',48,'全唐诗/poet.tang.2000.json','["落日明歌席，行雲逐舞人。", "江南飛暮雨，梁上下輕塵。", "冶服看疑畫，粧臺望似春。", "高車勿遽返，長袖欲相親。"]'),
('0c842d6e-dc6e-4e5f-b2a4-a913366efed1','詠妓','王績','唐','唐诗','tang','','[]','妖姬飾靚妝，窈窕出蘭房。',48,'全唐诗/poet.tang.2000.json','["妖姬飾靚妝，窈窕出蘭房。", "日照當軒影，風吹滿路香。", "早時歌扇薄，今日舞衫長。", "不應令曲誤，持此試周郎。"]'),
('3bb3e42f-c375-417b-b40f-c818807c10ef','辛司法宅觀妓','王績','唐','唐诗','tang','','[]','南國佳人至，北堂羅薦開。',48,'全唐诗/poet.tang.2000.json','["南國佳人至，北堂羅薦開。", "長裙隨鳳管，促柱送鸞杯。", "雲光身後蕩，雪態掌中回。", "到愁金谷晚，不怪玉山頹。"]'),
('b6635317-8c13-4fc9-a144-35a7c126c42c','詠巫山','王績','唐','唐诗','tang','','[]','電影江前落，雷聲峽外長。',24,'全唐诗/poet.tang.2000.json','["電影江前落，雷聲峽外長。", "霽雲無處所，臺館曉蒼蒼。"]'),
('1e3f5f37-c25d-4c30-a5bb-d77b405b3aad','詠懷','王績','唐','唐诗','tang','','[]','故鄉行雲是，虛室坐間同。',24,'全唐诗/poet.tang.2000.json','["故鄉行雲是，虛室坐間同。", "日落西山暮，方知天下空。"]'),
('7b02e97b-54ea-43f6-b3d8-abb7b6106c13','句','王績','唐','唐诗','tang','','[]','琴曲唯留古，書多半是經。',96,'全唐诗/poet.tang.2000.json','["琴曲唯留古，書多半是經。", "橫裁桑節杖，直剪竹皮巾。", "鶴警琴亭夜，鶯啼酒甕春。", "顏回唯樂道，原憲豈傷貧。", "寄身千載下，聊遊萬物初。", "欲令無作有，翻覺實成虛。", "雙關防易斷，隻眼畏難全。", "魚鱗張九拒，鶴翅擁三邊。"]'),
('494648d9-b5b0-44c7-bba2-0c0e4e6c9c36','詠舞','蕭德言','唐','唐诗','tang','','[]','低身鏘玉珮，舉袖拂羅衣。',24,'全唐诗/poet.tang.2000.json','["低身鏘玉珮，舉袖拂羅衣。", "對簷疑燕起，映雪似花飛。"]'),
('a87be94b-e983-40ff-8350-48a16dbfc585','過嚴君平古井','鄭世翼','唐','唐诗','tang','','[]','嚴平本高尚，遠蹈古人風。',60,'全唐诗/poet.tang.2000.json','["嚴平本高尚，遠蹈古人風。", "賣卜成都市，流名大漢中。", "舊井改人世，寒泉久不通。", "多年既罷汲，無禽乃遂空。", "如何屬秋氣，唯見落雙桐。"]'),
('2e5d1e50-6035-4034-807c-f51359bd70d7','登北邙還望京洛','鄭世翼','唐','唐诗','tang','','[]','步登北邙坂，踟躕聊寫望。',132,'全唐诗/poet.tang.2000.json','["步登北邙坂，踟躕聊寫望。", "宛洛盛皇居，規模窮大壯。", "三河分設險，兩崤資巨防。", "飛觀紫煙中，層臺碧雲上。", "青槐夾馳道，迢迢修且曠。", "左右多第宅，參差居將相。", "清晨謁帝返，車馬相追訪。", "胥徒各異流，文物紛殊狀。", "囂塵暗天起，簫管從風颺。", "伊余孤且直，生平獨淪喪。", "山幽有桂叢，何爲坐惆悵。"]'),
('0dbe2d50-899d-4bcb-a236-6c77004f49a7','巫山高','鄭世翼','唐','唐诗','tang','','[]','巫山凌太清，岧嶤類削成。',48,'全唐诗/poet.tang.2000.json','["巫山凌太清，岧嶤類削成。", "霏霏暮雨合，靄靄朝雲生。", "危峯入鳥道，深谷寫猨聲。", "別有幽棲客，淹留攀桂情。"]'),
('1a9599e4-7bb3-426f-a570-38b887e247c9','看新婚','鄭世翼','唐','唐诗','tang','','[]','初筓夢桃李，新妝應摽梅。',48,'全唐诗/poet.tang.2000.json','["初筓夢桃李，新妝應摽梅。", "疑逐朝雲去，翻隨暮雨來。", "雜珮含風響，叢花隔扇開。", "姮娥對此夕，何用久裴回。"]'),
('e6fc26d8-b28e-4e9d-bbfe-0e425ada0623','見佳人負錢出路','鄭世翼','唐','唐诗','tang','','[]','獨負千金價，應從買笑來。',24,'全唐诗/poet.tang.2000.json','["獨負千金價，應從買笑來。", "秖持難發口，經爲幾人開。"]'),
('c6ac5aec-9c94-4ded-b87a-4ee99998ac91','送金竟陵入蜀','崔信明','唐','唐诗','tang','','[]','金門去蜀道，玉壘望長安。',60,'全唐诗/poet.tang.2000.json','["金門去蜀道，玉壘望長安。", "豈言千里遠，方尋九折難。", "西上君飛葢，東歸我挂冠。", "猨聲出峽斷，月彩落江寒。", "從今與君別，花月幾新殘。"]'),
('2dc40981-1d73-460e-a7cd-f819bec7761c','句','崔信明','唐','唐诗','tang','','[]','楓落吳江冷。',6,'全唐诗/poet.tang.2000.json','["楓落吳江冷。"]'),
('d70ae348-3a98-4ff2-b91a-574320631372','侍宴詠石榴','孔紹安','唐','唐诗','tang','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u9b4f\u664b\u5357\u5317\u671d\u8bd7"]','可惜庭中樹，移根逐漢臣。',24,'全唐诗/poet.tang.2000.json','["可惜庭中樹，移根逐漢臣。", "只爲來時晚，花開不及春。"]'),
('9f496ac0-4e6d-4f42-9c57-0ee55664afdb','詠夭桃','孔紹安','唐','唐诗','tang','','[]','結葉還臨影，飛香欲徧空。',24,'全唐诗/poet.tang.2000.json','["結葉還臨影，飛香欲徧空。", "不意餘花落，翻沈露井中。"]'),
('8b8e56f2-6005-4d74-b162-210836b049fd','贈蔡君','孔紹安','唐','唐诗','tang','','[]','疇昔同幽谷，伊爾遷喬木。',24,'全唐诗/poet.tang.2000.json','["疇昔同幽谷，伊爾遷喬木。", "赫奕盛青紫，討論窮簡牘。"]'),
('74a013db-5343-43ec-b371-0dd4a97fffa9','結客少年場行','孔紹安','唐','唐诗','tang','','[]','結客佩吳鉤，橫行度隴頭。',60,'全唐诗/poet.tang.2000.json','["結客佩吳鉤，橫行度隴頭。", "鴈在弓前落，雲從陣後浮。", "吳師驚燧象，燕將警奔牛。", "轉蓬飛不息，冰河結未流。", "若使三邊定，當封萬戶侯。"]'),
('bb3da941-ce1c-444d-821d-932325687947','傷顧學士','孔紹安','唐','唐诗','tang','','[]','迢遰雙崤道，超忽三川湄。',96,'全唐诗/poet.tang.2000.json','["迢遰雙崤道，超忽三川湄。", "此中俱失路，思君不可思。", "遊人行變橘，逝者遽焚芝。", "憶昔江湖上，同詠子衿詩。", "何言陵谷徙，翻驚鄰笛悲。", "陳根非席卉，穗帳異書帷。", "與善成空說，殲良信在茲。", "今日嚴夫子，哀命不哀時。"]'),
('d6722c6d-f5cc-42ac-9d22-9ad59e34d136','別徐永元秀才','孔紹安','唐','唐诗','tang','','[]','金湯既失險，玉石乃同焚。',60,'全唐诗/poet.tang.2000.json','["金湯既失險，玉石乃同焚。", "墜葉還相覆，落羽更爲羣。", "豈謂三秋節，重傷千里分。", "遠離弦易轉，幽咽水難聞。", "欲識相思處，山川間白雲。"]'),
('33f9ccb9-1b90-41cf-9ce3-e9394b68c4a3','落葉','孔紹安','唐','唐诗','tang','','["\u79cb\u5929", "\u601d\u4e61", "\u5199\u666f", "\u6f02\u6cca"]','早秋驚落葉，飄零似客心。',24,'全唐诗/poet.tang.2000.json','["早秋驚落葉，飄零似客心。", "翻飛未肯下，猶言惜故林。"]'),
('e2be5a24-9ff3-44c0-a507-a9bca2a228e0','踏歌詞三首 一','謝偃','唐','唐诗','tang','','[]','春景嬌春臺，新露泣新梅。',48,'全唐诗/poet.tang.2000.json','["春景嬌春臺，新露泣新梅。", "春葉參差吐，新花重疊開。", "花影飛鶯去，歌聲度鳥來。", "倩看飄颻雪，何如舞袖迴。"]'),
('28a1faca-a893-4602-972d-dd049e8a7bf4','踏歌詞三首 二','謝偃','唐','唐诗','tang','','[]','逶迤度香閤，顧步出蘭閨。',48,'全唐诗/poet.tang.2000.json','["逶迤度香閤，顧步出蘭閨。", "欲繞鴛鴦殿，先過桃李蹊。", "風帶舒還卷，簪花舉復低。", "欲問今宵樂，但聽歌聲齊。"]'),
('e64c0c87-3e98-4dc7-bf2e-0c10e294c763','踏歌詞三首 三','謝偃','唐','唐诗','tang','','[]','夜久星沈沒，更深月影斜。',48,'全唐诗/poet.tang.2000.json','["夜久星沈沒，更深月影斜。", "裙輕纔動珮，鬟薄不勝花。", "細風吹寶袂，輕露濕紅紗。", "相看樂未已，蘭燈照九華。"]'),
('ba2a0966-6561-40d5-af93-d6a74b890222','樂府新歌應教','謝偃','唐','唐诗','tang','','[]','青樓綺閣已含春，凝妝豔粉復如神。',96,'全唐诗/poet.tang.2000.json','["青樓綺閣已含春，凝妝豔粉復如神。", "細細輕裙全漏影，離離薄扇詎障塵。", "樽中酒色恆宜滿，曲裏歌聲不厭新。", "紫燕欲飛先遶棟，黃鶯始哢即嬌人。", "撩亂垂絲昏柳陌，參差濃葉暗桑津。", "上客莫畏斜光晚，自有西園明月輪。"]'),
('4c5ac99b-8c21-4569-ac94-6565b5ed8e82','奉和出穎至淮應令','蔡允恭','唐','唐诗','tang','','[]','久倦川塗曲，忽此望淮圻。',48,'全唐诗/poet.tang.2000.json','["久倦川塗曲，忽此望淮圻。", "波長泛淼淼，眺迥情依依。", "稍覺金烏轉，漸見錦帆稀。", "欲知仁化洽，謳歌滿路歸。"]'),
('1712cdd4-1f15-41c6-a291-c99d8560f520','和衛尉寺柳','杜之松','唐','唐诗','tang','','[]','漢將本屯營，遼河有戍城。',48,'全唐诗/poet.tang.2000.json','["漢將本屯營，遼河有戍城。", "大夫曾取姓，先生亦得名。", "高枝拂遠鴈，疎影度遙星。", "不辭攀折苦，爲入管弦聲。"]'),
('ce66605b-05a1-442f-80b6-82c7534a651b','荅王無功冬夜載酒鄉館','崔善爲','唐','唐诗','tang','','[]','頒條忝貴郡，懸榻久相望。',48,'全唐诗/poet.tang.2000.json','["頒條忝貴郡，懸榻久相望。", "處士同楊鄭，邦君謝李疆。", "詎知方擁篲，逢子敬惟桑。", "明朝蓬戶側，會自謁任棠。"]'),
('689ae8ea-708d-48fe-b260-d31526030fca','荅王無功九日','崔善爲','唐','唐诗','tang','','[]','秋來菊花氣，深山客重尋。',48,'全唐诗/poet.tang.2000.json','["秋來菊花氣，深山客重尋。", "露葉疑涵玉，風花似散金。", "摘來還泛酒，獨坐即徐斟。", "王弘貪自醉，無復覓楊林。"]'),
('8f0ecec7-ab64-4251-8b38-f0be571c48ad','荅王無功問故園','朱仲晦','唐','唐诗','tang','','[]','我從銅州來，見子上京客。',144,'全唐诗/poet.tang.2000.json','["我從銅州來，見子上京客。", "問我故鄉事，慰子羈旅色。", "子問我所知，我對子應識。", "朋遊總強健，童稚各長成。", "華宗盛文史，連牆富池亭。", "獨子園最古，舊林間新坰。", "柳行隨堤勢，茅齋看地形。", "竹從去年移，梅是今年榮。", "渠水經夏響，石苔終歲青。", "院果早晚熟，林花先後明。", "語罷相歎息，浩然起深情。", "歸哉且五斗，餉子東皐耕。"]'),
('cb73f12a-2079-431e-a770-bd1281d5e335','從軍行','王宏','唐','唐诗','tang','','[]','兒生三日掌上珠，燕頷猨肱穠李膚。',128,'全唐诗/poet.tang.2000.json','["兒生三日掌上珠，燕頷猨肱穠李膚。", "十五學劒北擊胡，羌歌燕筑送城隅。", "城隅路接伊川驛，河陽渡頭邯鄲陌。", "可憐少年把手時，黃鳥雙飛梨花白。", "秦王築城三千里，西自臨洮東遼水。", "山邊疊疊黑雲飛，海畔莓莓青草死。", "從來戰鬬不求勳，殺身爲君君不聞。", "鳳皇樓上吹急管，落日裴回腸先斷。"]'),
('e2d0a6f4-112a-440d-bf55-a30627223421','文德皇后挽歌','朱子奢','唐','唐诗','tang','','[]','神京背紫陌，縞駟結行輈。',48,'全唐诗/poet.tang.2000.json','["神京背紫陌，縞駟結行輈。", "北去橫橋道，西分清渭流。", "寒光向壟沒，霜氣入松楸。", "今日泉臺路，非是濯龍遊。"]'),
('423e6b74-a70d-4bda-a909-50ad6cae07d9','大酺樂','張文收','唐','唐诗','tang','','[]','淚滴珠難盡，容殘玉易銷。',24,'全唐诗/poet.tang.2000.json','["淚滴珠難盡，容殘玉易銷。", "倘隨明月去，莫道夢魂遙。"]'),
('277d3d6f-42e6-4203-b9c4-d0663528e6d6','與琳法師','毛明素','唐','唐诗','tang','','[]','冶長倦縲紲，韓安歎死灰。',24,'全唐诗/poet.tang.2000.json','["冶長倦縲紲，韓安歎死灰。", "始驗山中木，方知貴不材。"]'),
('3ef0d070-f7ef-4f1c-9fb3-03d6fbbf3327','上之回','陳子良','唐','唐诗','tang','','[]','承平重遊樂，詔蹕上之回。',48,'全唐诗/poet.tang.2000.json','["承平重遊樂，詔蹕上之回。", "屬車響流水，清笳轉落梅。", "嶺雲蓋道轉，巖花映綬開。", "下輦便高宴，何如在瑤臺。"]'),
('d26d70e1-4c7d-4269-90fb-e40ac12cd575','新成安樂宮','陳子良','唐','唐诗','tang','','[]','春色照蘭宮，秦女坐牕中。',48,'全唐诗/poet.tang.2000.json','["春色照蘭宮，秦女坐牕中。", "柳葉來眉上，桃花落臉紅。", "拂塵開扇匣，卷帳却薰籠。", "衫薄偏憎日，裙輕更畏風。"]'),
('040ef541-1341-4471-a55e-22a60c0eccc6','夏晚尋于政世置酒賦韻','陳子良','唐','唐诗','tang','','[]','聊從嘉遯所，酌醴共抽簪。',48,'全唐诗/poet.tang.2000.json','["聊從嘉遯所，酌醴共抽簪。", "以茲山水地，留連風月心。", "長榆落照盡，高柳暮蟬吟。", "一返桃源路，別後難追尋。"]'),
('803c0af2-e196-41c0-aea7-2e8f6eb9b4ca','入蜀秋夜宿江渚','陳子良','唐','唐诗','tang','','[]','我行逢日暮，弭櫂獨維舟。',48,'全唐诗/poet.tang.2000.json','["我行逢日暮，弭櫂獨維舟。", "水霧一邊起，風林兩岸秋。", "山陰黑斷磧，月影素寒流。", "故鄉千里外，何以慰羈愁。"]'),
('35417355-7ddf-41c3-a3ec-0bbbb197664f','賦得妓','陳子良','唐','唐诗','tang','','[]','金谷多歡宴，佳麗正芳菲。',48,'全唐诗/poet.tang.2000.json','["金谷多歡宴，佳麗正芳菲。", "流霞席上滿，回雪掌中飛。", "明月臨歌扇，行雲接舞衣。", "何必桃將李，別有待春暉。"]'),
('1886abf2-2150-4e6a-97e2-cadac52961b3','詶蕭侍中春園聽妓','陳子良','唐','唐诗','tang','','[]','微雨散芳菲，中園照落暉。',48,'全唐诗/poet.tang.2000.json','["微雨散芳菲，中園照落暉。", "紅樹搖歌扇，綠珠飄舞衣。", "繁弦調對酒，雜引動思歸。", "愁人當此夕，羞見落花飛。"]'),
('d0ef48e1-e418-47d8-9cda-09cc906bdf54','遊俠篇','陳子良','唐','唐诗','tang','','[]','洛陽麗春色，遊俠騁輕肥。',60,'全唐诗/poet.tang.2000.json','["洛陽麗春色，遊俠騁輕肥。", "水逐車輪轉，塵隨馬足飛。", "雲影遙臨蓋，花氣近薰衣。", "東郊鬬雞罷，南皮射雉歸。", "日暮河橋上，揚鞭惜晚暉。"]'),
('1cb29f78-fb3f-4cb2-b2a5-764cfac93e72','春晚看羣公朝還人爲八韻','陳子良','唐','唐诗','tang','','[]','遊子惜春暮，策杖出蒿萊。',96,'全唐诗/poet.tang.2000.json','["遊子惜春暮，策杖出蒿萊。", "正直康莊晚，羣公謁帝迴。", "履度南宮至，車從北闕來。", "珂影傍明月，笳聲動落梅。", "迎風采旄轉，照日綬花開。", "紅塵掩鶴蓋，翠柳拂龍媒。", "綺雲臨舞閣，丹霞薄吹臺。", "輕肥寧所羨，未若反山隈。"]'),
('1e9d0cbe-2a72-4395-babc-4fbeb5707d2d','讚德上越國公楊素','陳子良','唐','唐诗','tang','','[]','君侯稱上宰，命世挺才英。',288,'全唐诗/poet.tang.2000.json','["君侯稱上宰，命世挺才英。", "本超騏驥足，復蘊風雲情。", "攄藻掞錦綺，育德潤瑤瓊。", "已踵四知舉，非無三傑名。", "濟世同舟檝，匡政本阿衡。", "雍容入青鎖，肅穆侍丹楹。", "桂宮擅鳴珮，槐路獨飛纓。", "高門羅虎戟，綺閣麗彫甍。", "金罇酌湛湛，歌扇掩盈盈。", "匈奴軼燕薊，烽火照幽幷。", "天子名薄伐，受脤事專征。", "七德播雄略，十萬騁行兵。", "鴈行蔽虜甸，魚貫出長城。", "交河方飲馬，瀚海盛揚旌。", "拔劒倚天外，蒙犀輝日精。", "彎弧穿伏石，揮戈斬大鯨。", "鼓鼙朝作氣，刁斗夜偏鳴。", "六郡多壯士，三邊豈足平。", "嶺雲朝合陣，山月夜臨營。", "胡塵暗馬色，芳樹動笳聲。", "關雲未盡散，塞霧常自生。", "川長蔓草綠，峯逈雜花明。", "小人愧王氏，雕文慙馬卿。", "濫此叨書記，何以謝過榮。"]'),
('5bd38801-104e-46a4-ad08-16c68a0cf091','於塞北春日思歸','陳子良','唐','唐诗','tang','','[]','我家吳會青山遠，他鄉關塞白雲深。',64,'全唐诗/poet.tang.2000.json','["我家吳會青山遠，他鄉關塞白雲深。", "爲許羈愁長下淚，那堪春色更傷心。", "驚鳥屢飛恆失侶，落花一去不歸林。", "如何此日嗟遲暮，悲來還作白頭吟。"]'),
('6afd4887-a00f-4b5f-95cf-434c3c3ca46c','送別','陳子良','唐','唐诗','tang','','[]','落葉聚還散，征禽去不歸。',24,'全唐诗/poet.tang.2000.json','["落葉聚還散，征禽去不歸。", "以我窮途泣，沾君出塞衣。"]'),
('c8c73b57-fd84-4fb9-94ef-68dcfe360df0','七夕看新婦隔巷停車','陳子良','唐','唐诗','tang','','[]','隔巷遙停幰，非復爲來遲。',24,'全唐诗/poet.tang.2000.json','["隔巷遙停幰，非復爲來遲。", "只言更尚淺，未是渡河時。"]'),
('7b3297b7-407a-442b-a37a-914c5908e660','詠春雪','陳子良','唐','唐诗','tang','','[]','光映妝樓月，花承歌扇風。',24,'全唐诗/poet.tang.2000.json','["光映妝樓月，花承歌扇風。", "欲妬梅將柳，故落早春中。"]'),
('f89b9007-3906-4a9e-9234-de9c776109c8','驄馬','庾抱','唐','唐诗','tang','','[]','櫪上浮雲驄，本出吳門中。',48,'全唐诗/poet.tang.2000.json','["櫪上浮雲驄，本出吳門中。", "發跡來東道，長鳴起北風。", "迴鞍拂桂白，赬汗類塵紅。", "滅沒徒留影，無因圖漢宮。"]'),
('a7e25710-4c42-4dce-80a3-844e779e0896','別蔡參軍','庾抱','唐','唐诗','tang','','[]','人世多飄忽，溝水易西東。',48,'全唐诗/poet.tang.2000.json','["人世多飄忽，溝水易西東。", "今日歡娛盡，何年風月同？", "悲生萬里外，恨起一杯中。", "性靈如未失，南北有征鴻。"]'),
('e502c1ae-0ea2-403e-9d0c-d533aa2a5cb2','賦得胥臺露','庾抱','唐','唐诗','tang','','[]','胥臺既落構，荆棘稍侵扉。',50,'全唐诗/poet.tang.2000.json','["胥臺既落構，荆棘稍侵扉。", "棟拆連雲影，梁摧照日暉。", "翔鶤逐不及，巢燕[反]無歸。", "唯有團階露，承曉共沾衣。"]'),
('baa4e7e2-9ba0-478e-8d84-79bdc508b477','臥痾喜霽開扉望月簡宮內知友','庾抱','唐','唐诗','tang','','[]','秋雨移弦望，疲痾倦苦辛。',72,'全唐诗/poet.tang.2000.json','["秋雨移弦望，疲痾倦苦辛。", "忽對荆山璧，委照越吟人。", "高高侵地鏡，皎皎徹天津。", "色麗班姬篋，光潤洛川神。", "輪輝池上動，桂影隙中新。", "懷賢雖不見，忽似暫參辰。"]'),
('eae56b9d-994b-4231-bc31-a9e7bf761a37','和樂記室憶江水','庾抱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','遙想觀濤處，猶意採蓮歌。',24,'全唐诗/poet.tang.2000.json','["遙想觀濤處，猶意採蓮歌。", "無因關塞葉，共下洞庭波。"]'),
('45610463-fdcb-4e71-ab2d-e20dd596351d','凌朝浮江旅思','馬周','唐','唐诗','tang','','["\u6292\u60c5", "\u7f81\u65c5", "\u5199\u666f"]','太清上初日，春水送孤舟。',48,'全唐诗/poet.tang.2000.json','["太清上初日，春水送孤舟。", "山遠疑無樹，潮平似不流。", "岸花開且落，江鳥沒還浮。", "羈望傷千里，長歌遣四愁。"]'),
('f784e66e-81e1-4c69-a1f1-2d820aa49744','句','馬周','唐','唐诗','tang','','[]','何惜鄧林樹，不借一枝棲。',12,'全唐诗/poet.tang.2000.json','["何惜鄧林樹，不借一枝棲。"]'),
('6b908117-31ca-49d2-a26c-5f506cc2918e','出玉關','來濟','唐','唐诗','tang','','[]','歛轡遵龍漢，銜悽渡玉關。',24,'全唐诗/poet.tang.2000.json','["歛轡遵龍漢，銜悽渡玉關。", "今日流沙外，垂涕念生還。"]'),
('af84c796-64c8-4c7c-9e57-ef9340202749','七夕','張文恭','唐','唐诗','tang','','[]','鳳律驚秋氣，龍梭靜夜機。',72,'全唐诗/poet.tang.2000.json','["鳳律驚秋氣，龍梭靜夜機。", "星橋百枝動，雲路七香飛。", "映月迴雕扇，凌霞曳綺衣。", "含情向華幄，流態入重闈。", "歡餘夕漏盡，怨結曉驂歸。", "誰念分河漢，還憶兩心違。"]'),
('0ffa6826-9a72-4b19-a6ab-07063bf69b0e','佳人照鏡','張文恭','唐','唐诗','tang','','[]','倦采蘼蕪葉，貪憐照膽明。',24,'全唐诗/poet.tang.2000.json','["倦采蘼蕪葉，貪憐照膽明。", "兩邊俱拭淚，一處有啼聲。"]'),
('d449fe2f-b14b-4439-a787-4f48f819517e','奉和同太子監守違戀','薛元超','唐','唐诗','tang','','[]','儲禁銅扉啓，宸行玉軑遙。',84,'全唐诗/poet.tang.2000.json','["儲禁銅扉啓，宸行玉軑遙。", "空懷壽街吏，尚隔寢門朝。", "北首瞻龍戟，塵外想鸞鑣。", "飛文映仙榜，瀝思叶神飆。", "帝念紆蒼璧，乾文煥紫霄。", "歸塘橫筆海，平圃振詞條。", "欲應重輪曲，鏘洋韻九韶。"]'),
('a4198e31-5fe9-42f1-94a6-42fdfa352ca1','荅辨才探得招字','蕭翼','唐','唐诗','tang','','[]','邂逅欵良宵，殷勤荷勝招。',48,'全唐诗/poet.tang.2000.json','["邂逅欵良宵，殷勤荷勝招。", "彌天俄若舊，初地豈成遙。", "酒蟻傾還泛，心猨躁似調。", "誰憐失羣鴈，長苦業風飄。"]'),
('7da8b393-f6b9-4fa0-9fcf-f062e1960fb8','道失','歐陽詢','唐','唐诗','tang','','[]','已惑孔貴嬪，又被辭人侮。',48,'全唐诗/poet.tang.2000.json','["已惑孔貴嬪，又被辭人侮。", "花牋一何榮，七字誰曾許。", "不下結綺閣，空迷江令語。", "琱戈動地來，悞殺陳後主。"]'),
('10c85f05-ed25-4824-8c9e-e01e587d7466','巫山高','閻立本','唐','唐诗','tang','','[]','君不見巫山高高半天起，絕壁千尋盡相似。',134,'全唐诗/poet.tang.2000.json','["君不見巫山高高半天起，絕壁千尋盡相似。", "君不見巫山磕匝翠屏開，湘江碧水遶山來。", "綠樹春嬌明月峽，紅花朝覆白雲臺。", "臺上朝雲無定所，此中窕窈神仙女。", "仙女盈盈仙骨飛，清容出沒有光輝。", "欲暮高唐行雨送，今宵定入荆王夢。", "荆王夢里愛穠華，枕席初開紅帳遮。", "可憐欲曉啼猨處，說道巫山是妾家。"]'),
('da7ba66c-93a2-4b7b-8eed-e6d95efae807','同潘屯田冬日早朝','張文琮','唐','唐诗','tang','','[]','假寐懷古人，夙興瞻曉月。',60,'全唐诗/poet.tang.2000.json','["假寐懷古人，夙興瞻曉月。", "通晨禁門啓，冠蓋趨朝謁。", "霜靄清九衢，霞光照雙闕。", "紛綸文物紀，煥爛聲明發。", "腰劒動陸離，鳴玉和清越。"]'),
('7b780554-3dbe-4dd4-b917-842da9fd972a','蜀道難','張文琮','唐','唐诗','tang','','[]','梁山鎮地險，積石阻雲端。',48,'全唐诗/poet.tang.2000.json','["梁山鎮地險，積石阻雲端。", "深谷下寥廓，層巖上鬱盤。", "飛梁駕絕嶺，棧道接危巒。", "攬轡獨長息，方知斯路難。"]'),
('b87c3027-1311-485f-bcf6-a00424ee55ba','昭君怨','張文琮','唐','唐诗','tang','','[]','戒途飛萬里，迴首望三秦。',48,'全唐诗/poet.tang.2000.json','["戒途飛萬里，迴首望三秦。", "忽見天山雪，還疑上苑春。", "玉痕垂粉淚，羅袂拂胡塵。", "爲得胡中曲，還悲遠嫁人。"]'),
('0bde8f84-73f7-41ab-ab1f-dd501a4bdf86','詠水','張文琮','唐','唐诗','tang','','[]','標名資上善，流派表靈長。',48,'全唐诗/poet.tang.2000.json','["標名資上善，流派表靈長。", "地圖羅四瀆，天文載五潢。", "方流涵玉潤，圓折動珠光。", "獨有蒙園吏，棲偃翫濠梁。"]'),
('84284fb0-a075-46c2-8579-0006c50a6685','賦橋','張文琮','唐','唐诗','tang','','[]','造舟浮渭日，鞭石表秦初。',48,'全唐诗/poet.tang.2000.json','["造舟浮渭日，鞭石表秦初。", "星文遙寫漢，虹勢尚凌虛。", "已授文成履，空題武騎書。", "別有臨濠上，棲偃獨觀魚。"]'),
('c70263d8-fbda-4e30-8a47-99d2f997e1f0','和楊舍人詠中書省花樹','張文琮','唐','唐诗','tang','','[]','花萼映芳叢，參差間早紅。',48,'全唐诗/poet.tang.2000.json','["花萼映芳叢，參差間早紅。", "因風時落砌，雜雨乍浮空。", "影照鳳池水，香飄雞樹風。", "豈不愛攀折，希君懷袖中。"]'),
('f889634b-508b-4a3a-9557-b64733de3b45','奉和過舊宅應制','上官儀','唐','唐诗','tang','','[]','石關清晚夏，璇輿御早秋。',84,'全唐诗/poet.tang.2000.json','["石關清晚夏，璇輿御早秋。", "神麾颺珠雨，仙吹響飛流。", "沛水祥雲泛，宛郊瑞氣浮。", "大風迎漢筑，藂煙入舜球。", "翠梧臨鳳邸，滋蘭帶鶴舟。", "偃伯歌玄化，扈蹕頌王遊。", "遺簪謬昭獎，珥筆荷恩休。"]'),
('27000328-2a05-45c4-af69-5c8b6b6e772d','早春桂林殿應詔','上官儀','唐','唐诗','tang','','[]','步輦出披香，清歌臨太液。',48,'全唐诗/poet.tang.2000.json','["步輦出披香，清歌臨太液。", "曉樹流鶯滿，春堤芳草積。", "風光翻露文，雪華上空碧。", "花蝶來未已，山光曖將夕。"]'),
('c2f9387b-e35f-4d47-a92c-800c893356b6','安德山池宴集','上官儀','唐','唐诗','tang','','[]','上路抵平津，後堂羅薦陳。',72,'全唐诗/poet.tang.2000.json','["上路抵平津，後堂羅薦陳。", "締交開狎賞，麗席展芳辰。", "密樹風煙積，迴塘荷芰新。", "雨霽虹橋晚，花落鳳臺春。", "翠釵低舞席，文杏散歌塵。", "方惜流觴滿，夕鳥已城闉。"]'),
('0561ee4c-2906-48e7-8b10-59c5f3119352','酬薛舍人萬年宮晚景寓直懷友','上官儀','唐','唐诗','tang','','[]','奕奕九成臺，窈窕絕塵埃。',120,'全唐诗/poet.tang.2000.json','["奕奕九成臺，窈窕絕塵埃。", "蒼蒼萬年樹，玲瓏下冥霧。", "池色搖晚空，巖花歛餘煦。", "清切丹禁靜，浩蕩文河注。", "留連窮勝託，夙期暌善謔。", "東望安仁省，西臨子雲閣。", "長嘯披煙霞，高步尋蘭若。", "金狄掩通門，雕鞍歸騎喧。", "燕姝對明月，荆豔促芳尊。", "別有青山路，策杖訪王孫。"]'),
('9afab914-ceee-4ea1-b1e7-7a8b3494a5e5','奉和潁川公秋夜','上官儀','唐','唐诗','tang','','[]','泬寥空色遠，芸黃淒序變。',48,'全唐诗/poet.tang.2000.json','["泬寥空色遠，芸黃淒序變。", "涸浦落遵鴻，長飆送巢燕。", "千秋流夕景，萬籟含宵喚。", "峻雉聆金柝，層臺切銀箭。"]'),
('133342dd-08d3-4a83-8106-773f3575ea97','謝都督挽歌','上官儀','唐','唐诗','tang','','[]','漠漠佳城幽，蒼蒼松檟暮。',48,'全唐诗/poet.tang.2000.json','["漠漠佳城幽，蒼蒼松檟暮。", "魯幕飄欲卷，宛駟悲還顧。", "楚挽繞盧山，胡笳臨武庫。", "悵然郊原靜，煙生歸鳥度。"]'),
('bc66a919-0677-42c4-b8ad-c198e2e5d1f0','八詠應制二首 一','上官儀','唐','唐诗','tang','','[]','啓重帷，重帷照文杏。',114,'全唐诗/poet.tang.2000.json','["啓重帷，重帷照文杏。", "翡翠藻輕花，流蘇媚浮影。", "瑤笙燕始歸，金堂露初晞。", "風隨少女至，虹共美人歸。", "羅薦已擘鴛鴦被，綺衣復有蒲萄帶。", "殘紅豔粉映簾中，戲蝶流鶯聚窗外。", "洛濱春雪迴，巫峽暮雲來。", "雪花飄玉輦，雲光上璧臺。", "共待新妝出，清歌送落梅。"]'),
('c0895a41-61f7-4cb9-bcff-f70474730891','八詠應制二首 二','上官儀','唐','唐诗','tang','','[]','入叢臺，叢臺裛春露。',98,'全唐诗/poet.tang.2000.json','["入叢臺，叢臺裛春露。", "滴瀝間深紅，參差散輕素。", "妝蝶驚復聚，黃鸝飛且顧。", "攀折殊未已，復值驚飛起。", "送影舞衫前，飄香歌扇裏。", "望望惜春暉，行行猶未歸。", "暫得佳遊趣，更愁花鳥稀。", "且學鳥聲調鳳管，方移花影入鴛機。"]'),
('54af578d-9ecd-4ac2-a051-5c0d15bdc63c','和太尉戲贈高陽公','上官儀','唐','唐诗','tang','','[]','薰爐御史出神仙，雲鞍羽蓋下芝田。',144,'全唐诗/poet.tang.2000.json','["薰爐御史出神仙，雲鞍羽蓋下芝田。", "紅塵正起浮橋路，青樓遙敞御溝前。", "傾城比態芳菲節，絕世相嬌是六年。", "慣是洛濱要解珮，本是河間好數錢。", "翠釵照耀銜雲髮，玉步逶迤動羅袜。", "石榴絞帶輕花轉，桃枝綠扇微風發。", "無情拂袂欲留賓，詎恨深潭不可越。", "天津一別九秋長，豈若隨聞三日香。", "南國自然勝掌上，東家復是憶王昌。"]'),
('98981c31-6093-4d92-8849-3380d2b64042','王昭君','上官儀','唐','唐诗','tang','','[]','玉關春色晚，金河路幾千。',48,'全唐诗/poet.tang.2000.json','["玉關春色晚，金河路幾千。", "琴悲桂條上，笛怨柳花前。", "霧掩臨妝月，風驚入鬢蟬。", "緘書待還使，淚盡白雲天。"]'),
('f435f9a4-27c8-4847-9768-608abd737b4d','詠雪應詔','上官儀','唐','唐诗','tang','','[]','禁園凝朔氣，瑞雪掩晨曦。',48,'全唐诗/poet.tang.2000.json','["禁園凝朔氣，瑞雪掩晨曦。", "花明棲鳳閣，珠散影娥池。", "飄素迎歌上，翻光向舞移。", "幸因千里映，還繞萬年枝。"]'),
('c789be77-2ccc-4842-801a-e23e86da659c','奉和山夜臨秋','上官儀','唐','唐诗','tang','','[]','殿帳清炎氣，輦道含秋陰。',48,'全唐诗/poet.tang.2000.json','["殿帳清炎氣，輦道含秋陰。", "淒風移漢筑，流水入虞琴。", "雲飛送斷雁，月上淨疎林。", "滴瀝露枝響，空蒙煙壑深。"]'),
('321efb3d-00fd-48cb-bb50-ec9ca0872662','江王太妃挽歌','上官儀','唐','唐诗','tang','','[]','黃鶴悲歌絕，椒花清頌餘。',48,'全唐诗/poet.tang.2000.json','["黃鶴悲歌絕，椒花清頌餘。", "埃凝寫鄰鏡，網結和扉魚。", "銀消風燭盡，珠滅夜輪虛。", "別有南陵路，幽叢臨葉疎。"]'),
('c33b0d82-de8c-4a99-add2-32e69029c53a','故北平公挽歌','上官儀','唐','唐诗','tang','','[]','木落園林曠，庭虛風露寒。',48,'全唐诗/poet.tang.2000.json','["木落園林曠，庭虛風露寒。", "北里清音絕，南陔芳草殘。", "遠氣猶標劒，浮雲尚寫冠。", "寂寂琴臺晚，秋陰入井榦。"]'),
('d33a49d6-b3c2-45a4-bd82-ecf4ccdc7f56','高密長公主挽歌','上官儀','唐','唐诗','tang','','[]','湘渚韜靈跡，娥臺靜瑞音。',48,'全唐诗/poet.tang.2000.json','["湘渚韜靈跡，娥臺靜瑞音。", "鳳逐清簫遠，鸞隨幽鏡沈。", "霜處華芙落，風前銀燭侵。", "寂寞平陽宅，月冷洞房深。"]'),
('4a2afca0-d72b-40f6-96f5-fbe3d0c1f7ea','詠畫障','上官儀','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','芳晨麗日桃花浦，珠簾翠帳鳳凰樓。',64,'全唐诗/poet.tang.2000.json','["芳晨麗日桃花浦，珠簾翠帳鳳凰樓。", "蔡女菱歌移錦纜，燕姬春望上瓊鉤。", "新妝漏影浮輕扇，冶袖飄香入淺流。", "未減行雨荆臺下，自比凌波洛浦遊。"]'),
('4413a74d-82b0-425c-9e34-0c9aeb8ac648','奉和秋日即目應制','上官儀','唐','唐诗','tang','','[]','上苑通平樂，神池邇建章。',96,'全唐诗/poet.tang.2000.json','["上苑通平樂，神池邇建章。", "樓臺相掩映，城闕互相望。", "緹油泛行幔，簫吹轉浮梁。", "晚雲含朔氣，斜照蕩秋光。", "落葉飄蟬影，平流寫雁行。", "槿散凌風縟，荷銷裛露香。", "仙歌臨枍詣，玄豫歷長楊。", "歸路乘明月，千門開未央。"]'),
('3be8afbd-659c-4e16-b54d-a9d17b9d0e0c','入朝洛堤步行','上官儀','唐','唐诗','tang','','["\u5e26\u6709\u5730\u540d", "\u5199\u666f", "\u5730\u540d"]','脈脈廣川流，驅馬歷長洲。',24,'全唐诗/poet.tang.2000.json','["脈脈廣川流，驅馬歷長洲。", "鵲飛山月曙，蟬噪野風秋。"]'),
('e3805b61-3371-4a92-aff5-82d83177cab0','春日','上官儀','唐','唐诗','tang','','[]','花輕蝶亂仙人杏，葉密鶯啼帝女桑。',32,'全唐诗/poet.tang.2000.json','["花輕蝶亂仙人杏，葉密鶯啼帝女桑。", "飛雲閣上春應至，明月樓中夜未央。"]'),
('9b2eea0c-48e0-42dd-a21d-8e13d489c060','從駕閭山詠馬','上官儀','唐','唐诗','tang','','[]','桂香塵處減，練影月前空。',24,'全唐诗/poet.tang.2000.json','["桂香塵處減，練影月前空。", "定惑由關吏，徒嗟塞上翁。"]'),
('2f9629a6-5d2c-40e9-a041-d147abeef542','中和樂九章 歌登封第一','盧照鄰','唐','唐诗','tang','','[]','炎圖喪寶，黃歷開璿。',60,'全唐诗/poet.tang.2000.json','["炎圖喪寶，黃歷開璿。", "祖武類帝，宗文配天。", "玉鑾垂日，翠華陵煙。", "東雲干呂，南風入弦。", "山稱萬歲，河慶千年。", "金繩永結，璧麗長懸。"]'),
('e8eb92f8-053a-4c1a-a640-289d0d9ab816','中和樂九章 歌明堂第二','盧照鄰','唐','唐诗','tang','','[]','穆穆聖皇，雍雍明堂。',60,'全唐诗/poet.tang.2000.json','["穆穆聖皇，雍雍明堂。", "左平右墄，上圓下方。", "調均風雨，制度陰陽。", "四牕八達，五室九房。", "南通夏火，西瞰秋霜。", "天子臨御，萬玉鏘鏘。"]'),
('216be46a-d387-41d5-a32d-be55eb8d7df3','中和樂九章 歌東軍第三','盧照鄰','唐','唐诗','tang','','[]','遐哉廟畧，赫矣台臣。',60,'全唐诗/poet.tang.2000.json','["遐哉廟畧，赫矣台臣。", "橫戈碣石，倚劒浮津。", "風丘拂籜，日域清塵。", "島夷復祀，龍伯來賓。", "休兵宇縣，獻馘天闉。", "斾海凱入，耀輝震震。"]'),
('a51eb3e2-275f-4a08-aa77-fe282f1d6e61','中和樂九章 歌南郊第四','盧照鄰','唐','唐诗','tang','','[]','虔郊上帝，肅事圓丘。',50,'全唐诗/poet.tang.2000.json','["虔郊上帝，肅事圓丘。", "龍駕四牡，鸞旗九斿。", "鐘歌晚引，紫煬高浮。", "日麗蒼璧，雲飛鳴球。", "皇之慶矣，萬壽千秋。"]'),
('0a65461a-e36b-4aea-89b4-76daa72b01f7','中和樂九章 歌中宮第五','盧照鄰','唐','唐诗','tang','','[]','祥遊沙麓，慶洽瑤衣。',60,'全唐诗/poet.tang.2000.json','["祥遊沙麓，慶洽瑤衣。", "黃雲晝聚，白氣宵飛。", "居中履正，稟和體微。", "儀刑赤縣，演教椒闈。", "陶鈞萬國，丹青四妃。", "河洲在詠，風化攸歸。"]'),
('18ed2950-d4b7-41e5-b754-5ce5f5bf030f','中和樂九章 歌儲宮第六','盧照鄰','唐','唐诗','tang','','[]','波澄少海，景麗前星。',60,'全唐诗/poet.tang.2000.json','["波澄少海，景麗前星。", "高禖誕聖，甲觀昇靈。", "承規翠所，問寢瑤庭。", "宗儒側席，問道橫經。", "山賓皎皎，國胄青青。", "黃裳元吉，邦家以寧。"]'),
('ff1d8ce6-94dc-420c-b43f-af8554fe8316','中和樂九章 歌諸王第七','盧照鄰','唐','唐诗','tang','','[]','星陳帝子，嶽列天孫。',60,'全唐诗/poet.tang.2000.json','["星陳帝子，嶽列天孫。", "義光帶礪，象著乾坤。", "我有明德，利建攸存。", "苴以茅社，錫以犧尊。", "藩屏王室，翼亮堯門。", "八才兩獻，夫何足論。"]'),
('9e4bec93-76b7-4e2c-9d2b-819a4ef5afa0','中和樂九章 歌公卿第八','盧照鄰','唐','唐诗','tang','','[]','蹇蹇三事，師師百僚。',60,'全唐诗/poet.tang.2000.json','["蹇蹇三事，師師百僚。", "羣龍在職，振鷺盈朝。", "豐金輝首，珮玉鳴腰。", "青蒲翼翼，丹地翹翹。", "歌雲佐漢，捧日匡堯。", "天工人代，邈邈昭昭。"]'),
('37f6d6e8-1009-47ae-93fe-371a7c13156d','中和樂九章 總歌第九','盧照鄰','唐','唐诗','tang','','[]','明明天子兮聖德揚，穆穆皇后兮陰化康。',101,'全唐诗/poet.tang.2000.json','["明明天子兮聖德揚，穆穆皇后兮陰化康。", "登若木兮坐明堂，池濛汜兮家扶桑。", "武化偃兮文化昌，禮樂昭兮股肱良。", "君臣已定兮君永無疆，顏子更生兮徒皇皇。", "若有人兮天一方，忠爲衣兮信爲裳。", "飡白玉兮飲瓊芳，心思荃兮路阻長。"]'),
('e008c814-63b8-43d7-a6a9-5a3811f43bcf','關山月','盧照鄰','唐','唐诗','tang','','[]','塞垣通碣石，虜障抵[祁]連。',50,'全唐诗/poet.tang.2000.json','["塞垣通碣石，虜障抵[祁]連。", "相思在萬里，明月正孤懸。", "影移金岫北，光斷玉門前。", "寄言閨中婦，時看鴻雁天。"]'),
('fe894df3-7104-4471-805e-e24902878c69','上之回','盧照鄰','唐','唐诗','tang','','[]','回中道路險，蕭關烽候多。',48,'全唐诗/poet.tang.2000.json','["回中道路險，蕭關烽候多。", "五營屯北地，萬乘出西河。", "單于拜玉璽，天子按雕戈。", "振旅汾川曲，秋風橫大歌。"]'),
('63a70f2f-c3ce-4a77-baa3-1285517fa6e7','紫騮馬','盧照鄰','唐','唐诗','tang','','[]','騮馬照金鞍，轉戰入皐蘭。',48,'全唐诗/poet.tang.2000.json','["騮馬照金鞍，轉戰入皐蘭。", "塞門風稍急，長城水正寒。", "雪暗鳴珂重，山長噴玉難。", "不辭橫絕漠，流血幾時乾。"]'),
('6a143f96-ed36-4fab-a412-73d4459e498e','戰城南','盧照鄰','唐','唐诗','tang','','["\u6218\u4e89", "\u9f13\u5439\u66f2\u8f9e", "\u7231\u56fd", "\u4e50\u5e9c"]','將軍出紫塞，冒頓在烏貪。',48,'全唐诗/poet.tang.2000.json','["將軍出紫塞，冒頓在烏貪。", "笳喧雁門北，陣翼龍城南。", "琱弓夜宛轉，鐵騎曉參驔。", "應須駐白日，爲待戰方酣。"]'),
('bd1fcb2e-9a07-4c07-b009-a26393c5ab2a','梅花落','盧照鄰','唐','唐诗','tang','','["\u8fb9\u585e", "\u6885\u82b1", "\u5c06\u58eb"]','梅嶺花初發，天山雪未開。',48,'全唐诗/poet.tang.2000.json','["梅嶺花初發，天山雪未開。", "雪處疑花落，花邊似雪迴。", "因風入舞袖，雜粉向妝臺。", "匈奴幾萬里，春至不知來。"]'),
('899334f7-2f09-4409-b031-d7f8e0d038fe','結客少年場行','盧照鄰','唐','唐诗','tang','','[]','長安重遊俠，洛陽富財雄。',132,'全唐诗/poet.tang.2000.json','["長安重遊俠，洛陽富財雄。", "玉劒浮雲騎，金鞭明月弓。", "鬬雞過渭北，走馬向關東。", "孫賓遙見待，郭解暗相通。", "不受千金爵，誰論萬里功。", "將軍下天上，虜騎入雲中。", "烽火夜似月，兵氣曉成虹。", "橫行徇知己，負羽遠從戎。", "龍旌昏朔霧，鳥陣捲胡風。", "追奔瀚海咽，戰罷陰山空。", "歸來謝天子，何如馬上翁。"]'),
('98ed1ed0-947f-4518-8970-6bb48552eef5','詠史四首 一','盧照鄰','唐','唐诗','tang','','[]','季生昔未達，身辱功不成。',96,'全唐诗/poet.tang.2000.json','["季生昔未達，身辱功不成。", "髠鉗爲臺隸，灌園變姓名。", "幸逢滕將軍，兼遇曹丘生。", "漢祖廣招納，一朝拜公卿。", "百金孰云重，一諾良匪輕。", "廷議斬樊噲，羣公寂無聲。", "處身孤且直，遭時坦而平。", "丈夫當如此，唯唯何足榮。"]'),
('32fcd011-62ac-4e60-bb70-5e1dfb7bd024','詠史四首 二','盧照鄰','唐','唐诗','tang','','[]','大漢昔云季，小人道遂振。',107,'全唐诗/poet.tang.2000.json','["大漢昔云季，小人道遂振。", "玉帛委奄尹，斧鑕嬰縉紳。", "邈哉郭先生，卷舒得其真。", "雍容謝朝廷，談笑獎人倫。", "在晦不絕俗，處亂不爲親。", "諸侯不得友，天子不得臣。", "沖情甄負甑，重價折角巾。", "悠悠天下士，相送洛橋津。", "誰知仙舟上寂寂無四鄰。"]'),
('bd4d47e1-211a-4c28-ba8d-f150b163eb2f','詠史四首 三','盧照鄰','唐','唐诗','tang','','[]','公業負奇志，交結盡才雄。',120,'全唐诗/poet.tang.2000.json','["公業負奇志，交結盡才雄。", "良田四百頃，所食常不充。", "一爲侍御史，慷慨說何公。", "何公何爲敗，吾謀適不同。", "仲頴恣殘忍，廢興良在躬。", "死人如亂麻，天子如轉蓬。", "干戈及黃屋，荆棘生紫宮。", "鄭生運其謀，將以清國戎。", "時來命不遂，脫身歸山東。", "凜凜千載下，穆然懷春風。"]'),
('1484c8f0-a418-491f-aa6f-6d82048973bc','詠史四首 四','盧照鄰','唐','唐诗','tang','','[]','昔有平陵男，姓朱名阿游。',132,'全唐诗/poet.tang.2000.json','["昔有平陵男，姓朱名阿游。", "直髮上衝冠，壯氣橫三秋。", "願得斬馬劒，先斷佞臣頭。", "天子玉檻折，將軍丹血流。", "捐生不肯拜，視死其若休。", "歸來教鄉里，童蒙遠相求。", "弟子數百人，散在十二州。", "三公不敢吏，五鹿何能酬。", "名與日月懸，義與天壤儔。", "何必疲執戟，區區在封侯。", "偉哉曠達士，知命固不憂。"]'),
('952912a1-abf3-4682-acec-26e87d18ccd2','贈李榮道士','盧照鄰','唐','唐诗','tang','','[]','錦節銜天使，瓊仙駕羽君。',96,'全唐诗/poet.tang.2000.json','["錦節銜天使，瓊仙駕羽君。", "投金翠山曲，奠璧清江濆。", "圓洞開丹鼎，方壇聚絳雲。", "寶貺幽難識，空歌迥易分。", "風搖十洲影，日亂九江文。", "敷誠歸上帝，應詔在明君。", "獨有南冠客，耿耿泣離羣。", "遙看八會所，真氣曉氤氳。"]'),
('f8c8dbac-7eae-4dcb-90a8-0e3fed6ddf71','贈李榮道士','盧照鄰','唐','唐诗','tang','','[]','錦節銜天使，瓊仙駕羽君。',48,'全唐诗/poet.tang.2000.json','["錦節銜天使，瓊仙駕羽君。", "投金翠山曲，奠璧清江濆。", "圓洞開丹鼎，方壇聚絳雲。", "寶貺幽難識，空歌迥易分。"]'),
('3205bd3f-23c0-4d1f-8c83-bcf561a72da9','早度分水嶺','盧照鄰','唐','唐诗','tang','','[]','丁年遊蜀道，班鬢向長安。',96,'全唐诗/poet.tang.2000.json','["丁年遊蜀道，班鬢向長安。", "徒費周王粟，空彈漢吏冠。", "馬蹄穿欲盡，貂裘敝轉寒。", "層冰橫九折，積石凌七盤。", "重溪既下漱，峻峰亦上干。", "隴頭聞戍鼓，嶺外咽飛湍。", "瑟瑟松風急，蒼蒼山月團。", "傳語後來者，斯路誠獨難。"]'),
('6a456ea5-dcc7-4ec2-bac8-4de49ae19515','三月曲水宴得尊字','盧照鄰','唐','唐诗','tang','','[]','風煙彭澤里，山水仲長園。',120,'全唐诗/poet.tang.2000.json','["風煙彭澤里，山水仲長園。", "由來棄銅墨，本自重琴尊。", "高情邈不嗣，雅道今復存。", "有美光時彥，養德坐山樊。", "門開芳杜逕，室距桃花源。", "公子黃金勒，仙人紫氣軒。", "長懷去城市，高詠狎蘭蓀。", "連沙飛白鷺，孤嶼嘯玄猿。", "日影巖前落，雲花江上翻。", "興蘭車馬散，林塘夕鳥喧。"]'),
('dfcbb8ca-cb5f-4dfd-aec2-6cb17f15bdde','奉使益州至長安發鍾陽驛','盧照鄰','唐','唐诗','tang','','[]','躋險方未夷，乘春聊騁望。',120,'全唐诗/poet.tang.2000.json','["躋險方未夷，乘春聊騁望。", "落花赴丹谷，奔流下青嶂。", "葳蕤曉樹滋，滉瀁春江漲。", "平川看釣侶，狹徑聞樵唱。", "蝶戲綠苔前，鶯歌白雲上。", "耳目多異賞，風煙有奇狀。", "峻阻將長城，高標吞巨舫。", "聯翩事羈靮，辛苦勞疲恙。", "夕濟幾潺湲，晨登每惆悵。", "誰念復芻狗，山河獨偏喪。"]'),
('ddc742aa-1465-4177-9203-011a6f7e6594','和王奭秋夜有所思','盧照鄰','唐','唐诗','tang','','[]','寂寂南軒夜，悠然懷所知。',72,'全唐诗/poet.tang.2000.json','["寂寂南軒夜，悠然懷所知。", "長河落雁苑，明月下鯨池。", "鳳臺有清曲，此曲何人吹？", "丹脣間玉齒，妙響入雲涯。", "窮巷秋風葉，空庭寒露枝。", "勞歌欲有和，星鬢已將垂。"]'),
('ddfb2ee8-b085-4e10-88b0-019d283ee62a','望宅中樹有所思','盧照鄰','唐','唐诗','tang','','[]','我家有庭樹，秋葉正離離。',48,'全唐诗/poet.tang.2000.json','["我家有庭樹，秋葉正離離。", "上舞雙棲鳥，中秀合歡枝。", "勞思復勞望，相見不相知。", "何當共攀折？歌笑此堂垂。"]'),
('aa26701d-f665-411b-8136-bc7a13aadd99','宿晉安亭','盧照鄰','唐','唐诗','tang','','[]','聞有弦歌地，穿鑿本多奇。',84,'全唐诗/poet.tang.2000.json','["聞有弦歌地，穿鑿本多奇。", "遊人試一覽，臨翫果忘疲。", "窗橫暮捲葉，簷臥古生枝。", "舊石開紅鮮，新河覆綠池。", "孤猿稍斷絕，宿鳥復參差。", "汎灩月華曉，裴回星鬢垂。", "今日刪書客，悽惶君詎知。"]'),
('b48823da-d47c-4b7e-8305-b73f2749f803','于時春也慨然有江湖之思寄贈柳九隴','盧照鄰','唐','唐诗','tang','','[]','提琴一萬里，負書三十年。',218,'全唐诗/poet.tang.2000.json','["提琴一萬里，負書三十年。", "晨攀偃蹇樹，暮宿清泠泉。", "翔禽鳴我側，旅獸過我前。", "無人且無事，獨酌還獨眠。", "遙聞彭澤宰，高弄武城弦。", "形骸寄文墨，意氣託神仙。", "我有壺中要，題爲物外篇。", "將以貽好道，道遠莫致旃。", "相思勞日夜，相望阻風煙。", "坐惜春華晚，徒令客思懸。", "水去東南地，氣凝西北天。", "關山悲蜀道，花鳥憶秦川。", "天子何時問，公卿本亦憐。", "自哀還自樂，歸藪復歸田。", "海屋銀爲棟，雲車電作鞭。", "倘遇鸞將鶴，誰論貂與蟬。", "萊洲頻度淺，桃實幾成圓。", "寄言飛鳧舃，歲[晏]同聯翩。"]'),
('a56ea6d4-8621-48a9-8a87-8d4d08de2a45','至望喜矚目言懷貽劍外知己','盧照鄰','唐','唐诗','tang','','[]','聖圖夷九折，神化掩三分。',72,'全唐诗/poet.tang.2000.json','["聖圖夷九折，神化掩三分。", "緘愁赴蜀道，題拙奉虞薰。", "隱轔度深谷，遙褭上高雲。", "碧流遞縈注，青山互糾紛。", "澗松咽風緒，巖花濯露文。", "思北常依馭，圖南每喪羣。"]'),
('b90c0ead-1e5e-4603-93a3-8d85e5e17d72','赤谷安禪師塔','盧照鄰','唐','唐诗','tang','','[]','獨坐巖之曲，悠然無俗紛。',96,'全唐诗/poet.tang.2000.json','["獨坐巖之曲，悠然無俗紛。", "酌酒呈丹桂，思詩贈白雲。", "煙霞朝晚聚，猿鳥歲時聞。", "水華競秋色，山翠含夕曛。", "高談十二部，細覈五千文。", "如如數冥味，生生理氛氳。", "古人有糟粕，輪扁情未分。", "且當事芝朮，從吾所好云。"]'),
('76adf443-ff11-4694-ba5f-e1e292f0a5d1','贈益府裴錄事','盧照鄰','唐','唐诗','tang','','[]','忽忽歲云暮，相望限風煙。',96,'全唐诗/poet.tang.2000.json','["忽忽歲云暮，相望限風煙。", "長歌欲對酒，危坐遂停弦。", "停弦變霜露，對酒懷朋故。", "朝看桂蟾晚，夜聞鴻雁度。", "鴻度何時還？桂晚不同攀。", "浮雲映丹壑，明月滿青山。", "青山雲路深，丹壑月華臨。", "耿耿離憂積，空令星鬢侵。"]'),
('bd055164-1caf-4777-80c7-68876c692c7d','贈益府羣官','盧照鄰','唐','唐诗','tang','','[]','一鳥自北燕，飛來向西蜀。',156,'全唐诗/poet.tang.2000.json','["一鳥自北燕，飛來向西蜀。", "單棲劍門上，獨舞岷山足。", "昂藏多古貌，哀怨有新曲。", "羣鳳從之遊，問之何所欲？", "荅言寒鄉子，飄颻萬餘里。", "不息惡木枝，不飲盜泉水。", "常思稻粱遇，願棲梧桐樹。", "智者不我邀，愚夫余不顧。", "所以成獨立，耿耿歲云暮。", "日夕苦風霜，思歸赴洛陽。", "羽翮毛衣短，關山道路長。", "明月流客思，白雲迷故鄉。", "誰能借風便，一舉凌蒼蒼。"]'),
('c71cfe7d-31c6-46ef-bd68-b6b4a166ea48','送梓州高參軍還京','盧照鄰','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba", "\u9001\u522b"]','京洛風塵遠，褒斜煙露深。',48,'全唐诗/poet.tang.2000.json','["京洛風塵遠，褒斜煙露深。", "北遊君似智，南飛我異禽。", "別路琴聲斷，秋山猿鳥吟。", "一乖青巖酌，空佇白雲心。"]'),
('f732e41e-9f88-4a95-bc87-fa8e37c485c5','大劍送別劉右史','盧照鄰','唐','唐诗','tang','','[]','金碧禺山遠，關梁蜀道難。',48,'全唐诗/poet.tang.2000.json','["金碧禺山遠，關梁蜀道難。", "相逢屬晚歲，相送動征鞍。", "地咽緜川冷，雲凝劍閣寒。", "倘遇忠孝所，爲道憶長安。"]'),
('af89cce8-dcc4-4f68-9ca3-16e349a73a7b','同臨津紀明府孤雁','盧照鄰','唐','唐诗','tang','','[]','三秋違北地，萬里向南翔。',72,'全唐诗/poet.tang.2000.json','["三秋違北地，萬里向南翔。", "河洲花稍白，關塞葉初黃。", "避繳風霜勁，懷書道路長。", "水流疑箭動，月照似弓傷。", "橫天無有陣，度海不成行。", "會刷能鳴羽，還赴上林鄉。"]'),
('fe567083-75f2-4088-8cd1-7cd783bfe142','失羣雁','盧照鄰','唐','唐诗','tang','','[]','三秋北地雪皚皚，萬里南翔渡海來。',192,'全唐诗/poet.tang.2000.json','["三秋北地雪皚皚，萬里南翔渡海來。", "欲隨石燕沈湘水，試逐銅烏繞帝臺。", "帝臺銀闕距金塘，中間鵷鷺已成行。", "先過上苑傳書信，暫下中州戲稻粱。", "虞人負繳來相及，齊客虛弓忽見傷。", "毛翎頻頓飛無力，羽翮摧頹君不識。", "唯有莊周解愛鳴，復道郊哥重奇色。", "惆悵驚思悲未已，裴回自憐中罔極。", "傳聞有鳥集朝陽，詎勝仙鳧邇帝鄉。", "雲間海上應鳴舞，遠得鵾弦猶獨撫。", "金龜全寫中牟印，玉鵠當變萊蕪釜。", "願君弄影鳳皇池，時憶籠中摧折羽。"]'),
('a29954ad-e112-4473-9804-52bad4b62b9c','行路難','盧照鄰','唐','唐诗','tang','','["\u54f2\u7406"]','君不見長安城北渭橋邊，枯木橫槎臥古田。',323,'全唐诗/poet.tang.2000.json','["君不見長安城北渭橋邊，枯木橫槎臥古田。", "昔日含紅復含紫，常時留霧亦留煙。", "春景春風花似雪，香車玉轝恆闐咽。", "若箇遊人不競攀，若箇娼家不來折。", "娼家寶袜蛟龍帔，公子銀鞍千萬騎。", "黃鶯一一向花嬌，青鳥雙雙將子戲。", "千尺長條百尺枝，月桂星榆相蔽虧。", "珊瑚葉上鴛鴦鳥，鳳皇巢裏雛鵷兒。", "巢傾枝折鳳歸去，條枯葉落任風吹。", "一朝零落無人問，萬古摧殘君詎知。", "人生貴賤無終始，倏忽須臾難久恃。", "誰家能駐西山日，誰家能堰東流水。", "漢家陵樹滿秦川，行來行去盡哀憐。", "自昔公卿二千石，咸擬榮華一萬年。", "不見朱脣將白貌，唯聞素棘與黃泉。", "金貂有時換美酒，玉麈但搖莫計錢。", "寄言坐客神仙署，一生一死交情處。", "蒼龍闕下君不來，白鶴山前我應去。", "雲間海上邈難期，赤心會合在何時。", "但願堯年一百萬，長作巢由也不辭。"]'),
('fecca913-ad91-4fab-b34d-5734a2533039','長安古意','盧照鄰','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','長安大道連狹斜，青牛白馬七香車。',384,'全唐诗/poet.tang.2000.json','["長安大道連狹斜，青牛白馬七香車。", "玉輦縱橫過主第，金鞭絡繹向侯家。", "龍銜寶蓋承朝日，鳳吐流蘇帶晚霞。", "百丈遊絲爭繞樹，一羣嬌鳥共啼花。", "啼花戲蝶千門側，碧樹銀臺萬種色。", "複道交窗作合歡，雙闕連薨垂鳳翼。", "梁家畫閣天中起，漢帝金莖雲外直。", "樓前相望不相知，陌上相逢詎相識。", "借問吹簫向紫煙，曾經學舞度芳年。", "得成比目何辭死，願作鴛鴦不羨仙。", "比目鴛鴦真可羨，雙去雙來君不見。", "生憎帳額繡孤鸞，好取門簾帖雙燕。", "雙燕雙飛繞畫梁，羅幃翠被鬱金香。", "片片行雲著蟬鬢，纖纖初月上鴉黃。", "鴉黃粉白車中出，含嬌含態情非一。", "妖童寶馬鐵連錢，娼婦盤龍金屈膝。", "御史府中烏夜啼，廷尉門前雀欲栖。", "隱隱朱城臨玉道，遙遙翠幰沒金堤。", "挾彈飛鷹杜陵北，探丸借客渭橋西。", "俱邀俠客芙蓉劍，共宿娼家桃李蹊。", "娼家日暮紫羅裙，清歌一囀口氛氳。", "北堂夜夜人如月，南陌朝朝騎似雲。", "南陌北堂連北里，五劇三條控三市。", "弱柳青槐拂地垂，佳氣紅塵暗天起。"]'),
('1fefcf1f-2187-40e6-942e-96af173b04a8','明月引','盧照鄰','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭波起兮鴻雁翔，風瑟瑟兮野蒼蒼。',115,'全唐诗/poet.tang.2000.json','["洞庭波起兮鴻雁翔，風瑟瑟兮野蒼蒼。", "浮雲卷靄，明月流光。", "荆南兮趙北，碣石兮瀟湘。", "澄清規於萬里，照離思於千行。", "橫桂枝於西第，繞菱花於北堂。", "高樓思婦，飛蓋君王。", "文姬絕域，侍子他鄉。", "見胡鞍之似練，知漢劍之如霜。", "試登高而騁目，莫不變而回腸。"]'),
('8d9a5fbd-cf99-4284-aa9a-84eef6ac87bd','獄中學騷體','盧照鄰','唐','唐诗','tang','','[]','夫何秋夜之無情兮，皎皛悠悠而太長。',141,'全唐诗/poet.tang.2000.json','["夫何秋夜之無情兮，皎皛悠悠而太長。", "圜戶杳其幽邃兮，愁人披此嚴霜。", "見河漢之西落，聞鴻雁之南翔。", "山有桂兮桂有芳，心思君兮君不將。", "憂與憂兮相積，歡與歡兮兩忘。", "風嫋嫋兮木紛紛，凋綠葉兮吹白雲。", "寸步千里兮不相聞，思公子兮日將曛。", "林已暮兮鳥羣飛，重門掩兮人徑稀。", "萬族皆有所托兮，蹇獨淹留而不歸。"]'),
('1b9647e1-6a61-431a-8a23-12ebaaa3c122','懷仙引','盧照鄰','唐','唐诗','tang','','[]','若有人兮山之曲，駕青虬兮乘白鹿。',206,'全唐诗/poet.tang.2000.json','["若有人兮山之曲，駕青虬兮乘白鹿。", "往從之遊願心足，披澗戶，訪巖軒。", "石瀨潺湲橫石徑，松蘿冪䍥掩松門。", "下空濛而無鳥，上巉巖而有猨。", "懷飛閣，度飛梁。", "休余馬於幽谷，挂余冠於夕陽。", "曲復曲兮煙莊邃，行復行兮天路長。", "修途杳其未半，飛雨忽以茫茫。", "山坱軋，磴連褰。", "攀石壁而無據，泝泥溪而不前。", "向無情之白日，竊有恨於皇天。", "回行遵故道，通川遍流潦。", "回首望羣峰，白雲正溶溶。", "珠爲闕兮玉爲樓，青雲蓋兮紫霜裘。", "天長地久時相憶，千齡萬代一來遊。"]'),
('cf0d1aaf-62b4-45fe-846b-143219dae055','七日登樂遊故墓','盧照鄰','唐','唐诗','tang','','[]','四序周緹籥，三正紀璿耀。',96,'全唐诗/poet.tang.2000.json','["四序周緹籥，三正紀璿耀。", "綠野變初黃，暘山開曉眺。", "中天擢露掌，匝地分星徼。", "漢寢睠遺靈，秦江想餘弔。", "蟻泛青田酌，鶯歌紫芝調。", "柳色搖歲華，冰文蕩春照。", "遠迹謝羣動，高情符衆妙。", "蘭遊澹未歸，傾光下巖窈。"]'),
('42a9e25a-c411-4091-8ea5-98eaf8f40898','釋疾文三歌 一','盧照鄰','唐','唐诗','tang','','[]','歲將暮兮歡不再，時已晚兮憂來多。',32,'全唐诗/poet.tang.2000.json','["歲將暮兮歡不再，時已晚兮憂來多。", "東郊絕此麒麟筆，西山秘此鳳凰柯。"]'),
('6d5af37b-1189-4896-8316-99d231ba3437','釋疾文三歌 二','盧照鄰','唐','唐诗','tang','','[]','歲去憂來兮東流水，地久天長兮人共死。',48,'全唐诗/poet.tang.2000.json','["歲去憂來兮東流水，地久天長兮人共死。", "明鏡羞窺兮向十年，駿馬停驅兮幾千里。", "麟兮鳳兮，自古吞恨無已。"]'),
('c2e17d89-5874-44f1-bb92-508c917b605c','釋疾文三歌 三','盧照鄰','唐','唐诗','tang','','[]','茨山有薇兮潁水有漪，夷爲柏兮秋有實。',38,'全唐诗/poet.tang.2000.json','["茨山有薇兮潁水有漪，夷爲柏兮秋有實。", "叔爲柳兮春向飛，倏爾而笑，汎滄浪兮不歸。"]'),
('c62feb83-a378-4215-bc2b-62e2cb4a7bee','酬楊比部員外暮宿琴堂朝躋書閣率爾見贈之作','盧照鄰','唐','唐诗','tang','','[]','閑拂簷塵看，鳴琴候月彈。',48,'全唐诗/poet.tang.2000.json','["閑拂簷塵看，鳴琴候月彈。", "桃源迷漢姓，松徑有秦官。", "空谷歸人少，青山背日寒。", "羨君棲隱處，遙望在雲端。"]'),
('e13b9e9c-1984-45ef-9a2a-8311dad2e95e','劉生','盧照鄰','唐','唐诗','tang','','[]','劉生氣不平，抱劍欲專征。',48,'全唐诗/poet.tang.2000.json','["劉生氣不平，抱劍欲專征。", "報恩爲豪俠，死難在橫行。", "翠羽裝刀鞘，黃金飾馬鈴。", "但令一顧重，不恡百身輕。"]'),
('90828a1a-3eb1-43cf-af43-cb3801b4a11b','隴頭水','盧照鄰','唐','唐诗','tang','','[]','隴阪高無極，征人一望鄉。',48,'全唐诗/poet.tang.2000.json','["隴阪高無極，征人一望鄉。", "關河別去水，沙塞斷歸腸。", "馬繫千年樹，旌懸九月霜。", "從來共嗚咽，皆是爲勤王。"]'),
('758b079b-ecac-4f88-8600-257403690898','巫山高','盧照鄰','唐','唐诗','tang','','[]','巫山望不極，望望下朝氛。',48,'全唐诗/poet.tang.2000.json','["巫山望不極，望望下朝氛。", "莫辨啼猿樹，徒看神女雲。", "驚濤亂水脉，驟雨暗峯文。", "霑裳即此地，況復遠思君。"]'),
('e6409c86-16a6-4fe7-96ea-8b86172a06bc','芳樹','盧照鄰','唐','唐诗','tang','','[]','芳樹本多奇，年華復在斯。',48,'全唐诗/poet.tang.2000.json','["芳樹本多奇，年華復在斯。", "結翠成新幄，開紅滿故枝。", "風歸花歷亂，日度影參差。", "容色朝朝落，思君君不知。"]'),
('27d3b858-16d3-4ace-8220-5af012748f1b','雨雪曲','盧照鄰','唐','唐诗','tang','','["\u8fb9\u585e"]','虜騎三秋入，關雲萬里平。',48,'全唐诗/poet.tang.2000.json','["虜騎三秋入，關雲萬里平。", "雪似胡沙暗，冰如漢月明。", "高闕銀爲闕，長城玉作城。", "節旄零落盡，天子不知名。"]'),
('a8ea6e9f-64ed-4670-b042-077f5dc46e86','昭君怨','盧照鄰','唐','唐诗','tang','','[]','合殿恩中絕，交河使漸稀。',48,'全唐诗/poet.tang.2000.json','["合殿恩中絕，交河使漸稀。", "肝腸辭玉輦，形影向金微。", "漢地草應綠，胡庭沙正飛。", "願逐三秋雁，年年一度歸。"]');
